(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,98455,(e,i,a)=>{i.exports=JSON.parse('[{"id":"idoine","mot":"idoine","nature":"adjectif","definitions":["Qui convient parfaitement à un usage, à une situation."],"phonetique":"/i.dwan/","etymologie":"Du latin idoneus, « propre à, capable de ».","registre":"soutenu","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["adéquat","approprié","convenable","pertinent"],"antonymes":["inadapté","inapproprié","impropre"],"exemplesCorrects":["Il a trouvé l\'endroit idoine pour installer son atelier.","Ce n\'est pas le moment idoine pour aborder ce sujet délicat.","Elle attendait la personne idoine pour reprendre l\'affaire familiale."],"exemplesIncorrects":["Cette tarte est vraiment idoine, je vais en reprendre une part.","Il s\'est montré idoine envers ses collègues hier soir."],"distracteurs":["anodin","indolent","indigne","idiomatique"],"anecdote":"Le mot, longtemps confiné au vocabulaire juridique et administratif, a connu un regain d\'usage chez les chroniqueurs des années 2000."},{"id":"saugrenu","mot":"saugrenu","nature":"adjectif","definitions":["Qui est à la fois inattendu, absurde et un peu ridicule."],"phonetique":"/so.ɡʁə.ny/","etymologie":"Composé de « sau- » (sel) et de « grenu », littéralement « assaisonné de gros sel », d\'où « grossier, déplaisant ».","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["absurde","loufoque","extravagant","biscornu"],"antonymes":["sensé","raisonnable","logique"],"exemplesCorrects":["Il a eu l\'idée saugrenue de partir camper en plein hiver.","Sa proposition saugrenue a déclenché un éclat de rire général.","On l\'a regardé avec surprise tant sa question paraissait saugrenue."],"exemplesIncorrects":["Le repas était délicieux mais un peu saugrenu pour mon goût.","Il a remporté la médaille avec une performance saugrenue."],"distracteurs":["sagace","salutaire","sanguin","sournois"],"anecdote":"Le mot était dès le XVIIᵉ siècle utilisé par Molière, qui adorait les sonorités qui prêtent à rire."},{"id":"melancolie","mot":"mélancolie","nature":"nom féminin","definitions":["Tristesse vague et douce, souvent teintée de rêverie."],"phonetique":"/me.lɑ̃.kɔ.li/","etymologie":"Du grec mélas (noir) et kholê (bile) : la « bile noire », l\'une des quatre humeurs de la médecine antique.","registre":"courant","niveau":1,"themes":["emotions","litteraire"],"synonymes":["spleen","nostalgie","vague à l\'âme","neurasthénie"],"antonymes":["allégresse","gaieté","enthousiasme"],"exemplesCorrects":["Une douce mélancolie l\'envahissait chaque automne, au moment où les feuilles tombaient.","Il regardait les photos anciennes avec une mélancolie souriante.","Cette chanson porte en elle toute la mélancolie d\'une époque révolue."],"exemplesIncorrects":["Il a couru le marathon avec mélancolie et a battu son record.","Sa mélancolie était si éclatante qu\'on l\'entendait rire à l\'autre bout du couloir."],"distracteurs":["amertume","lassitude","morosité"],"anecdote":"Baudelaire faisait de la mélancolie l\'un des moteurs essentiels de la création poétique moderne."},{"id":"crepuscule","mot":"crépuscule","nature":"nom masculin","definitions":["Lumière incertaine qui suit le coucher du soleil ou, plus rarement, qui précède l\'aurore.","Au figuré : déclin, fin d\'une époque, d\'une vie."],"phonetique":"/kʁe.pys.kyl/","etymologie":"Du latin crepusculum, dérivé de creper « obscur ».","registre":"courant","niveau":1,"themes":["nature","litteraire"],"synonymes":["tombée du jour","brune","soir","déclin"],"antonymes":["aurore","aube","matin"],"exemplesCorrects":["Le crépuscule embrasait l\'horizon d\'un rouge profond.","Au crépuscule, les chauves-souris quittèrent leur abri.","Cet écrivain au crépuscule de sa vie publia son œuvre la plus tendre."],"exemplesIncorrects":["Le crépuscule éclatant de midi nous obligea à chercher l\'ombre.","Elle s\'est levée à l\'aube, au crépuscule, pour aller pêcher."],"distracteurs":["pénombre","obscurité","horizon","firmament"],"anecdote":"On parle de « crépuscule civil », « nautique » et « astronomique » pour distinguer trois moments précis selon la position du soleil sous l\'horizon."},{"id":"quiproquo","mot":"quiproquo","nature":"nom masculin","definitions":["Méprise qui consiste à prendre une personne ou une chose pour une autre, souvent à l\'origine de situations comiques."],"phonetique":"/ki.pʁɔ.ko/","etymologie":"Du latin qui pro quo, « qui à la place de quoi ».","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["malentendu","méprise","confusion","imbroglio"],"antonymes":["entente","accord","compréhension"],"exemplesCorrects":["Toute la pièce repose sur un quiproquo savamment entretenu jusqu\'au dernier acte.","Le quiproquo s\'est dissipé dès qu\'ils ont échangé deux mots.","Un simple quiproquo téléphonique l\'a privé d\'un rendez-vous important."],"exemplesIncorrects":["Ils ont signé le quiproquo devant le notaire ce matin.","Le quiproquo de cette tarte est un secret de famille."],"distracteurs":["stratagème","subterfuge","quolibet","quidam"],"anecdote":"Le quiproquo est un ressort comique central chez Marivaux et Feydeau, qui en ont fait un art à part entière."},{"id":"tergiverser","mot":"tergiverser","nature":"verbe","definitions":["User de détours, de faux-fuyants pour éviter de prendre une décision."],"phonetique":"/tɛʁ.ʒi.vɛʁ.se/","etymologie":"Du latin tergiversari, « tourner le dos », de tergum (dos) et versare (tourner).","registre":"soutenu","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["atermoyer","hésiter","louvoyer","biaiser"],"antonymes":["trancher","décider","agir"],"exemplesCorrects":["Cesse de tergiverser, il faut donner une réponse aujourd\'hui.","Le ministre a tergiversé pendant des semaines avant de se prononcer.","Plutôt que de tergiverser, elle prit le premier billet disponible."],"exemplesIncorrects":["Il a tergiversé son adversaire d\'un seul mot tranchant.","Nous avons tergiversé la salle de la cave au grenier."],"distracteurs":["vaciller","transiger","transgresser","tergir"],"anecdote":"On reproche souvent à la diplomatie de tergiverser, mais c\'est aussi sa manière d\'éviter les conflits prématurés."},{"id":"plethore","mot":"pléthore","nature":"nom féminin","definitions":["Excès, abondance considérée comme nuisible ou superflue."],"phonetique":"/ple.tɔʁ/","etymologie":"Du grec plêthôrê, « plénitude excessive ».","registre":"soutenu","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["surabondance","profusion","foison","excès"],"antonymes":["pénurie","manque","rareté"],"exemplesCorrects":["Une pléthore de candidatures rendit le tri particulièrement délicat.","Il y a pléthore de cafés dans ce quartier, c\'en est presque comique.","On déplorait la pléthore de réformes annoncées sans jamais être appliquées."],"exemplesIncorrects":["La pléthore manquait cruellement après une saison aussi sèche.","Cette pléthore de monnaie ne pèse rien dans ma poche."],"distracteurs":["pénurie","myriade","carence","panoplie"],"anecdote":"À l\'origine terme médical désignant un excès de sang, le mot a glissé vers son sens figuré dès le XIXᵉ siècle."},{"id":"desuet","mot":"désuet","nature":"adjectif","definitions":["Qui n\'est plus en usage, tombé en désuétude ; vieilli, démodé."],"phonetique":"/de.zɥɛ/","etymologie":"Du latin desuetus, « déshabitué », de desuescere « perdre l\'habitude ».","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["suranné","démodé","obsolète","vieillot"],"antonymes":["moderne","actuel","en vogue"],"exemplesCorrects":["Ce vocabulaire désuet donne du charme aux romans du XIXᵉ siècle.","Les costumes désuets du musée témoignaient d\'une élégance disparue.","Sa manière de saluer paraissait désuète mais charmante."],"exemplesIncorrects":["Ce nouveau modèle est si désuet qu\'il vient d\'arriver sur le marché.","Une connexion désuète permet aux ingénieurs de tester en temps réel."],"distracteurs":["vétuste","caduc","périmé"],"anecdote":"« Désuet » et « vétuste » ne sont pas exactement synonymes : « vétuste » s\'applique surtout à un bâtiment, « désuet » à un usage ou un style."},{"id":"vetuste","mot":"vétuste","nature":"adjectif","definitions":["Qui est en mauvais état parce qu\'ancien et mal entretenu."],"phonetique":"/ve.tyst/","etymologie":"Du latin vetustus, « vieux, ancien ».","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["délabré","décrépit","branlant","défraîchi"],"antonymes":["neuf","flambant","moderne","rénové"],"exemplesCorrects":["Ils ont retapé une vétuste ferme normande pour en faire leur maison de campagne.","L\'ascenseur vétuste ne fonctionnait plus depuis longtemps.","On accédait à la bibliothèque par un escalier vétuste qui grinçait à chaque pas."],"exemplesIncorrects":["Cet immeuble vétuste sort tout juste de terre.","Son sourire vétuste illuminait la pièce."],"distracteurs":["lugubre","obsolète","frêle"],"anecdote":"Le droit immobilier français parle de « vétusté » pour désigner l\'usure normale d\'un logement, distincte des dégradations."},{"id":"insipide","mot":"insipide","nature":"adjectif","definitions":["Qui n\'a pas de saveur, sans goût.","Au figuré : sans intérêt, sans relief, ennuyeux."],"phonetique":"/ɛ̃.si.pid/","etymologie":"Du latin insipidus, formé du préfixe in- (privatif) et sapidus (qui a du goût).","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["fade","terne","morne","plat"],"antonymes":["savoureux","piquant","captivant"],"exemplesCorrects":["Ce potage est insipide, il manque cruellement de sel.","Le roman se traîne dans une intrigue insipide sur des centaines de pages.","Elle trouvait insipide tout discours de circonstance."],"exemplesIncorrects":["Ce plat est tellement insipide que ses arômes dansent sur la langue.","Son humour insipide faisait rire tout le monde aux éclats."],"distracteurs":["anodin","mièvre","intrépide","instable"],"anecdote":"« Sapide » existe encore comme antonyme savant d\'« insipide », mais on ne l\'utilise plus guère qu\'en œnologie."},{"id":"lambiner","mot":"lambiner","nature":"verbe","definitions":["Agir avec une lenteur excessive, traîner."],"phonetique":"/lɑ̃.bi.ne/","etymologie":"Dérivé de « lambin », attesté au XVIIᵉ siècle, peut-être d\'un croisement avec « lambeau ».","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["traîner","musarder","lanterner","flâner"],"antonymes":["se hâter","se dépêcher","filer"],"exemplesCorrects":["Ne lambine pas, le train part dans dix minutes.","Il a lambiné toute la matinée au lieu de réviser.","Elle a tendance à lambiner devant les vitrines."],"exemplesIncorrects":["Il a lambiné l\'épreuve en un temps record.","Tu lambineras très fort à ce concours, j\'en suis sûr."],"distracteurs":["tergiverser","vaciller","louvoyer"],"anecdote":"« Lambin » a longtemps servi de surnom moqueur dans les fables et chansons populaires."},{"id":"inopine","mot":"inopiné","nature":"adjectif","definitions":["Qui arrive sans qu\'on s\'y attende, imprévu."],"phonetique":"/i.nɔ.pi.ne/","etymologie":"Du latin inopinatus, « auquel on ne pense pas ».","registre":"soutenu","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["imprévu","fortuit","inattendu","subit"],"antonymes":["prévu","attendu","planifié"],"exemplesCorrects":["Une visite inopinée du contrôleur les prit au dépourvu.","L\'arrivée inopinée de la pluie gâcha le pique-nique.","Il fit une rencontre inopinée à la sortie du cinéma."],"exemplesIncorrects":["Nous avions tout organisé pour rendre cet anniversaire parfaitement inopiné.","Le rendez-vous inopiné figurait depuis trois semaines à son agenda."],"distracteurs":["soudain","incongru","intempestif"],"anecdote":"Dans l\'administration française, un « contrôle inopiné » désigne précisément une inspection annoncée à la dernière minute."},{"id":"bigarre","mot":"bigarré","nature":"adjectif","definitions":["Qui présente des couleurs ou des éléments variés, contrastés.","Au figuré : d\'une grande diversité, hétéroclite."],"phonetique":"/bi.ɡa.ʁe/","etymologie":"Dérivé de l\'ancien français « garre » (bariolé), d\'origine obscure.","registre":"soutenu","niveau":2,"themes":["nature","litteraire"],"synonymes":["bariolé","hétéroclite","panaché","chamarré"],"antonymes":["uniforme","monochrome","uni"],"exemplesCorrects":["La foule bigarrée du carnaval déferlait sur les boulevards.","Un parterre bigarré de fleurs sauvages bordait le chemin.","Sa garde-robe bigarrée trahissait un goût prononcé pour les couleurs vives."],"exemplesIncorrects":["Ses cheveux bigarrés étaient d\'un noir uniforme et profond.","Le brouillard bigarré rendait toute la rue invisible."],"distracteurs":["tacheté","ombragé","bigot","bigle"],"anecdote":"« Bigarré » s\'employait dès le XVIᵉ siècle pour décrire des tissus aux motifs irréguliers, avant de s\'appliquer à des foules ou à des paysages."},{"id":"diaphane","mot":"diaphane","nature":"adjectif","definitions":["Qui laisse passer la lumière sans être tout à fait transparent.","Au figuré : d\'une grande finesse, d\'une pâleur délicate."],"phonetique":"/dja.fan/","etymologie":"Du grec diaphanês, « qui se laisse voir à travers ».","registre":"soutenu","niveau":2,"themes":["nature","litteraire"],"synonymes":["translucide","transparent","vaporeux","ténu"],"antonymes":["opaque","épais","trouble"],"exemplesCorrects":["La porcelaine diaphane laissait deviner la flamme à travers la paroi.","Elle avait un teint diaphane qui semblait éclairé de l\'intérieur.","Le brouillard diaphane voilait à peine les contours de la ville."],"exemplesIncorrects":["Le mur de béton diaphane bloquait toute la lumière.","Le tissu diaphane était si épais qu\'il pesait dans les bras."],"distracteurs":["limpide","cristallin","didactique","diaprée"],"anecdote":"Les médecins de la Renaissance qualifiaient de « diaphanes » les tissus humains assez fins pour être traversés par la lumière, comme la membrane de l\'œil."},{"id":"suranne","mot":"suranné","nature":"adjectif","definitions":["Qui a perdu son actualité, son charme par effet du temps ; vieillot, démodé."],"phonetique":"/sy.ʁa.ne/","etymologie":"De l\'ancien français « sur an », « au-delà d\'un an », d\'où « périmé ».","registre":"soutenu","niveau":2,"themes":["litteraire","quotidien"],"synonymes":["désuet","démodé","vieillot","passé"],"antonymes":["moderne","contemporain","actuel"],"exemplesCorrects":["Ses manières surannées rappelaient les salons d\'autrefois.","Elle écrivait dans un style suranné qui charmait ses lecteurs.","Le mobilier suranné de la pension lui donnait un cachet hors du temps."],"exemplesIncorrects":["Cette innovation surannée vient de révolutionner l\'industrie.","Son enthousiasme suranné débordait dans chacun de ses gestes."],"distracteurs":["vétuste","caduc","obsolète"],"anecdote":"Le mot a particulièrement séduit les écrivains symbolistes, qui en aimaient la sonorité légèrement décalée."},{"id":"imbroglio","mot":"imbroglio","nature":"nom masculin","definitions":["Situation confuse, embrouillée, dont il est difficile de se sortir."],"phonetique":"/ɛ̃.bʁɔ.ljo/","etymologie":"De l\'italien imbroglio, de imbrogliare « emmêler ».","registre":"courant","niveau":2,"themes":["emprunts","quotidien"],"synonymes":["embrouillamini","écheveau","complication"],"antonymes":["clarté","simplicité","limpidité"],"exemplesCorrects":["L\'imbroglio juridique a duré plus de dix ans avant qu\'un accord soit trouvé.","Personne ne comprenait plus rien à cet imbroglio diplomatique.","Il s\'est retrouvé pris dans un imbroglio dont il a eu peine à se dégager."],"exemplesIncorrects":["Tout s\'est déroulé dans un imbroglio parfaitement limpide.","Cet imbroglio se mange chaud, accompagné d\'un bon vin."],"distracteurs":["quiproquo","labyrinthe","stratagème","subterfuge"],"anecdote":"Le mot, emprunté à l\'italien au XVIIᵉ siècle, désignait d\'abord une intrigue de théâtre embrouillée à dessein."},{"id":"mansuetude","mot":"mansuétude","nature":"nom féminin","definitions":["Indulgence, douceur de caractère envers ceux qui ont commis une faute."],"phonetique":"/mɑ̃.sɥe.tyd/","etymologie":"Du latin mansuetudo, « douceur, bienveillance », formé sur manus (main) et suescere (s\'habituer) : « habitué à la main ».","registre":"soutenu","niveau":2,"themes":["emotions","abstrait"],"synonymes":["clémence","indulgence","bienveillance","magnanimité"],"antonymes":["sévérité","rigueur","intransigeance"],"exemplesCorrects":["Le juge fit preuve de mansuétude envers ce jeune coupable.","Elle racontait ses bêtises d\'enfance avec la mansuétude de l\'âge mûr.","On loua sa mansuétude à l\'égard des élèves les plus dissipés."],"exemplesIncorrects":["Sa mansuétude implacable terrorisa l\'assemblée.","Pris d\'une mansuétude colérique, il claqua la porte."],"distracteurs":["longanimité","déférence","mansion","manuscrit"],"anecdote":"L\'étymologie évoque l\'animal sauvage apprivoisé, qui s\'habitue à la main de l\'homme — image latine de la douceur acquise."},{"id":"atermoyer","mot":"atermoyer","nature":"verbe","definitions":["Remettre à plus tard, différer par hésitation ou par calcul."],"phonetique":"/a.tɛʁ.mwa.je/","etymologie":"De l\'ancien français « atermoier », de « terme » au sens de délai.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["tergiverser","temporiser","différer","louvoyer"],"antonymes":["trancher","agir","se résoudre"],"exemplesCorrects":["Il ne sert à rien d\'atermoyer : la décision doit tomber ce soir.","Le gouvernement a longuement atermoyé avant d\'annoncer la mesure.","Elle atermoya plusieurs semaines avant d\'accepter le poste."],"exemplesIncorrects":["Il a atermoyé son verre d\'une main ferme.","Elle a atermoyé brillamment ce concours difficile."],"distracteurs":["transiger","esquiver","ajourner"],"anecdote":"« Atermoiement » est aujourd\'hui plus courant que le verbe, sans doute parce qu\'il est utile aux journalistes pour qualifier les hésitations politiques."},{"id":"sempiternel","mot":"sempiternel","nature":"adjectif","definitions":["Qui dure toujours, qui se répète sans cesse, souvent avec une nuance de lassitude."],"phonetique":"/sɑ̃.pi.tɛʁ.nɛl/","etymologie":"Du latin sempiternus, contraction de semper (toujours) et aeternus (éternel).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["perpétuel","éternel","incessant","chronique"],"antonymes":["éphémère","passager","fugace"],"exemplesCorrects":["Il nous infligeait ses sempiternelles plaintes à chaque dîner.","Cette sempiternelle dispute au sujet du chauffage finit par lasser tout le monde.","On retrouvait dans ses discours les sempiternels lieux communs."],"exemplesIncorrects":["Ce sempiternel feu d\'artifice a duré quelques secondes à peine.","Son humeur sempiternelle changeait du tout au tout chaque heure."],"distracteurs":["lancinant","récurrent","permanent"],"anecdote":"Le mot a une coloration légèrement péjorative : on s\'en sert souvent pour railler ce qui se répète à l\'excès."},{"id":"velleite","mot":"velléité","nature":"nom féminin","definitions":["Intention timide ou passagère qui ne se traduit pas en acte."],"phonetique":"/ve.le.i.te/","etymologie":"Du latin scolastique velleitas, dérivé de velle « vouloir ».","registre":"soutenu","niveau":3,"themes":["abstrait","emotions"],"synonymes":["envie passagère","élan","esquisse de volonté","tentation"],"antonymes":["détermination","résolution","volonté"],"exemplesCorrects":["Il a eu quelques velléités de départ, mais il est resté.","Ses velléités de réforme se sont éteintes dès la première difficulté.","Elle reconnaît avoir eu des velléités d\'écrire, sans jamais s\'y mettre vraiment."],"exemplesIncorrects":["Avec une velléité de fer, il dirigea l\'entreprise pendant trente ans.","Sa velléité indomptable lui a permis de remporter le championnat."],"distracteurs":["intention","résolution","impulsion"],"anecdote":"Le terme vient d\'un débat médiéval entre théologiens scolastiques sur les degrés du « vouloir » humain."},{"id":"truculent","mot":"truculent","nature":"adjectif","definitions":["Qui est haut en couleur, d\'une vivacité expressive, parfois jusqu\'à l\'outrance."],"phonetique":"/tʁy.ky.lɑ̃/","etymologie":"Du latin truculentus, « farouche, sauvage », à l\'origine sens beaucoup plus rude.","registre":"soutenu","niveau":3,"themes":["litteraire","quotidien"],"synonymes":["pittoresque","savoureux","haut en couleur","rabelaisien"],"antonymes":["fade","terne","insipide"],"exemplesCorrects":["Ce personnage truculent dominait toutes les pages du roman.","Il racontait ses voyages dans un style truculent qui ravissait l\'assistance.","La truculente boulangère du quartier connaissait tous les ragots."],"exemplesIncorrects":["Cette pièce truculente plongeait la salle dans un silence morne.","Le commentaire truculent du juge fut d\'une neutralité parfaite."],"distracteurs":["verveux","facétieux","truchement","turbulent"],"anecdote":"« Truculent » a glissé du sens latin de « féroce » vers son sens moderne de « savoureux » grâce aux critiques littéraires du XIXᵉ siècle."},{"id":"ineffable","mot":"ineffable","nature":"adjectif","definitions":["Qui ne peut être exprimé par des mots, tant il dépasse les ressources du langage."],"phonetique":"/i.nɛ.fabl/","etymologie":"Du latin ineffabilis, formé sur effari « énoncer », précédé du préfixe privatif in-.","registre":"littéraire","niveau":3,"themes":["litteraire","abstrait","emotions"],"synonymes":["indicible","inexprimable","indéfinissable","sublime"],"antonymes":["exprimable","trivial","banal"],"exemplesCorrects":["Une ineffable tendresse passa dans son regard.","Le silence de la cathédrale dégageait une beauté ineffable.","Il évoquait son bonheur avec une joie ineffable."],"exemplesIncorrects":["Le règlement ineffable tient en quatre articles très clairs.","Cet ineffable horaire de train est affiché à la gare."],"distracteurs":["ineffaçable","innommable","inavouable"],"anecdote":"Dans la tradition mystique chrétienne, « ineffable » désigne la part de Dieu qui échappe à toute parole humaine."},{"id":"tonitruant","mot":"tonitruant","nature":"adjectif","definitions":["Qui résonne avec la force du tonnerre ; très bruyant, retentissant."],"phonetique":"/tɔ.ni.tʁy.ɑ̃/","etymologie":"Du latin tonitruare, « tonner ».","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["fracassant","retentissant","assourdissant","éclatant"],"antonymes":["étouffé","feutré","discret"],"exemplesCorrects":["Un éclat de rire tonitruant traversa la salle.","Il fit son entrée par une déclaration tonitruante.","La voix tonitruante du conférencier faisait vibrer les vitres."],"exemplesIncorrects":["Le chuchotement tonitruant des amoureux se perdit dans la nuit.","Une pluie tonitruante de pétales blancs tomba doucement."],"distracteurs":["détonnant","vibrant","torrentiel","tournoyant"],"anecdote":"L\'adjectif est très prisé du journalisme politique, qui aime décrire les sorties « tonitruantes » des ténors d\'assemblée."},{"id":"procrastiner","mot":"procrastiner","nature":"verbe","definitions":["Reporter sans cesse au lendemain ce qu\'on pourrait faire le jour même."],"phonetique":"/pʁɔ.kʁas.ti.ne/","etymologie":"Du latin procrastinare, de pro (en avant) et crastinus (du lendemain).","registre":"courant","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["atermoyer","tergiverser","remettre","différer"],"antonymes":["expédier","achever","s\'atteler"],"exemplesCorrects":["J\'ai procrastiné cette tâche pendant deux semaines avant de m\'y mettre.","Lui qui procrastine en temps normal s\'est lancé sans hésiter.","Procrastiner devient un art quand on a vingt onglets ouverts."],"exemplesIncorrects":["Il a procrastiné son adversaire dès le premier set.","Le facteur procrastine le courrier avec une précision admirable."],"distracteurs":["temporiser","esquiver","déserter"],"anecdote":"Le verbe, attesté en français dès le XVIᵉ siècle, n\'a connu un usage massif qu\'avec l\'essor des sciences cognitives au début du XXIᵉ."},{"id":"atrabilaire","mot":"atrabilaire","nature":"adjectif","definitions":["D\'humeur sombre, hargneuse ; mélancolique au point d\'en être irritable."],"phonetique":"/a.tʁa.bi.lɛʁ/","etymologie":"Du latin atra bilis, « bile noire », fluide qui passait pour engendrer mélancolie et colère.","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["acariâtre","bilieux","ombrageux","morose"],"antonymes":["enjoué","affable","serein"],"exemplesCorrects":["Ce personnage atrabilaire évoque irrésistiblement le Misanthrope de Molière.","Il accueillait les visiteurs d\'un ton atrabilaire qui les décourageait d\'insister.","Sa vieille tante atrabilaire trouvait à redire à tout."],"exemplesIncorrects":["Cet enfant atrabilaire riait aux éclats à la moindre plaisanterie.","Sa joie atrabilaire envahit toute la maisonnée."],"distracteurs":["lunatique","irascible","arbitraire","atrophié"],"anecdote":"Alceste, le héros du Misanthrope, est l\'archétype même de l\'atrabilaire amoureux."},{"id":"onirique","mot":"onirique","nature":"adjectif","definitions":["Qui appartient au rêve ou qui en a la qualité étrange et flottante."],"phonetique":"/ɔ.ni.ʁik/","etymologie":"Du grec oneiros, « rêve ».","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["féerique","fantasmagorique","imaginaire","irréel"],"antonymes":["réel","concret","tangible"],"exemplesCorrects":["Le film offrait une succession d\'images oniriques d\'une grande beauté.","Elle décrivait ses paysages d\'enfance avec une intensité presque onirique.","Sa peinture, aux couleurs oniriques, semblait flotter hors du temps."],"exemplesIncorrects":["L\'inventaire onirique du magasin tient en deux pages de chiffres exacts.","Le rapport comptable onirique remporta le prix de la rigueur."],"distracteurs":["fantastique","spectral","vaporeux"],"anecdote":"L\'adjectif s\'est répandu dans le sillage de la psychanalyse, qui a fait du rêve un objet d\'étude central."},{"id":"sibyllin","mot":"sibyllin","nature":"adjectif","definitions":["Dont le sens est volontairement obscur, énigmatique."],"phonetique":"/si.bi.lɛ̃/","etymologie":"De « Sibylle », nom des prêtresses antiques qui prédisaient l\'avenir en termes ambigus.","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["énigmatique","obscur","ambigu","hermétique"],"antonymes":["limpide","clair","explicite"],"exemplesCorrects":["Sa réponse sibylline ne fit qu\'épaissir le mystère.","Le ministre s\'est contenté de quelques formules sibyllines.","Elle se plaît à laisser des messages sibyllins sur son répondeur."],"exemplesIncorrects":["Ce mode d\'emploi sibyllin se lit en cinq minutes sans difficulté.","Son sourire sibyllin était d\'une franchise désarmante."],"distracteurs":["abscons","elliptique","serpentin","subliminal"],"anecdote":"La Sibylle de Cumes prophétisait sur des feuilles que le vent dispersait — les fidèles devaient les recomposer."},{"id":"iconoclaste","mot":"iconoclaste","nature":"adjectif","definitions":["Qui s\'attaque aux traditions, aux valeurs ou aux figures établies.","Sens historique : qui détruit les images religieuses."],"phonetique":"/i.kɔ.nɔ.klast/","etymologie":"Du grec eikôn (image) et klastes (briseur).","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["irrévérencieux","contestataire","subversif","novateur"],"antonymes":["conformiste","traditionaliste","orthodoxe"],"exemplesCorrects":["Son essai iconoclaste fit l\'effet d\'une bombe dans le milieu académique.","Il prit plaisir à formuler des opinions iconoclastes sur les classiques.","Cette mise en scène iconoclaste divisa profondément la critique."],"exemplesIncorrects":["Sa fidélité iconoclaste aux traditions familiales était irréprochable.","Elle gardait pieusement la mémoire iconoclaste de ses ancêtres."],"distracteurs":["frondeur","anticonformiste","iconographe","idéaliste"],"anecdote":"L\'iconoclasme byzantin, aux VIIIᵉ et IXᵉ siècles, fit détruire d\'innombrables icônes — un épisode dont le mot porte encore la trace."},{"id":"idiosyncrasie","mot":"idiosyncrasie","nature":"nom féminin","definitions":["Particularité de comportement, de tempérament ou de réaction propre à un individu."],"phonetique":"/i.djo.sɛ̃.kʁa.zi/","etymologie":"Du grec idios (propre, particulier) et sunkrasis (mélange).","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["singularité","particularisme","tempérament","originalité"],"antonymes":["banalité","uniformité"],"exemplesCorrects":["Son idiosyncrasie le rendait reconnaissable entre tous, jusqu\'à sa façon de marcher.","Les idiosyncrasies de chaque écrivain font la richesse d\'une langue.","On apprenait à composer avec les idiosyncrasies de la patronne."],"exemplesIncorrects":["L\'idiosyncrasie commune à tous les humains rend ce trait universel.","Le règlement intérieur impose une idiosyncrasie stricte."],"distracteurs":["particularité","physionomie","identité"],"anecdote":"Le mot servait initialement en médecine pour décrire des réactions inhabituelles à certains aliments ou médicaments."},{"id":"apocryphe","mot":"apocryphe","nature":"adjectif","definitions":["Dont l\'authenticité est douteuse, qui n\'est pas reconnu par une autorité officielle.","Sens premier : textes religieux écartés du canon."],"phonetique":"/a.pɔ.kʁif/","etymologie":"Du grec apokruphos, « caché, secret ».","registre":"soutenu","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["douteux","controuvé","supposé","non authentifié"],"antonymes":["authentique","canonique","avéré"],"exemplesCorrects":["La citation circulait depuis des années, mais elle s\'est révélée apocryphe.","Plusieurs évangiles apocryphes sont aujourd\'hui étudiés par les historiens.","Cette anecdote, sans doute apocryphe, est trop belle pour être vraie."],"exemplesIncorrects":["L\'authenticité apocryphe de ce manuscrit ne fait aucun doute.","Le notaire a établi l\'origine apocryphe et certifiée du document."],"distracteurs":["fallacieux","fictif","spéculatif"],"anecdote":"Les premiers chrétiens distinguaient les écrits « canoniques » (officiels) des « apocryphes », souvent prisés pour leurs récits plus pittoresques."},{"id":"ersatz","mot":"ersatz","nature":"nom masculin","definitions":["Produit de substitution, généralement de moindre qualité que celui qu\'il remplace."],"phonetique":"/ɛʁ.zats/","etymologie":"Mot allemand signifiant « remplacement », popularisé pendant les guerres mondiales par les denrées de substitution.","registre":"courant","niveau":2,"themes":["emprunts","quotidien"],"synonymes":["succédané","substitut","imitation"],"antonymes":["original","véritable"],"exemplesCorrects":["Ce café d\'orge n\'est qu\'un pâle ersatz de l\'expresso italien.","On nous servait pendant la guerre un ersatz de beurre à base de margarine douteuse.","Son ami n\'était qu\'un ersatz de confident, attentif mais distrait."],"exemplesIncorrects":["Ce vin est un ersatz d\'exception, primé au concours général.","Elle a apprécié l\'ersatz authentique du grand chef étoilé."],"distracteurs":["subterfuge","pastiche","simulacre"],"anecdote":"L\'usage du mot s\'est répandu en français autour de 1914-1918, époque où les armées allemandes manquant de matières premières multipliaient les produits de remplacement."},{"id":"spleen","mot":"spleen","nature":"nom masculin","definitions":["Mélancolie profonde, ennui existentiel sans cause précise."],"phonetique":"/splin/","etymologie":"De l\'anglais spleen, « rate », l\'organe considéré jadis comme siège de l\'humeur noire.","registre":"littéraire","niveau":3,"themes":["emprunts","emotions","litteraire"],"synonymes":["mélancolie","nostalgie","neurasthénie","vague à l\'âme"],"antonymes":["allégresse","jubilation"],"exemplesCorrects":["Baudelaire a fait du spleen l\'une des grandes catégories de la sensibilité moderne.","Un spleen tenace l\'habitait dès les premières pluies d\'automne.","Il évoquait son spleen d\'adolescent avec un sourire ému."],"exemplesIncorrects":["Le spleen festif éclatait dans toutes les rues du village.","Elle a remporté la course portée par un spleen contagieux."],"distracteurs":["ennui","morosité","splendeur","spectre"],"anecdote":"Baudelaire intitule « Spleen et Idéal » la première partie des Fleurs du Mal — le spleen y est l\'envers nécessaire de l\'idéal."},{"id":"avatar","mot":"avatar","nature":"nom masculin","definitions":["Transformation, métamorphose d\'une chose ou d\'une personne.","Souvent au pluriel : mésaventure, incident fâcheux."],"phonetique":"/a.va.taʁ/","etymologie":"Du sanskrit avatāra, « descente », désignant à l\'origine l\'incarnation terrestre d\'une divinité hindoue.","registre":"courant","niveau":2,"themes":["emprunts","abstrait"],"synonymes":["incarnation","métamorphose","péripétie","mésaventure"],"antonymes":["stabilité","permanence"],"exemplesCorrects":["Le voyage a connu mille avatars avant d\'arriver à bon port.","Le mythe a traversé les siècles sous de multiples avatars.","Sa carrière n\'a pas été exempte d\'avatars."],"exemplesIncorrects":["Cet avatar inattendu fut d\'une banalité réjouissante.","Le projet s\'est déroulé sans le moindre avatar, à la grande joie de l\'avatar."],"distracteurs":["metempsycose","vicissitude","déboire"],"anecdote":"Le sens informatique de « représentation virtuelle » est arrivé bien plus tard, dans les années 1980, en gardant l\'idée d\'une incarnation."},{"id":"kitsch","mot":"kitsch","nature":"adjectif","definitions":["De mauvais goût, mais assumé ou cultivé pour son charme désuet ou son outrance."],"phonetique":"/kitʃ/","etymologie":"De l\'allemand kitsch, peut-être de kitschen « bâcler ».","registre":"courant","niveau":2,"themes":["emprunts","quotidien"],"synonymes":["clinquant","ringard","tape-à-l\'œil"],"antonymes":["sobre","raffiné","épuré"],"exemplesCorrects":["Son salon est délicieusement kitsch, plein de chinoiseries et de napperons brodés.","Le film assume son esthétique kitsch jusqu\'au générique de fin.","Elle collectionne les objets kitsch des années soixante-dix."],"exemplesIncorrects":["Ce manifeste kitsch d\'une sobriété rare a marqué l\'histoire de l\'art.","Le minimaliste kitsch épure tout dans son intérieur."],"distracteurs":["outré","rétro","kaki","kitchenette"],"anecdote":"Le mot a d\'abord servi à dénoncer l\'art bourgeois du XIXᵉ siècle avant d\'être revendiqué, dès les années soixante, comme un genre à part entière."},{"id":"patio","mot":"patio","nature":"nom masculin","definitions":["Cour intérieure, généralement pavée et ornée, propre à l\'architecture méditerranéenne."],"phonetique":"/pa.tjo/","etymologie":"Mot espagnol, lui-même issu du provençal patu, désignant un terrain non bâti.","registre":"courant","niveau":1,"themes":["emprunts","quotidien"],"synonymes":["cour","atrium","courette"],"antonymes":[],"exemplesCorrects":["Nous dînions chaque soir sur le patio, à l\'ombre du citronnier.","Le patio andalou bruissait d\'une fontaine discrète.","Le riad ouvrait sur un patio rafraîchissant."],"exemplesIncorrects":["Le patio s\'élevait sur trois étages au cœur de l\'immeuble.","Le patio enneigé du sommet alpin offrait une vue spectaculaire."],"distracteurs":["véranda","péristyle","palio","portique"],"anecdote":"Hérité des maisons romaines et arabes, le patio joue un rôle climatique : il aère et tempère l\'intérieur."},{"id":"gosse","mot":"gosse","nature":"nom","definitions":["Enfant, en français de France ; mais en français québécois, désigne un testicule (à n\'employer qu\'avec précaution)."],"phonetique":"/ɡɔs/","etymologie":"Origine incertaine ; attesté dès le XIXᵉ siècle dans l\'argot parisien.","registre":"familier","niveau":1,"themes":["regionalismes","quotidien"],"synonymes":["enfant","môme","gamin"],"antonymes":["adulte"],"exemplesCorrects":["À Paris, les gosses jouaient autrefois dans la rue, sans téléphone ni surveillance.","Il a élevé seul ses deux gosses après le départ de leur mère.","« Allez les gosses, à table ! » lança-t-elle joyeusement."],"exemplesIncorrects":["Cette gosse était la doyenne du village, à quatre-vingt-douze ans.","Le directeur a réuni les gosses de l\'entreprise pour le bilan annuel."],"distracteurs":["marmot","loupiot","goss","gosier"],"anecdote":"Le faux ami entre français de France et québécois est célèbre : un Québécois qui entend « j\'ai mal aux gosses » comprend tout autre chose qu\'un Français."},{"id":"crognon","mot":"crognon","nature":"nom masculin","definitions":["Croûton de pain, plus particulièrement l\'extrémité dorée et croquante d\'une baguette."],"phonetique":"/kʁɔ.ɲɔ̃/","etymologie":"Diminutif issu de l\'ancien français cron, « crochu, dur », désignant la partie ferme du pain.","registre":"familier","niveau":1,"themes":["regionalismes","quotidien"],"synonymes":["croûton","quignon","talon"],"antonymes":["mie"],"exemplesCorrects":["Elle mordit dans le crognon encore chaud sorti du four.","Mon grand-père réservait toujours le crognon pour son chien.","Donne-moi le crognon, c\'est ma part préférée."],"exemplesIncorrects":["Le crognon mousseux du dessert ravissait les enfants.","Ce crognon de pâte fraîche se boit en apéritif."],"distracteurs":["entame","crogneux","grognon","carcasse"],"anecdote":"Le mot est répandu dans l\'Ouest de la France, en concurrence avec « quignon » qui domine ailleurs — joli exemple de variation régionale française."},{"id":"chenu","mot":"chenu","nature":"adjectif","definitions":["Blanchi par l\'âge ; au sens figuré, vénérable.","Régionalement (Bourgogne, Suisse romande) : excellent, bien réussi."],"phonetique":"/ʃə.ny/","etymologie":"Du latin canutus, « blanc de cheveux ».","registre":"littéraire","niveau":3,"themes":["regionalismes","litteraire"],"synonymes":["chevronné","vénérable","blanchi"],"antonymes":["juvénile","novice"],"exemplesCorrects":["Le vieux chêne chenu se dressait au milieu de la cour de l\'école.","Il avait l\'air chenu et solennel des magistrats d\'autrefois.","En Bourgogne, on dit volontiers d\'un repas réussi qu\'il fut « bien chenu »."],"exemplesIncorrects":["Le poulain chenu galopait à travers le pré au lever du soleil.","Cette plante chenue vient tout juste de germer la semaine dernière."],"distracteurs":["argenté","barbon","chenil","chétif"],"anecdote":"Brillat-Savarin, gourmet bourguignon, employait « chenu » pour louer un fromage particulièrement réussi — un sens régional encore vivace."},{"id":"ataraxie","mot":"ataraxie","nature":"nom féminin","definitions":["Tranquillité profonde de l\'âme, exempte de trouble et de désir, idéal philosophique antique."],"phonetique":"/a.ta.ʁak.si/","etymologie":"Du grec ataraxia, « absence de trouble », central chez les stoïciens et les épicuriens.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire","emotions"],"synonymes":["impassibilité","sérénité","imperturbabilité","quiétude"],"antonymes":["agitation","trouble","passion"],"exemplesCorrects":["Il cultivait une forme d\'ataraxie qui agaçait ses interlocuteurs les plus pressés.","L\'ataraxie épicurienne vise le plaisir stable, non l\'excitation.","Atteindre l\'ataraxie, c\'est moins ne rien sentir que ne plus être ballotté."],"exemplesIncorrects":["Dans une fureur d\'ataraxie, il claqua la porte de la salle de conseil.","Son ataraxie débordante envoya tous les invités sur la piste de danse."],"distracteurs":["apathie","agoraphobie","anorexie"],"anecdote":"Pour les stoïciens, l\'ataraxie s\'obtient en distinguant ce qui dépend de nous (nos jugements) de ce qui ne dépend pas (le monde)."},{"id":"bucolique","mot":"bucolique","nature":"adjectif","definitions":["Qui évoque la campagne paisible et idéalisée, propre aux poèmes pastoraux."],"phonetique":"/by.kɔ.lik/","etymologie":"Du grec boukolikos, « relatif au pâtre », par les Bucoliques de Virgile.","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["pastoral","champêtre","agreste","idyllique"],"antonymes":["urbain","industriel"],"exemplesCorrects":["Ils s\'étaient retirés dans une maison bucolique au cœur du Lubéron.","Le tableau, d\'une douceur bucolique, montrait un troupeau au crépuscule.","La scène avait quelque chose de bucolique, malgré la pluie fine."],"exemplesIncorrects":["Le périphérique parisien offrait un cadre bucolique au coureur.","L\'usine d\'aciérie, dans son ronronnement bucolique, charmait les passants."],"distracteurs":["rustique","botanique","boréal"],"anecdote":"Virgile écrit ses Bucoliques en imitant le grec Théocrite, lançant un genre poétique qui traversera deux mille ans."},{"id":"ineluctable","mot":"inéluctable","nature":"adjectif","definitions":["Qu\'on ne peut éviter, contre quoi on ne peut lutter."],"phonetique":"/i.ne.lyk.tabl/","etymologie":"Du latin ineluctabilis, de luctari « lutter », précédé de in- privatif.","registre":"soutenu","niveau":3,"themes":["abstrait"],"synonymes":["inévitable","fatal","implacable","irréversible"],"antonymes":["évitable","contournable"],"exemplesCorrects":["La fin de l\'été est inéluctable, comme chaque année.","Il accepta avec calme cette décision inéluctable.","Le déclin de l\'empire paraissait inéluctable aux contemporains."],"exemplesIncorrects":["Ce résultat inéluctable peut être facilement modifié au dernier moment.","Cette tartelette inéluctable a un goût de framboise délicieux."],"distracteurs":["irrévocable","imminent","inéducable","ineffable"],"anecdote":"Cicéron emploie déjà le mot pour décrire les destins que la philosophie stoïcienne enseigne à accepter."},{"id":"pernicieux","mot":"pernicieux","nature":"adjectif","definitions":["Dangereux, nuisible, particulièrement parce que son effet est sourd ou progressif."],"phonetique":"/pɛʁ.ni.sjø/","etymologie":"Du latin perniciosus, de pernicies « ruine, destruction ».","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["nocif","néfaste","délétère","funeste"],"antonymes":["bienfaisant","salutaire","bénéfique"],"exemplesCorrects":["L\'influence pernicieuse des réseaux sociaux fait débat chez les pédiatres.","Il dénonça l\'habitude pernicieuse de répéter sans vérifier.","Une rumeur pernicieuse circulait dans tout le service."],"exemplesIncorrects":["Sa générosité pernicieuse aidait tout le monde.","Cette tisane pernicieuse soulage agréablement les nerfs."],"distracteurs":["perfide","vicieux","pernottant","permissif"],"anecdote":"« Pernicieux » est resté un classique du vocabulaire médical jusqu\'au XIXᵉ siècle, désignant des maladies à évolution insidieuse."},{"id":"halcyon","mot":"alcyonien","nature":"adjectif","definitions":["Qui évoque les jours paisibles, sereins et heureux, à la manière des légendaires jours d\'accalmie liés à l\'alcyon."],"phonetique":"/al.sjɔ.njɛ̃/","etymologie":"Du grec halkuốn, via le latin alcyo, « alcyon », oiseau mythique (martin-pêcheur) auquel les Grecs attribuaient le pouvoir d\'apaiser la mer pendant la couvaison.","registre":"littéraire","niveau":5,"themes":["emprunts","litteraire"],"synonymes":["serein","paisible","tranquille"],"antonymes":["tumultueux","agité"],"exemplesCorrects":["Il évoquait avec tendresse les jours alcyoniens de leur jeunesse.","Un calme alcyonien régnait sur la baie au lever du jour.","Les poètes du Grand Siècle aimaient cette image alcyonienne."],"exemplesIncorrects":["Le vent alcyonien arrachait les toits du village.","Une dispute alcyonienne explosa au milieu du dîner."],"distracteurs":["lénifiant","olympien","élégiaque","vespéral"],"anecdote":"Selon Ovide, Alcyon fut métamorphosée en oiseau ; Éole, son père, calmait la mer pendant qu\'elle couvait, d\'où l\'expression « jours alcyoniens »."},{"id":"saudade","mot":"saudade","nature":"nom féminin","definitions":["Mélancolie douce-amère, mêlée de nostalgie et de désir, propre à la culture portugaise.","Mot souvent considéré comme intraduisible : il évoque la présence d\'une absence."],"phonetique":"/saw.dad/","etymologie":"Du portugais saudade, peut-être issu du latin solitas « solitude ».","registre":"littéraire","niveau":4,"themes":["emprunts","emotions"],"synonymes":["mélancolie","nostalgie","spleen"],"antonymes":["allégresse","entrain"],"exemplesCorrects":["Une saudade tenace lui revenait chaque fois qu\'il entendait du fado.","Il y a dans Lisbonne une saudade urbaine, faite de pierres et de pluie.","Elle peignait sa saudade dans des paysages bleus et lents."],"exemplesIncorrects":["La saudade festive du carnaval éclatait dans toutes les rues.","Une saudade énergique le poussa à courir le marathon."],"distracteurs":["désenchantement","blues","sarcasme","savoir-vivre"],"anecdote":"Le poète Fernando Pessoa fait de la saudade un sentiment proprement portugais, mêlant le manque de ce qui n\'a peut-être jamais existé."},{"id":"lugubre","mot":"lugubre","nature":"adjectif","definitions":["Funeste, sinistre ; qui évoque la mort ou un profond chagrin."],"phonetique":"/ly.ɡybʁ/","etymologie":"Du latin lugubris, de lugere « être en deuil ».","registre":"soutenu","niveau":2,"themes":["emotions","litteraire"],"synonymes":["sinistre","funèbre","macabre","sombre"],"antonymes":["joyeux","gai","lumineux"],"exemplesCorrects":["La maison vide rendait un son lugubre quand la porte grinçait.","Il prit une voix lugubre pour raconter sa mésaventure.","Le couloir lugubre du vieil hôpital donnait des frissons."],"exemplesIncorrects":["Un sourire lugubre éclairait toute la pièce.","Sa robe lugubre couleur soleil attira tous les regards."],"distracteurs":["sépulcral","morne","luxueux","lugustre"],"anecdote":"Au XVIIᵉ, on jouait des « pièces lugubres » lors des veillées funéraires, sortes de poèmes en prose pour accompagner le deuil."},{"id":"etiquette","mot":"étiquette","nature":"nom féminin","definitions":["Ensemble des règles de comportement, surtout en société élégante ou diplomatique.","Petit papier collé sur un objet pour indiquer son nom, son prix, sa nature."],"phonetique":"/e.ti.kɛt/","etymologie":"De l\'ancien français estiquette « petit poteau, écriteau », dérivé du verbe estiquier « ficher ».","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["protocole","convenances","cérémonial","label"],"antonymes":["désinvolture","familiarité"],"exemplesCorrects":["L\'étiquette de la cour de Versailles fixait des règles d\'une minutie déconcertante.","Elle observait les règles d\'étiquette avec un soin amusé.","Vérifie l\'étiquette avant d\'acheter : elle indique parfois la provenance."],"exemplesIncorrects":["Sans aucune étiquette ni règle, ce dîner d\'ambassadeurs fut parfait.","L\'étiquette du château vola dans le vent jusqu\'à la prochaine bourgade."],"distracteurs":["bienséance","étiologie","étincelle"],"anecdote":"On dit que la cour de Louis XIV adopta ces règles strictes parce que des panonceaux (étiquettes) indiquaient aux courtisans où ne pas marcher dans les jardins."},{"id":"obsequieux","mot":"obséquieux","nature":"adjectif","definitions":["Trop empressé à plaire, d\'une politesse exagérée et insincère."],"phonetique":"/ɔp.se.kjø/","etymologie":"Du latin obsequiosus, dérivé de obsequi « suivre, complaire à ».","registre":"soutenu","niveau":3,"themes":["emotions","litteraire"],"synonymes":["servile","flagorneur","complaisant","courtisan"],"antonymes":["fier","indépendant","franc"],"exemplesCorrects":["Il accueillait son patron d\'un sourire obséquieux qui agaçait tout le bureau.","Le ton obséquieux du majordome cachait mal son mépris.","Cette correspondance obséquieuse trahissait la peur du courtisan."],"exemplesIncorrects":["Sa franchise obséquieuse lui valait l\'admiration de tous.","Cet enfant obséquieux refusait toujours d\'obéir aux adultes."],"distracteurs":["doucereux","mielleux","objectif","obstiné"],"anecdote":"Molière met en scène l\'obséquiosité dans Le Tartuffe, qui devient le portrait-type du flatteur intéressé."},{"id":"exquis","mot":"exquis","nature":"adjectif","definitions":["D\'une délicatesse rare ; charmant, raffiné.","En art ou en cuisine : d\'une qualité supérieure, particulièrement choisie."],"phonetique":"/ɛks.ki/","etymologie":"Du latin exquisitus, « recherché », participe de exquirere « chercher avec soin ».","registre":"courant","niveau":1,"themes":["quotidien","emotions"],"synonymes":["délicieux","raffiné","délicat","charmant"],"antonymes":["grossier","vulgaire","fade"],"exemplesCorrects":["Le dîner fut exquis du début à la fin, et la conversation à l\'avenant.","Cette aquarelle exquise tient sur la paume d\'une main.","Elle a un goût exquis pour les vieux livres reliés."],"exemplesIncorrects":["Ce vacarme exquis sortait des hauts-parleurs à plein volume.","Une grossièreté exquise sortit de sa bouche."],"distracteurs":["succulent","exigeant","exquisite"],"anecdote":"Le « cadavre exquis » est un jeu surréaliste où chacun ajoute un mot à un poème sans voir ce qui précède — André Breton en raffolait."},{"id":"incurie","mot":"incurie","nature":"nom féminin","definitions":["Négligence grave dans la conduite d\'une affaire ; absence de soin."],"phonetique":"/ɛ̃.ky.ʁi/","etymologie":"Du latin incuria, « manque de soin ».","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["négligence","laxisme","désinvolture","carence"],"antonymes":["soin","diligence","rigueur"],"exemplesCorrects":["Le rapport pointe une incurie chronique dans la gestion du dossier.","L\'incurie des services finit par lasser les usagers.","Tout ici trahissait l\'incurie : poussière, paperasses, ordinateurs en panne."],"exemplesIncorrects":["Son incurie maniaque l\'obligeait à tout vérifier trois fois.","Une incurie impeccable régnait dans ce bureau parfaitement tenu."],"distracteurs":["imprévoyance","incursion","incurable"],"anecdote":"Le terme est très utilisé en droit administratif pour caractériser les fautes lourdes mais sans intention de nuire."},{"id":"amphigourique","mot":"amphigourique","nature":"adjectif","definitions":["Obscur, embrouillé, qui n\'a ni queue ni tête, en parlant d\'un discours ou d\'un écrit."],"phonetique":"/ɑ̃.fi.ɡu.ʁik/","etymologie":"De « amphigouri », mot du XVIIIᵉ siècle d\'origine incertaine, peut-être de amphi- (autour) et goury (vraisemblablement formé par l\'usage).","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["abscons","obscur","embrouillé","alambiqué"],"antonymes":["clair","limpide","intelligible"],"exemplesCorrects":["Sa thèse amphigourique perdit ses lecteurs dès la troisième page.","Le discours amphigourique du ministre fit sourire la salle.","Cette lettre amphigourique sentait l\'ironie."],"exemplesIncorrects":["Une formulation amphigourique tient sur trois mots clairs.","Ce texte amphigourique se lit avec une facilité enfantine."],"distracteurs":["filandreux","sibyllin","amphibologique","amphigastrique"],"anecdote":"Voltaire raillait les sermons « amphigouriques » de certains prédicateurs, leur préférant un style sec et précis."},{"id":"lapidaire","mot":"lapidaire","nature":"adjectif","definitions":["Bref, frappant, qui dit beaucoup en peu de mots — comme une inscription sur une pierre.","Relatif aux pierres précieuses ou aux tailleurs de pierre."],"phonetique":"/la.pi.dɛʁ/","etymologie":"Du latin lapidarius, de lapis « pierre ».","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["concis","laconique","incisif","sentencieux"],"antonymes":["verbeux","diffus","prolixe"],"exemplesCorrects":["Sa réponse lapidaire mit fin à la conversation.","Il aimait les formules lapidaires, héritées des stoïciens.","Une critique lapidaire valait mieux qu\'un long argumentaire."],"exemplesIncorrects":["Il développa son raisonnement lapidaire pendant trois heures sans pause.","Cette tarte lapidaire est servie en dessert au restaurant."],"distracteurs":["lapilli","lapereau","lapinière"],"anecdote":"Le « style lapidaire » est celui des épitaphes : forcément bref, parce qu\'on n\'écrit que ce qu\'il faut sur une pierre tombale."},{"id":"soporifique","mot":"soporifique","nature":"adjectif","definitions":["Qui endort, qui provoque le sommeil.","Au figuré : très ennuyeux, qui plonge dans la somnolence."],"phonetique":"/sɔ.pɔ.ʁi.fik/","etymologie":"Du latin sopor « sommeil profond » et -ifique « qui produit ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["assoupissant","ennuyeux","anesthésiant","endormant"],"antonymes":["stimulant","captivant","tonique"],"exemplesCorrects":["Cette conférence soporifique a eu raison du quart de la salle.","Sa voix soporifique aurait endormi tout un théâtre.","Le médecin lui prescrivit une tisane légèrement soporifique."],"exemplesIncorrects":["Cet expresso soporifique m\'a tenu éveillé jusqu\'à l\'aube.","Son rire soporifique tonifiait toute l\'assemblée."],"distracteurs":["lassant","soliloque","somatique"],"anecdote":"Le suffixe -fique est très productif : pacifique (qui fait la paix), terrifique (qui terrifie), soporifique (qui endort)."},{"id":"chimerique","mot":"chimérique","nature":"adjectif","definitions":["Qui relève de la chimère ; imaginaire, irréalisable.","Qui se nourrit d\'illusions."],"phonetique":"/ʃi.me.ʁik/","etymologie":"De chimère, monstre fabuleux à tête de lion, corps de chèvre et queue de serpent, du grec khimaira.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["illusoire","utopique","imaginaire","fantasque"],"antonymes":["réaliste","concret","tangible"],"exemplesCorrects":["Ce projet chimérique enchantait ses partisans et désespérait ses banquiers.","Elle nourrissait des espoirs chimériques pour son neveu.","Le rêve chimérique d\'une langue universelle a traversé les siècles."],"exemplesIncorrects":["Sa stratégie chimérique se réalisa en trois mois.","Cette pièce, parfaitement réaliste et chimérique, plut à la critique."],"distracteurs":["chimiotherapie","chichiteux","chinois"],"anecdote":"La Chimère figure parmi les créatures les plus étranges de la mythologie : tuée par Bellérophon, montée sur le cheval ailé Pégase."},{"id":"ataraxie2","mot":"stoïcisme","nature":"nom masculin","definitions":["Doctrine philosophique antique qui place la sagesse dans la maîtrise des passions et l\'acceptation des choses.","Plus largement, attitude faite de fermeté et d\'impassibilité face à l\'adversité."],"phonetique":"/stɔ.is.ism/","etymologie":"De stoïque, du grec stoa « portique », car Zénon de Cition enseignait sous le portique peint d\'Athènes.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["impassibilité","endurance","force d\'âme","ataraxie"],"antonymes":["impatience","abattement"],"exemplesCorrects":["Il accepta la nouvelle avec un stoïcisme qui força le respect.","Le stoïcisme antique a profondément marqué la pensée occidentale.","Marc Aurèle a laissé un manuel de stoïcisme tenu à l\'usage personnel."],"exemplesIncorrects":["Son stoïcisme nerveux trahissait sa peur du moindre changement.","Le stoïcisme excité de la foule était impossible à canaliser."],"distracteurs":["résignation","asthénie","athéisme"],"anecdote":"Sénèque, Épictète et Marc Aurèle sont les trois figures romaines majeures du stoïcisme — un esclave, un philosophe et un empereur."},{"id":"guerilla","mot":"guérilla","nature":"nom féminin","definitions":["Forme de guerre menée par petits groupes contre une armée régulière, fondée sur la surprise et le harcèlement.","Lutte longue et inégale ; tout combat de ce type."],"phonetique":"/ɡe.ʁi.ja/","etymologie":"De l\'espagnol guerrilla « petite guerre », diminutif de guerra.","registre":"courant","niveau":2,"themes":["emprunts","abstrait"],"synonymes":["maquis","résistance","harcèlement"],"antonymes":["guerre rangée","armistice"],"exemplesCorrects":["La guérilla menée par les paysans tint l\'armée régulière en échec pendant des années.","Le procès s\'est transformé en guérilla juridique permanente.","Ils pratiquaient une guérilla communicationnelle redoutable."],"exemplesIncorrects":["Cette paix universelle de guérilla règne partout depuis dix ans.","Sa guérilla de gentillesse charmait tous ses voisins."],"distracteurs":["embuscade","rébellion","guerrière","guérite"],"anecdote":"Le mot apparaît en français pendant la guerre d\'indépendance espagnole (1808-1814), où les civils harassent les armées napoléoniennes."},{"id":"manie","mot":"manie","nature":"nom féminin","definitions":["Goût excessif ou habitude bizarre, propre à un individu.","En médecine : trouble caractérisé par une exaltation pathologique."],"phonetique":"/ma.ni/","etymologie":"Du grec mania « folie, frénésie ».","registre":"courant","niveau":1,"themes":["emotions","quotidien"],"synonymes":["tic","habitude","obsession","marotte"],"antonymes":["spontanéité","naturel"],"exemplesCorrects":["Il a la manie d\'aligner ses crayons par couleur avant d\'écrire.","Cette manie de tout vérifier le rendait fatigant à vivre.","Chacun a ses petites manies, après tout."],"exemplesIncorrects":["Sa rare manie de spontanéité bouleversait tous ses plans.","Cette manie collective d\'oublier ne dérange personne."],"distracteurs":["lubie","malice","manche"],"anecdote":"Le mot a longtemps désigné en français une véritable maladie mentale, avant d\'adoucir progressivement son sens jusqu\'à devenir un quasi-synonyme de « tic ». "},{"id":"incipit","mot":"incipit","nature":"nom masculin","definitions":["Premiers mots d\'un texte, d\'une œuvre littéraire ou d\'un morceau musical."],"phonetique":"/ɛ̃.si.pit/","etymologie":"Mot latin, « il commence », première personne du présent de incipere.","registre":"soutenu","niveau":4,"themes":["litteraire"],"synonymes":["ouverture","début","préambule"],"antonymes":["explicit","chute","épilogue"],"exemplesCorrects":["« Longtemps, je me suis couché de bonne heure » est sans doute l\'incipit le plus célèbre du XXᵉ siècle.","Un incipit réussi attire l\'œil et tient le lecteur.","Elle relisait sans cesse l\'incipit de Madame Bovary."],"exemplesIncorrects":["Cet incipit final du roman m\'a profondément ému.","L\'incipit musical, à la dernière mesure, fit pleurer la salle."],"distracteurs":["exorde","préface","incident","incise"],"anecdote":"Les manuscrits médiévaux indiquaient souvent en marge l\'incipit pour identifier l\'œuvre — d\'où le mot, repris tel quel du latin."},{"id":"revasser","mot":"rêvasser","nature":"verbe","definitions":["Se laisser aller à des rêveries vagues, sans suite ni objet précis."],"phonetique":"/ʁɛ.va.se/","etymologie":"Dérivé péjoratif de rêver, avec le suffixe -asser qui marque la répétition ou le caractère un peu vain.","registre":"courant","niveau":1,"themes":["quotidien","emotions"],"synonymes":["songer","rêvailler","musarder","lambiner"],"antonymes":["se concentrer","s\'atteler"],"exemplesCorrects":["Elle aime rêvasser à la fenêtre en regardant tomber la pluie.","Au lieu de travailler, il rêvassait à ses prochaines vacances.","Une heure passée à rêvasser n\'est pas une heure perdue."],"exemplesIncorrects":["Il rêvassa rigoureusement le rapport en deux heures.","Son aptitude à rêvasser intensément l\'a propulsé champion d\'échecs."],"distracteurs":["vaguer","ressasser","renifler","remâcher"],"anecdote":"« Rêvasser » a une connotation tendre, presque enfantine : on n\'imagine pas un dirigeant « rêvasser » en plein conseil."},{"id":"logorrhee","mot":"logorrhée","nature":"nom féminin","definitions":["Flot intarissable de paroles, qui dépasse les besoins de la communication."],"phonetique":"/lɔ.ɡɔ.ʁe/","etymologie":"Du grec logos « parole » et rhein « couler » : « flot de paroles ».","registre":"soutenu","niveau":4,"themes":["litteraire","emotions"],"synonymes":["verbiage","bavardage","flux","diarrhée verbale"],"antonymes":["concision","laconisme","silence"],"exemplesCorrects":["Sa logorrhée éclatait dès qu\'on prononçait le mot « politique ».","Cette logorrhée enthousiaste lassait tout l\'auditoire.","L\'écrivain souffrait d\'une logorrhée littéraire que ses éditeurs peinaient à freiner."],"exemplesIncorrects":["Sa logorrhée silencieuse résumait sa réticence à parler.","Sa concision avait quelque chose d\'une logorrhée bien mesurée."],"distracteurs":["verbosité","loquacité","logique","lobotomie"],"anecdote":"Le mot est venu du vocabulaire médical (incontinence verbale dans certains troubles psychiatriques) avant de glisser vers l\'usage courant."},{"id":"estran","mot":"estran","nature":"nom masculin","definitions":["Partie du littoral alternativement couverte et découverte par la marée."],"phonetique":"/ɛs.tʁɑ̃/","etymologie":"Du vieux norrois strönd, « rivage », transmis par le normand.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["grève","batture","laisse de mer"],"antonymes":["large","haute mer"],"exemplesCorrects":["À marée basse, les pêcheurs à pied arpentent l\'estran à la recherche de coques.","L\'estran rocheux abrite une faune que la mer recouvre deux fois par jour.","Nous avons marché sur l\'estran luisant jusqu\'aux premières vagues."],"exemplesIncorrects":["Il a garé sa voiture sur l\'estran du parking municipal.","L\'estran de la montagne offrait une vue imprenable sur la vallée."],"distracteurs":["écueil","estuaire","étiage","estompe"],"anecdote":"L\'estran est un milieu si particulier que les biologistes le découpent en étages selon la durée d\'immersion."},{"id":"frondaison","mot":"frondaison","nature":"nom féminin","definitions":["Feuillage des arbres.","Époque où les arbres se couvrent de feuilles."],"phonetique":"/fʁɔ̃.dɛ.zɔ̃/","etymologie":"Dérivé de l\'ancien français fronde, du latin frons, frondis, « feuillage ».","registre":"littéraire","niveau":3,"themes":["nature","litteraire"],"synonymes":["feuillage","ramure","verdure"],"antonymes":["défeuillaison","nudité"],"exemplesCorrects":["La lumière du soir filtrait à travers la frondaison du grand chêne.","Dès la frondaison, le parc retrouve sa fraîcheur et son ombre.","Les oiseaux se cachaient dans l\'épaisse frondaison des tilleuls."],"exemplesIncorrects":["Il a rangé la frondaison dans le tiroir de son bureau.","La frondaison de l\'orchestre a duré tout le concert."],"distracteurs":["floraison","fenaison","frondeur","fondation"],"anecdote":"Le mot vient du latin frons, frondis (feuillage) et n\'a aucun lien étymologique avec la fronde, instrument de jet. Hugo et Chateaubriand en ont popularisé l\'usage poétique, où il coexiste avec son cousin feuillaison."},{"id":"ramure","mot":"ramure","nature":"nom féminin","definitions":["Ensemble des branches d\'un arbre.","Bois ramifié du cerf et du daim."],"phonetique":"/ʁa.myʁ/","etymologie":"Dérivé de rame, ancienne forme de rameau, du latin ramus, « branche ».","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["ramée","branchage","frondaison","bois"],"antonymes":["tronc","souche"],"exemplesCorrects":["Le vent agitait la ramure dénudée des peupliers.","Le cerf portait une ramure imposante à douze cors.","Sous la ramure entrelacée, le sentier disparaissait dans l\'ombre."],"exemplesIncorrects":["Elle a commandé une ramure de bœuf chez le boucher.","La ramure de la rivière coulait vers la mer."],"distracteurs":["rature","armure","rainure"],"anecdote":"Chez le cerf, la ramure tombe et repousse chaque année, plus fournie : un rare exemple de régénération osseuse chez les mammifères."},{"id":"embruns","mot":"embruns","nature":"nom masculin","definitions":["Fines gouttelettes d\'eau de mer arrachées aux vagues par le vent."],"phonetique":"/ɑ̃.bʁœ̃/","etymologie":"De l\'occitan embruma, « bruiner », de la famille du latin bruma.","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["embrun","écume","poudrin"],"antonymes":["accalmie"],"exemplesCorrects":["Les embruns lui piquaient le visage à chaque rafale.","Sur la jetée, on respirait les embruns iodés du large.","Le phare disparaissait par moments derrière un voile d\'embruns."],"exemplesIncorrects":["Il a saupoudré sa tarte d\'embruns de sucre glace.","Les embruns du désert rendaient la marche pénible."],"distracteurs":["embuns","effluves","embellie"],"anecdote":"Les embruns transportent du sel et des micro-organismes parfois jusqu\'à plusieurs kilomètres à l\'intérieur des terres."},{"id":"bruine","mot":"bruine","nature":"nom féminin","definitions":["Pluie très fine et serrée, faite de gouttelettes presque en suspension."],"phonetique":"/bʁɥin/","etymologie":"Du latin pruina, « givre, gelée blanche ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["crachin","bruinage","drache"],"antonymes":["averse","ondée"],"exemplesCorrects":["Une bruine glacée tombait sur la ville depuis le matin.","On distinguait à peine les toits dans la bruine de novembre.","La bruine collait les cheveux sans vraiment mouiller."],"exemplesIncorrects":["La bruine du volcan a recouvert le village de cendres.","Il a bu une bruine bien fraîche après sa course."],"distracteurs":["brume","bruire","buée","ruine"],"anecdote":"Météorologiquement, la bruine se distingue de la pluie par la taille de ses gouttes, inférieures à un demi-millimètre."},{"id":"givre","mot":"givre","nature":"nom masculin","definitions":["Fine couche de glace blanche qui se dépose sur les surfaces par temps froid et humide."],"phonetique":"/ʒivʁ/","etymologie":"Origine incertaine, peut-être d\'un radical prélatin évoquant le froid.","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["gelée blanche","frimas","verglas"],"antonymes":["dégel"],"exemplesCorrects":["Le givre dessinait des fougères sur les carreaux de la fenêtre.","Au petit matin, le givre couvrait l\'herbe d\'un voile argenté.","Les branches alourdies de givre scintillaient au soleil levant."],"exemplesIncorrects":["Il a versé du givre dans son café pour le sucrer.","Le givre de l\'été rendait la plage brûlante."],"distracteurs":["guivre","cuivre","givret"],"anecdote":"Le givre se forme par sublimation inverse : la vapeur d\'eau se change directement en glace, sans passer par l\'état liquide."},{"id":"clairiere","mot":"clairière","nature":"nom féminin","definitions":["Endroit dégarni d\'arbres au milieu d\'une forêt."],"phonetique":"/klɛ.ʁjɛʁ/","etymologie":"Dérivé de clair, « lumineux, dégagé », du latin clarus.","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["clarière","trouée","éclaircie"],"antonymes":["fourré","taillis"],"exemplesCorrects":["Au détour du sentier, une clairière baignée de soleil les attendait.","Les biches venaient brouter dans la clairière au crépuscule.","Ils dressèrent la tente au cœur d\'une clairière silencieuse."],"exemplesIncorrects":["Il a accroché la clairière au mur du salon.","La clairière de l\'océan était trop forte pour nager."],"distracteurs":["lisière","tanière","ornière"],"anecdote":"Les clairières naturelles naissent souvent de la chute d\'un grand arbre, qui ouvre une fenêtre de lumière exploitée aussitôt par les jeunes pousses."},{"id":"alize","mot":"alizé","nature":"nom masculin","definitions":["Vent régulier qui souffle toute l\'année des tropiques vers l\'équateur."],"phonetique":"/a.li.ze/","etymologie":"Origine incertaine, peut-être de l\'ancien français alis, « lisse, régulier ».","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["vent régulier"],"antonymes":["bourrasque","rafale"],"exemplesCorrects":["Les voiliers d\'autrefois traversaient l\'Atlantique portés par les alizés.","L\'alizé rafraîchissait l\'île chaque après-midi avec une belle constance.","Sans l\'alizé, la chaleur des Antilles serait difficilement supportable."],"exemplesIncorrects":["Il a planté un alizé dans son jardin au printemps.","L\'alizé de minuit a réveillé toute la maisonnée par son vacarme."],"distracteurs":["zéphyr","alésage","alidade"],"anecdote":"Ce sont les alizés qui ont rendu possible la « route des épices » : Christophe Colomb les utilisa pour gagner les Amériques."},{"id":"limon","mot":"limon","nature":"nom masculin","definitions":["Terre fine et fertile déposée par les eaux d\'un cours d\'eau."],"phonetique":"/li.mɔ̃/","etymologie":"Du latin limus, « boue, vase ».","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["alluvion","vase","boue","sédiment"],"antonymes":["roche","sable stérile"],"exemplesCorrects":["Les crues du Nil déposaient un limon noir qui faisait la richesse de l\'Égypte.","Après la décrue, les champs étaient couverts d\'un limon fertile.","Le potier puisait son argile dans le limon de la rivière."],"exemplesIncorrects":["Il a pressé un limon pour aromatiser son thé.","Le limon brillait de mille feux à la devanture du joaillier."],"distracteurs":["lichen","humus","filon"],"anecdote":"Plusieurs traditions font naître l\'homme du limon de la terre : l\'image dit la fécondité prêtée à cette terre des fleuves."},{"id":"zenith","mot":"zénith","nature":"nom masculin","definitions":["Point du ciel situé à la verticale de l\'observateur.","Point le plus haut, apogée."],"phonetique":"/ze.nit/","etymologie":"De l\'arabe samt (ar-ras), « le chemin au-dessus de la tête », via le latin médiéval.","registre":"courant","niveau":3,"themes":["nature","abstrait"],"synonymes":["apogée","sommet","faîte","summum"],"antonymes":["nadir","déclin","creux"],"exemplesCorrects":["À midi, le soleil atteignait presque le zénith.","Sa carrière connut son zénith au début des années quatre-vingt.","Au zénith de sa gloire, l\'écrivain choisit de se retirer."],"exemplesIncorrects":["Il a rangé le zénith dans la cave avec les vieux outils.","Le zénith de la soupe manquait cruellement de sel."],"distracteurs":["nadir","méridien","zéphyr"],"anecdote":"Le mot est jumeau de « nadir », son exact opposé : tous deux nous viennent des astronomes arabes du Moyen Âge."},{"id":"seve","mot":"sève","nature":"nom féminin","definitions":["Liquide nourricier qui circule dans les plantes.","Vigueur, énergie vitale."],"phonetique":"/sɛv/","etymologie":"Du latin sapa, « suc, vin cuit », croisé avec sucus.","registre":"courant","niveau":2,"themes":["nature","litteraire"],"synonymes":["suc","vigueur","vitalité","fluide"],"antonymes":["torpeur","langueur"],"exemplesCorrects":["Au printemps, la sève monte et les bourgeons éclatent.","On entaille l\'érable pour en recueillir la sève sucrée.","Il y avait dans ses vers une sève juvénile irrésistible."],"exemplesIncorrects":["Il a réparé la sève crevée de son vélo.","La sève du moteur était à plat ce matin."],"distracteurs":["fève","rêve","lève"],"anecdote":"La sève brute monte des racines vers les feuilles, et la sève élaborée redescend, chargée des sucres produits par la photosynthèse."},{"id":"futaie","mot":"futaie","nature":"nom féminin","definitions":["Forêt de grands arbres au tronc élevé et dégagé."],"phonetique":"/fy.tɛ/","etymologie":"Dérivé de fût, « tronc d\'arbre », du latin fustis.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["forêt","bois","sylve"],"antonymes":["taillis","broussaille"],"exemplesCorrects":["Le sentier s\'enfonçait dans une futaie de hêtres centenaires.","La haute futaie laissait à peine passer la lumière.","On exploitait cette futaie pour ses chênes de charpente."],"exemplesIncorrects":["Il a commandé une futaie de champagne pour la fête.","La futaie de poissons remontait le courant."],"distracteurs":["futile","frontaie","fustige"],"anecdote":"On oppose la futaie, faite d\'arbres issus de semences, au taillis, formé de rejets poussant sur des souches."},{"id":"drache","mot":"drache","nature":"nom féminin","definitions":["Forte pluie, averse soudaine et abondante."],"phonetique":"/dʁaʃ/","etymologie":"Du flamand, « forte averse ».","registre":"familier","niveau":3,"themes":["regionalismes","nature"],"synonymes":["averse","saucée","ondée"],"antonymes":["éclaircie","accalmie"],"exemplesCorrects":["On s\'est fait surprendre par une drache en sortant du café.","Quelle drache ! On ne voyait plus le bout de la rue.","À Lille, une drache de fin d\'après-midi n\'étonne personne."],"exemplesIncorrects":["Il a savouré une drache bien fraîche au dessert.","La drache du four a fait lever la pâte en quelques minutes."],"distracteurs":["bâche","tache","douche"],"anecdote":"Dans le Nord et en Belgique, on parle même de « drache nationale » pour la pluie qui tombe immanquablement les jours de fête."},{"id":"ducasse","mot":"ducasse","nature":"nom féminin","definitions":["Fête populaire annuelle, kermesse, dans le nord de la France et en Belgique."],"phonetique":"/dy.kas/","etymologie":"Altération de dédicace : la fête de la dédicace de l\'église, devenue fête de village.","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["kermesse","fête foraine","frairie"],"antonymes":[],"exemplesCorrects":["La ducasse du village attire les manèges chaque mois d\'août.","On mange des gaufres et on danse jusqu\'au bout de la nuit, c\'est la ducasse.","Les géants défilent dans les rues pour l\'ouverture de la ducasse."],"exemplesIncorrects":["Il a réglé la ducasse d\'électricité avant la fin du mois.","La ducasse de la montagne était couverte de neige."],"distracteurs":["bécasse","liesse","ripaille"],"anecdote":"La célèbre ducasse d\'Ath, avec ses géants, est inscrite au patrimoine culturel immatériel de l\'humanité par l\'UNESCO."},{"id":"gone","mot":"gone","nature":"nom masculin","definitions":["Enfant, gamin, dans le parler lyonnais."],"phonetique":"/ɡɔn/","etymologie":"Mot lyonnais d\'origine incertaine, « gamin des rues ».","registre":"familier","niveau":4,"themes":["regionalismes"],"synonymes":["gamin","gosse","môme","pitchoun"],"antonymes":["adulte","vieillard"],"exemplesCorrects":["Quand j\'étais gone, on jouait sur les pentes de la Croix-Rousse.","Les gones du quartier se retrouvaient au bord de la Saône.","C\'est un vrai gone de Lyon, fier de ses traboules."],"exemplesIncorrects":["Il a acheté un gone tout neuf pour aller travailler.","La gone de la rivière était en crue ce matin."],"distracteurs":["cône","zone","borne"],"anecdote":"Le personnage de Guignol, né à Lyon, est l\'archétype du gone : malicieux, gouailleur et bon cœur."},{"id":"pitchoun","mot":"pitchoun","nature":"nom masculin","definitions":["Petit enfant, dans le Midi de la France."],"phonetique":"/pi.tʃun/","etymologie":"De l\'occitan pichon, « petit ».","registre":"familier","niveau":4,"themes":["regionalismes"],"synonymes":["petit","gamin","gone","bambin"],"antonymes":["adulte","aîné"],"exemplesCorrects":["Allez, viens là, mon pitchoun, on va manger.","Les pitchouns couraient pieds nus dans les ruelles du village.","Elle gardait les pitchouns du quartier pendant l\'été."],"exemplesIncorrects":["Il a garé son pitchoun devant la mairie.","Le pitchoun de la soupe était trop épais."],"distracteurs":["potiron","pichet","pinson"],"anecdote":"Le mot a essaimé bien au-delà du Midi grâce aux chansons et au cinéma, au point de devenir un terme d\'affection presque national."},{"id":"cagnard","mot":"cagnard","nature":"nom masculin","definitions":["Soleil très chaud, forte chaleur ; endroit exposé au plein soleil."],"phonetique":"/ka.ɲaʁ/","etymologie":"Du provençal cagnard, « endroit abrité et ensoleillé ».","registre":"familier","niveau":4,"themes":["regionalismes","nature"],"synonymes":["plein soleil","canicule","fournaise"],"antonymes":["ombre","fraîcheur"],"exemplesCorrects":["On ne va pas rester en plein cagnard, cherchons un peu d\'ombre.","À deux heures, le cagnard rendait la place déserte.","Les cigales chantaient de plus belle sous le cagnard d\'août."],"exemplesIncorrects":["Il a mis un pull à cause du cagnard glacial.","Le cagnard tombait à gros flocons sur le village."],"distracteurs":["cafard","canard","cagneux"],"anecdote":"Le même mot a donné « cagnarder », c\'est-à-dire paresser au soleil : tout un art de vivre méridional en un verbe."},{"id":"fada","mot":"fada","nature":"adjectif","definitions":["Un peu fou, simple d\'esprit, dans le parler du Midi (souvent affectueux)."],"phonetique":"/fa.da/","etymologie":"De l\'occitan fadat, « touché par les fées », d\'où « un peu fou ».","registre":"familier","niveau":3,"themes":["regionalismes"],"synonymes":["toqué","timbré","marteau","zinzin"],"antonymes":["sensé","raisonnable"],"exemplesCorrects":["Il est complètement fada de pétanque, il y joue tous les jours.","Ne fais pas le fada, descends de ce mur !","Un peu fada, ce projet, mais après tout pourquoi pas."],"exemplesIncorrects":["La route était fada à cause des travaux.","Il a peint le mur d\'un beau fada lumineux."],"distracteurs":["fade","soda","fana"],"anecdote":"À Marseille, la Cité radieuse de Le Corbusier est surnommée « la Maison du fada », tant son architecture parut audacieuse à ses débuts."},{"id":"peuchere","mot":"peuchère","nature":"interjection","definitions":["Exclamation de compassion ou d\'attendrissement, dans le Midi : « le pauvre ! »."],"phonetique":"/pø.ʃɛʁ/","etymologie":"Du provençal pecaire, « pécheur », devenu exclamation de pitié.","registre":"familier","niveau":4,"themes":["regionalismes"],"synonymes":["le pauvre","hélas"],"antonymes":[],"exemplesCorrects":["Il a raté son train d\'une minute, peuchère !","Peuchère, le petit s\'est endormi avant la fin du repas.","Elle a tout perdu dans l\'inondation, peuchère."],"exemplesIncorrects":["Il a acheté une peuchère neuve au marché.","La peuchère du moteur faisait un bruit inquiétant."],"distracteurs":["pécore","vachère","panère"],"anecdote":"Pagnol a fait connaître « peuchère » à toute la France à travers ses films, où le mot ponctue la tendresse bourrue de ses personnages."},{"id":"barouf","mot":"barouf","nature":"nom masculin","definitions":["Grand bruit, tapage, vacarme."],"phonetique":"/ba.ʁuf/","etymologie":"De l\'arabe maghrébin, « grand bruit, tapage ».","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["vacarme","raffut","ramdam","boucan"],"antonymes":["silence","calme"],"exemplesCorrects":["Les voisins ont fait un de ces baroufs jusqu\'à trois heures du matin.","Quel barouf dans la cour de récréation à la sonnerie !","Inutile de faire tout ce barouf pour si peu."],"exemplesIncorrects":["Il a dégusté un barouf bien mûr au dessert.","Le barouf du lac était parfaitement lisse ce matin."],"distracteurs":["baroud","bazar","tarif"],"anecdote":"Comme « ramdam » ou « toubib », « barouf » fait partie de ces mots venus de l\'arabe que le français a adoptés au fil des échanges méditerranéens."},{"id":"ramdam","mot":"ramdam","nature":"nom masculin","definitions":["Tapage, vacarme ; agitation bruyante."],"phonetique":"/ʁam.dam/","etymologie":"De ramadan, par allusion à l\'animation nocturne du mois de jeûne.","registre":"familier","niveau":3,"themes":["quotidien","emprunts"],"synonymes":["vacarme","raffut","barouf","tintamarre"],"antonymes":["silence","quiétude"],"exemplesCorrects":["Les enfants ont fait un ramdam de tous les diables tout l\'après-midi.","Cette annonce a déclenché un beau ramdam sur les réseaux.","Arrête ce ramdam, j\'essaie de me concentrer."],"exemplesIncorrects":["Il a planté un ramdam dans son jardin potager.","Le ramdam de la rivière reflétait le ciel bleu."],"distracteurs":["macadam","ramage","tandem"],"anecdote":"Le glissement de sens est curieux : du mois sacré du jeûne, le mot n\'a gardé en français que l\'idée de l\'agitation des veillées."},{"id":"esquinter","mot":"esquinter","nature":"verbe","definitions":["Abîmer, détériorer.","Fatiguer à l\'excès, épuiser."],"phonetique":"/ɛs.kɛ̃.te/","etymologie":"De l\'occitan esquinçar, « déchirer ».","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["abîmer","amocher","éreinter","détériorer"],"antonymes":["réparer","ménager","soigner"],"exemplesCorrects":["Il a esquinté sa voiture contre un poteau en se garant.","Cette longue marche m\'a complètement esquinté.","Ne t\'esquinte pas la vue à lire dans la pénombre."],"exemplesIncorrects":["Elle a esquinté un délicieux gâteau pour le goûter.","Le soleil esquintait gaiement au-dessus des collines."],"distracteurs":["esquisser","esquiver","quintette"],"anecdote":"Dans la langue familière, on « s\'esquinte au travail » comme on « s\'esquinte les yeux » : le mot dit toujours l\'usure que l\'on s\'inflige."},{"id":"ronchon","mot":"ronchon","nature":"adjectif","definitions":["Qui ronchonne, qui exprime sa mauvaise humeur en grommelant."],"phonetique":"/ʁɔ̃.ʃɔ̃/","etymologie":"Dérivé de ronchonner, d\'origine onomatopéique (Sud-Est).","registre":"familier","niveau":2,"themes":["emotions","quotidien"],"synonymes":["grognon","bougon","râleur","grincheux"],"antonymes":["affable","enjoué","avenant"],"exemplesCorrects":["Il est toujours un peu ronchon avant son premier café.","Ne sois pas si ronchon, la journée commence à peine.","Sous ses airs ronchons, c\'est un homme très généreux."],"exemplesIncorrects":["Le ciel ronchon annonçait une belle journée ensoleillée.","Cette tarte ronchon était délicieusement sucrée."],"distracteurs":["cochon","torchon","bouchon"],"anecdote":"Blanche-Neige a popularisé le ronchon par excellence : Grincheux, le nain perpétuellement de mauvaise humeur."},{"id":"trifouiller","mot":"trifouiller","nature":"verbe","definitions":["Fouiller, remuer en désordre, manipuler maladroitement."],"phonetique":"/tʁi.fu.je/","etymologie":"Mot-valise de tripoter et fouiller.","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["fouiller","fureter","tripoter","farfouiller"],"antonymes":["ranger","ordonner"],"exemplesCorrects":["Il a trifouillé dans le tiroir pendant dix minutes sans rien trouver.","Arrête de trifouiller les fils, tu vas tout débrancher.","Qui a encore trifouillé dans mes affaires ?"],"exemplesIncorrects":["Elle a trifouillé un magnifique discours pour la cérémonie.","Le soleil trifouillait à l\'horizon au lever du jour."],"distracteurs":["gribouiller","tortiller","trinquer","tricoter"],"anecdote":"Le français regorge de ces verbes expressifs en -ouiller — farfouiller, gribouiller, patouiller — où le suffixe ajoute une nuance de désordre brouillon."},{"id":"loustic","mot":"loustic","nature":"nom masculin","definitions":["Individu peu sérieux, plaisantin.","Personnage dont on se méfie un peu."],"phonetique":"/lus.tik/","etymologie":"De l\'allemand lustig, « joyeux, gai », introduit par les soldats.","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["plaisantin","farceur","luron","zigoto"],"antonymes":["pince-sans-rire","rabat-joie"],"exemplesCorrects":["C\'est un sacré loustic, toujours prêt à faire le pitre.","Quel est le loustic qui a caché mes clés ?","Méfie-toi de ce loustic, il n\'en fait qu\'à sa tête."],"exemplesIncorrects":["Il a dégusté un loustic bien frais en terrasse.","La loustic de la voiture était à plat ce matin."],"distracteurs":["rustique","élastique","moustique"],"anecdote":"Dans les régiments d\'autrefois, le « loustic » était le farceur de la compagnie, chargé d\'égayer la troupe : le sens s\'est ensuite élargi."},{"id":"chambouler","mot":"chambouler","nature":"verbe","definitions":["Bouleverser, mettre sens dessus dessous."],"phonetique":"/ʃɑ̃.bu.le/","etymologie":"Probablement croisement de chambarder et de bouler.","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["bouleverser","chambarder","renverser","perturber"],"antonymes":["ordonner","stabiliser","ranger"],"exemplesCorrects":["Cette nouvelle a chamboulé tous nos projets de vacances.","Le déménagement a chamboulé les habitudes de la famille.","Il est resté tout chamboulé après cette rencontre inattendue."],"exemplesIncorrects":["Elle a chamboulé une tarte aux pommes pour le dessert.","Le lac chamboulait paisiblement sous la lune."],"distracteurs":["chamailler","chambrer","bousculer"],"anecdote":"Le « chamboule-tout », jeu de fête foraine où l\'on renverse des boîtes, doit évidemment son nom à ce verbe."},{"id":"palimpseste","mot":"palimpseste","nature":"nom masculin","definitions":["Manuscrit dont on a effacé le premier texte pour en écrire un autre.","Œuvre dont on perçoit les états antérieurs sous la version finale."],"phonetique":"/pa.lɛ̃p.sɛst/","etymologie":"Du grec palimpsêstos, « gratté de nouveau », de palin (de nouveau) et psên (gratter).","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["manuscrit gratté"],"antonymes":[],"exemplesCorrects":["Sous la prière médiévale, les chercheurs ont retrouvé un palimpseste d\'Archimède.","La ville est un palimpseste où chaque époque a laissé sa trace.","Son roman se lit comme un palimpseste, hanté par ses lectures."],"exemplesIncorrects":["Il a commandé un palimpseste de jambon à la charcuterie.","Le palimpseste soufflait fort sur la côte cette nuit-là."],"distracteurs":["pamphlet","parchemin","palissade"],"anecdote":"Parce que le parchemin coûtait cher, les moines grattaient les textes antiques pour réécrire dessus : on a ainsi failli perdre, puis retrouvé, des œuvres entières."},{"id":"deliquescence","mot":"déliquescence","nature":"nom féminin","definitions":["État de décadence, de déchéance avancée.","Propriété d\'un corps qui fond en absorbant l\'humidité de l\'air."],"phonetique":"/de.li.kɛ.sɑ̃s/","etymologie":"Du latin deliquescere, « se liquéfier, fondre ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["décadence","déchéance","délabrement","ruine"],"antonymes":["essor","apogée","vigueur"],"exemplesCorrects":["L\'empire glissait lentement vers la déliquescence.","La déliquescence des institutions inquiétait les observateurs.","On assistait, impuissant, à la déliquescence de ses facultés."],"exemplesIncorrects":["Il a célébré la déliquescence éclatante de son équipe victorieuse.","La déliquescence du sportif lui valut une médaille d\'or."],"distracteurs":["réminiscence","quintessence","luminescence"],"anecdote":"Le mot a d\'abord été chimique : certains sels, dits déliquescents, se dissolvent dans l\'eau qu\'ils captent à l\'air. La métaphore morale est venue ensuite."},{"id":"fuligineux","mot":"fuligineux","nature":"adjectif","definitions":["Qui produit ou rappelle la suie ; noirâtre.","Obscur, confus, en parlant de l\'esprit ou du style."],"phonetique":"/fy.li.ʒi.nø/","etymologie":"Du latin fuligo, « suie ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["enfumé","noirâtre","obscur","ténébreux"],"antonymes":["limpide","clair","lumineux"],"exemplesCorrects":["Une fumée fuligineuse s\'échappait des cheminées de l\'usine.","Le ciel fuligineux annonçait l\'orage.","Il se perdait dans des raisonnements fuligineux dont nul ne sortait."],"exemplesIncorrects":["Le diamant fuligineux jetait mille éclats au soleil.","Elle servit un dessert fuligineux et sucré à souhait."],"distracteurs":["vertigineux","ferrugineux","oléagineux"],"anecdote":"Les médecins anciens parlaient d\'haleine « fuligineuse » dans les fièvres : la langue s\'y couvrait comme d\'un dépôt de suie."},{"id":"abscons","mot":"abscons","nature":"adjectif","definitions":["Difficile à comprendre, obscur, peu intelligible."],"phonetique":"/aps.kɔ̃/","etymologie":"Du latin absconsus, « caché, dérobé ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["obscur","abstrus","hermétique","sibyllin"],"antonymes":["limpide","clair","accessible"],"exemplesCorrects":["Le rapport était rédigé dans un jargon abscons.","Ses explications absconses ont laissé l\'auditoire perplexe.","Pourquoi rendre abscons ce qui pourrait être dit simplement ?"],"exemplesIncorrects":["Le ciel abscons promettait une journée radieuse.","Il a couru un marathon abscons en un temps record."],"distracteurs":["abscisse","fécond","abondant"],"anecdote":"« Abscons » et « caché » sont cousins : la racine latine se retrouve dans « absconse », la petite lanterne dont les moines masquaient la flamme."},{"id":"thaumaturge","mot":"thaumaturge","nature":"nom masculin","definitions":["Personne qui fait ou prétend faire des miracles."],"phonetique":"/to.ma.tyʁʒ/","etymologie":"Du grec thauma, « prodige », et ergon, « œuvre ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["faiseur de miracles","magicien","guérisseur"],"antonymes":["sceptique","rationaliste"],"exemplesCorrects":["La foule accourait vers le thaumaturge qui guérissait, disait-on, par l\'imposition des mains.","On le traitait de thaumaturge tant ses remèdes paraissaient miraculeux.","Le roman met en scène un thaumaturge ambigu, entre saint et imposteur."],"exemplesIncorrects":["Il a réparé le thaumaturge de la cuisine en deux minutes.","Le thaumaturge soufflait en tempête sur la baie."],"distracteurs":["dramaturge","démiurge","thérapeute"],"anecdote":"Les rois de France étaient réputés thaumaturges : on croyait qu\'ils guérissaient les écrouelles d\'un simple toucher, en disant « le roi te touche, Dieu te guérit »."},{"id":"anachorete","mot":"anachorète","nature":"nom masculin","definitions":["Religieux retiré dans la solitude ; par extension, personne qui vit à l\'écart du monde."],"phonetique":"/a.na.kɔ.ʁɛt/","etymologie":"Du grec anakhōrêtês, « celui qui se retire ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["ermite","solitaire","reclus","cénobite"],"antonymes":["mondain","sociable"],"exemplesCorrects":["Il vivait en anachorète, loin de toute agitation, parmi ses livres.","Les premiers anachorètes se retiraient au désert pour prier.","Depuis sa retraite, elle menait une existence d\'anachorète."],"exemplesIncorrects":["Il a commandé un anachorète bien cuit au restaurant.","L\'anachorète de l\'autoroute était saturé aux heures de pointe."],"distracteurs":["anachronisme","catéchèse","anchois"],"anecdote":"On oppose l\'anachorète, qui vit seul, au cénobite, qui vit en communauté : deux manières opposées d\'embrasser la vie monastique."},{"id":"matois","mot":"matois","nature":"adjectif","definitions":["Rusé et malin sous une apparence bonhomme."],"phonetique":"/ma.twa/","etymologie":"Origine incertaine, peut-être de l\'argot mate, « lieu de rencontre des filous ».","registre":"littéraire","niveau":4,"themes":["litteraire"],"synonymes":["rusé","finaud","madré","roublard"],"antonymes":["naïf","candide","ingénu"],"exemplesCorrects":["Le paysan matois feignait de ne rien comprendre pour mieux marchander.","Un sourire matois éclairait son visage ridé.","Sous des dehors placides, c\'était un négociateur matois."],"exemplesIncorrects":["Le ciel matois laissait présager un orage violent.","Elle a préparé un gratin matois et savoureux."],"distracteurs":["matelas","patois","matelot","matité"],"anecdote":"Le « compère matois » est un personnage récurrent des fables et des contes, cousin du renard goupil, toujours plus malin que ses dupes."},{"id":"fatras","mot":"fatras","nature":"nom masculin","definitions":["Amas confus et désordonné de choses ou d\'idées."],"phonetique":"/fa.tʁa/","etymologie":"De l\'ancien français, peut-être du latin farsura, « remplissage ».","registre":"soutenu","niveau":4,"themes":["abstrait","quotidien"],"synonymes":["amas","fouillis","bric-à-brac","capharnaüm"],"antonymes":["ordre","classement"],"exemplesCorrects":["Il fouillait dans un fatras de vieux papiers.","Son exposé n\'était qu\'un fatras d\'idées mal reliées.","Au grenier s\'entassait un fatras d\'objets oubliés."],"exemplesIncorrects":["Elle a savouré un fatras délicieux au dessert.","Le fatras coulait limpide entre les rochers."],"distracteurs":["fracas","matelas","fatigue"],"anecdote":"Au Moyen Âge, le « fatras » était un genre poétique fait d\'assemblages cocasses : le sens de désordre lui est resté."},{"id":"cenacle","mot":"cénacle","nature":"nom masculin","definitions":["Cercle restreint d\'écrivains, d\'artistes ou de penseurs réunis par une même affinité."],"phonetique":"/se.nakl/","etymologie":"Du latin cenaculum, « salle à manger à l\'étage », puis salle de la Cène.","registre":"littéraire","niveau":4,"themes":["litteraire"],"synonymes":["cercle","coterie","chapelle","aréopage"],"antonymes":["foule","grand public"],"exemplesCorrects":["Les jeunes romantiques se retrouvaient dans le cénacle de Victor Hugo.","Ce prix est décerné par un cénacle de happy few.","Loin des cénacles parisiens, il écrivait dans une solitude choisie."],"exemplesIncorrects":["Il a réparé le cénacle de la voiture au garage.","Le cénacle de l\'orage gronda toute la nuit."],"distracteurs":["tabernacle","obstacle","pinacle"],"anecdote":"Le mot vient de la salle où eut lieu la Cène ; il désigne aujourd\'hui tout petit cercle d\'initiés, souvent littéraire."},{"id":"sentencieux","mot":"sentencieux","nature":"adjectif","definitions":["Qui s\'exprime par maximes, avec une gravité affectée et un ton de leçon."],"phonetique":"/sɑ̃.tɑ̃.sjø/","etymologie":"Du latin sententiosus, « riche en pensées », de sententia.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["doctoral","moralisateur","solennel","pontifiant"],"antonymes":["léger","badin","spontané"],"exemplesCorrects":["Il prit un ton sentencieux pour énoncer des évidences.","Ces maximes sentencieuses finissaient par lasser l\'auditoire.","Rien n\'agace comme un conseil donné d\'un air sentencieux."],"exemplesIncorrects":["Le gâteau sentencieux fondait délicieusement en bouche.","Une pluie sentencieuse arrosa les jardins tout l\'après-midi."],"distracteurs":["silencieux","consciencieux","sentimental"],"anecdote":"Le mot dérive de « sentence » au sens de maxime : le sentencieux multiplie les formules définitives comme s\'il rendait un verdict."},{"id":"rebarbatif","mot":"rébarbatif","nature":"adjectif","definitions":["D\'un abord rebutant, désagréable.","Ennuyeux, aride, en parlant d\'un sujet ou d\'un texte."],"phonetique":"/ʁe.baʁ.ba.tif/","etymologie":"De l\'ancien français se rebarber, « tenir tête, barbe contre barbe ».","registre":"soutenu","niveau":4,"themes":["abstrait","quotidien"],"synonymes":["rebutant","revêche","aride","ingrat"],"antonymes":["engageant","avenant","attrayant"],"exemplesCorrects":["Derrière des dehors rébarbatifs, le concierge était plein d\'attentions.","La grammaire lui semblait une matière rébarbative.","Le règlement, rébarbatif au possible, décourageait toute lecture."],"exemplesIncorrects":["Elle a passé des vacances rébarbatives et reposantes au soleil.","Ce dessert rébarbatif était d\'une douceur exquise."],"distracteurs":["réparateur","barbare","récapitulatif"],"anecdote":"L\'image est savoureuse : se « rebarber », c\'était autrefois s\'affronter de si près que les barbes se touchaient, d\'où l\'idée d\'un contact hérissé."},{"id":"serendipite","mot":"sérendipité","nature":"nom féminin","definitions":["Don de faire par hasard des découvertes heureuses et inattendues."],"phonetique":"/se.ʁɛ̃.di.pi.te/","etymologie":"De l\'anglais serendipity, forgé par Horace Walpole d\'après le conte Les Trois Princes de Serendip.","registre":"soutenu","niveau":4,"themes":["abstrait","emprunts"],"synonymes":["heureux hasard","fortuité"],"antonymes":["malchance","méthode"],"exemplesCorrects":["La pénicilline doit beaucoup à la sérendipité de Fleming.","C\'est par pure sérendipité qu\'elle a trouvé ce manuscrit oublié.","Flâner en librairie, c\'est s\'offrir une chance de sérendipité."],"exemplesIncorrects":["Il a rempli le réservoir de sérendipité avant de partir.","La sérendipité de la soupe manquait un peu de sel."],"distracteurs":["sérénité","serpentin","disparité"],"anecdote":"Walpole inventa le mot en 1754 dans une lettre, à partir d\'un conte persan où trois princes font sans cesse des trouvailles inattendues."},{"id":"amenite","mot":"aménité","nature":"nom féminin","definitions":["Amabilité, douceur dans les manières et le caractère.","Au pluriel et par ironie : paroles désobligeantes."],"phonetique":"/a.me.ni.te/","etymologie":"Du latin amoenitas, « agrément, charme ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["amabilité","affabilité","courtoisie","douceur"],"antonymes":["rudesse","âpreté","acrimonie"],"exemplesCorrects":["Il recevait ses hôtes avec une aménité de tous les instants.","Elle répondit avec aménité aux questions les plus insistantes.","Les deux adversaires s\'échangèrent quelques aménités peu amènes."],"exemplesIncorrects":["L\'aménité du moteur l\'empêchait de démarrer.","Il a planté une aménité au fond du jardin."],"distracteurs":["amnistie","affinité","annuité"],"anecdote":"Par antiphrase, « échanger des aménités » signifie souvent tout le contraire : se lancer des amabilités acerbes."},{"id":"dereliction","mot":"déréliction","nature":"nom féminin","definitions":["État d\'abandon et de solitude morale extrême."],"phonetique":"/de.ʁe.lik.sjɔ̃/","etymologie":"Du latin derelictio, « abandon total ».","registre":"littéraire","niveau":5,"themes":["emotions","litteraire","abstrait"],"synonymes":["abandon","délaissement","isolement","déshérence"],"antonymes":["réconfort","secours","soutien"],"exemplesCorrects":["Il connut, dans l\'exil, une déréliction sans nom.","La déréliction du malade abandonné de tous serrait le cœur.","Le poème dit la déréliction de l\'âme privée de toute espérance."],"exemplesIncorrects":["La déréliction de la fête battait son plein jusqu\'à l\'aube.","Il a savouré sa déréliction éclatante après la victoire."],"distracteurs":["dérision","prédiction","déréglementation"],"anecdote":"Le mot a une forte charge spirituelle : on parle de la déréliction du Christ en croix, dans le cri « pourquoi m\'as-tu abandonné ? »."},{"id":"allegresse","mot":"allégresse","nature":"nom féminin","definitions":["Joie vive qui se manifeste au-dehors, gaieté débordante."],"phonetique":"/a.le.ɡʁɛs/","etymologie":"De l\'ancien français alegresse, de alègre, du latin alacer, « vif, gai ».","registre":"soutenu","niveau":2,"themes":["emotions"],"synonymes":["liesse","jubilation","exultation","gaieté"],"antonymes":["tristesse","abattement","morosité"],"exemplesCorrects":["Une allégresse générale saisit la foule à l\'annonce de la victoire.","Les enfants couraient dans le jardin avec une allégresse communicative.","Le retour du printemps le remplissait d\'une allégresse enfantine."],"exemplesIncorrects":["Il a annoncé la nouvelle avec une profonde allégresse et beaucoup de larmes.","L\'allégresse de l\'examen raté pesait sur tout le groupe."],"distracteurs":["allégeance","agilité","âpreté"],"anecdote":"L\'allégresse partage sa racine avec « allègre » et « alacrité » : toutes disent une légèreté vive, presque dansante."},{"id":"courroux","mot":"courroux","nature":"nom masculin","definitions":["Vive colère, indignation."],"phonetique":"/ku.ʁu/","etymologie":"De l\'ancien français corouz, du latin populaire corruptiare, « gâter, irriter ».","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["colère","ire","fureur","indignation"],"antonymes":["sérénité","calme","mansuétude"],"exemplesCorrects":["Le courroux du roi s\'abattit sur les conspirateurs.","Elle contint son courroux et répondit d\'une voix glacée.","Rien n\'apaisait le courroux des dieux, disait le poète."],"exemplesIncorrects":["Il a accueilli ses amis avec un courroux chaleureux.","Le courroux du soleil rendait la promenade agréable."],"distracteurs":["courroie","concours","secours"],"anecdote":"Mot du registre épique, le courroux est celui d\'Achille dans l\'Iliade : la colère qui ouvre toute la littérature occidentale."},{"id":"depit","mot":"dépit","nature":"nom masculin","definitions":["Chagrin mêlé de contrariété, causé par une déception ou une vexation."],"phonetique":"/de.pi/","etymologie":"Du latin despectus, « mépris, action de regarder de haut ».","registre":"courant","niveau":3,"themes":["emotions"],"synonymes":["amertume","rancœur","vexation","déconvenue"],"antonymes":["satisfaction","contentement"],"exemplesCorrects":["Par dépit, elle déchira la lettre sans la lire.","Il accepta la défaite avec un dépit mal dissimulé.","Le dépit amoureux est un grand pourvoyeur de mauvaises décisions."],"exemplesIncorrects":["Quel dépit de gagner enfin le concours tant convoité !","Il sauta de dépit en apprenant son augmentation."],"distracteurs":["débit","répit","déni"],"anecdote":"La locution « en dépit de », qui signifie « malgré », garde la trace du sens premier de mépris : agir au mépris de quelque chose."},{"id":"langueur","mot":"langueur","nature":"nom féminin","definitions":["Abattement physique ou moral, mélancolie douce.","Manque d\'énergie, d\'entrain."],"phonetique":"/lɑ̃.ɡœʁ/","etymologie":"Du latin languor, « faiblesse, abattement ».","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["alanguissement","torpeur","mélancolie","atonie"],"antonymes":["vigueur","ardeur","entrain"],"exemplesCorrects":["Une douce langueur l\'envahissait aux heures chaudes de l\'après-midi.","Il y avait dans son regard une langueur romantique.","La langueur de l\'été semblait suspendre le temps."],"exemplesIncorrects":["Il a remporté la course avec une langueur impressionnante.","La langueur du moteur faisait trembler toute la voiture."],"distracteurs":["longueur","candeur","ardeur"],"anecdote":"« Les sanglots longs des violons de l\'automne blessent mon cœur d\'une langueur monotone » : Verlaine a fixé pour toujours la couleur du mot."},{"id":"liesse","mot":"liesse","nature":"nom féminin","definitions":["Joie collective et débordante, allégresse partagée."],"phonetique":"/ljɛs/","etymologie":"De l\'ancien français leece, du latin laetitia, « joie ».","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["allégresse","jubilation","exultation"],"antonymes":["affliction","désolation"],"exemplesCorrects":["La ville était en liesse après le sacre de son équipe.","Une foule en liesse accompagnait le cortège.","Ce fut un soir de liesse, de chants et de danses."],"exemplesIncorrects":["Il a appris la triste nouvelle dans une grande liesse.","Seul dans sa chambre, il ressentait une liesse silencieuse et solitaire."],"distracteurs":["laisse","paresse","lisse"],"anecdote":"On emploie presque toujours « liesse » dans la locution « en liesse » : le mot ne vit guère qu\'au cœur des foules en fête."},{"id":"felicite","mot":"félicité","nature":"nom féminin","definitions":["Bonheur complet et durable ; état de parfaite satisfaction."],"phonetique":"/fe.li.si.te/","etymologie":"Du latin felicitas, « bonheur, chance », de felix, « heureux, fertile ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["béatitude","bonheur","plénitude","contentement"],"antonymes":["malheur","infortune","détresse"],"exemplesCorrects":["Ils goûtaient dans cette retraite une félicité parfaite.","La félicité conjugale qu\'on lui prêtait n\'était qu\'apparente.","Les Anciens plaçaient la félicité dans la sagesse, non dans les biens."],"exemplesIncorrects":["Il a vécu une félicité atroce après son accident.","La félicité de la défaite l\'a plongé dans le désespoir."],"distracteurs":["facilité","fébrilité","publicité"],"anecdote":"Les « félicitations » que l\'on adresse aujourd\'hui dérivent de ce mot : c\'était à l\'origine souhaiter à autrui la félicité."},{"id":"desarroi","mot":"désarroi","nature":"nom masculin","definitions":["Trouble profond, désorganisation morale qui ôte tout repère."],"phonetique":"/de.za.ʁwa/","etymologie":"De l\'ancien français desarroyer, « mettre en désordre », de arroi, « arrangement ».","registre":"courant","niveau":3,"themes":["emotions"],"synonymes":["détresse","trouble","confusion","égarement"],"antonymes":["assurance","sérénité","sang-froid"],"exemplesCorrects":["La nouvelle la laissa dans un désarroi total.","On lisait le désarroi sur le visage des rescapés.","Devant tant de choix, il éprouvait un certain désarroi."],"exemplesIncorrects":["Il a rangé son bureau avec un désarroi méthodique.","Le désarroi du paysage ensoleillé invitait à la promenade."],"distracteurs":["désaveu","désarmoi","convoi"],"anecdote":"Le mot vient de l\'ancien « arroi », l\'équipement et l\'ordre d\'une troupe : être en désarroi, c\'était d\'abord avoir rompu les rangs."},{"id":"emoi","mot":"émoi","nature":"nom masculin","definitions":["Trouble, agitation causés par une émotion vive."],"phonetique":"/e.mwa/","etymologie":"De l\'ancien français esmai, de esmayer, « troubler, effrayer ».","registre":"soutenu","niveau":3,"themes":["emotions","litteraire"],"synonymes":["agitation","trouble","effervescence","émotion"],"antonymes":["calme","quiétude","impassibilité"],"exemplesCorrects":["Sa déclaration mit toute l\'assemblée en émoi.","Le quartier était en émoi après l\'étrange disparition.","Un doux émoi la saisit lorsqu\'il entra."],"exemplesIncorrects":["Il a classé ses dossiers dans un émoi parfait.","L\'émoi du lac, parfaitement plat, reflétait les montagnes."],"distracteurs":["envoi","emploi","octroi"],"anecdote":"On retrouve « émoi » dans l\'expression « tout en émoi », et son cousin verbal « s\'émouvoir » : la même racine que l\'anglais dismay."},{"id":"leitmotiv","mot":"leitmotiv","nature":"nom masculin","definitions":["Formule, idée qui revient sans cesse dans un discours, une œuvre.","Thème musical récurrent associé à un personnage ou à une situation."],"phonetique":"/lajt.mo.tiv/","etymologie":"De l\'allemand Leitmotiv, « motif conducteur », de leiten, « conduire ».","registre":"courant","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["refrain","rengaine","thème récurrent"],"antonymes":[],"exemplesCorrects":["« La sécurité d\'abord » était devenu le leitmotiv de la campagne.","Wagner a porté le leitmotiv musical à son apogée.","Le retour à la nature est le leitmotiv de tout le roman."],"exemplesIncorrects":["Il a réparé le leitmotiv crevé de son vélo.","Le leitmotiv soufflait fort sur la côte cette nuit-là."],"distracteurs":["lénifiant","diktat","laïus"],"anecdote":"Le terme est né dans l\'analyse des opéras de Wagner avant de gagner le langage courant pour désigner toute idée fixe."},{"id":"zeitgeist","mot":"zeitgeist","nature":"nom masculin","definitions":["Esprit d\'une époque, climat intellectuel et culturel d\'un temps donné."],"phonetique":"/zajt.ɡajst/","etymologie":"De l\'allemand Zeit, « temps », et Geist, « esprit ».","registre":"soutenu","niveau":5,"themes":["emprunts","abstrait"],"synonymes":["esprit du temps","air du temps"],"antonymes":[],"exemplesCorrects":["Ce film a parfaitement capté le zeitgeist des années folles.","Difficile d\'échapper au zeitgeist de son époque.","Le philosophe analysait le zeitgeist d\'un siècle inquiet."],"exemplesIncorrects":["Il a commandé un zeitgeist bien frais en terrasse.","Le zeitgeist de la rivière reflétait le ciel d\'été."],"distracteurs":["zénith","gestalt","ersatz"],"anecdote":"Popularisé par les philosophes allemands romantiques, le mot dit que chaque époque respire un même air, perceptible après coup."},{"id":"farniente","mot":"farniente","nature":"nom masculin","definitions":["Douce oisiveté, plaisir de ne rien faire."],"phonetique":"/faʁ.njɛnt/","etymologie":"De l\'italien far niente, « ne rien faire ».","registre":"familier","niveau":4,"themes":["emprunts","quotidien"],"synonymes":["oisiveté","paresse","désœuvrement","flânerie"],"antonymes":["labeur","activité","affairement"],"exemplesCorrects":["Après des mois de travail, il s\'offrit une semaine de pur farniente.","Le farniente sur la plage, à l\'ombre d\'un parasol, voilà son idéal.","Rien de tel qu\'un dimanche de farniente pour récupérer."],"exemplesIncorrects":["Il a couru le farniente en moins de quatre heures.","Le farniente du chantier a duré toute la semaine, sans répit."],"distracteurs":["fariboles","dolce vita","ferraille"],"anecdote":"L\'italien a légué au français cet art de l\'oisiveté heureuse, cousin du « dolce far niente », la douceur de ne rien faire."},{"id":"flegme","mot":"flegme","nature":"nom masculin","definitions":["Calme imperturbable, maîtrise de soi devant l\'agitation ou l\'adversité."],"phonetique":"/flɛɡm/","etymologie":"Du grec phlegma, « humeur froide », l\'une des quatre humeurs de la médecine antique.","registre":"courant","niveau":4,"themes":["emotions","emprunts"],"synonymes":["sang-froid","impassibilité","placidité","calme"],"antonymes":["fébrilité","emportement","nervosité"],"exemplesCorrects":["Il accueillit la mauvaise nouvelle avec un flegme tout britannique.","Son flegme en pleine tempête rassurait l\'équipage.","Rien n\'entame le flegme de ce vieux diplomate."],"exemplesIncorrects":["Il bondit de son siège avec un flegme incontrôlable.","Le flegme du volcan en éruption était terrifiant."],"distracteurs":["phlox","fragment","flemme"],"anecdote":"Pour les médecins anciens, l\'excès de « phlegme » donnait un tempérament froid et lent : le flegmatique d\'aujourd\'hui en a hérité le calme."},{"id":"aficionado","mot":"aficionado","nature":"nom masculin","definitions":["Amateur passionné et averti d\'un domaine, d\'une discipline."],"phonetique":"/a.fi.sjo.na.do/","etymologie":"Mot espagnol, de afición, « passion », du latin affectio.","registre":"courant","niveau":4,"themes":["emprunts"],"synonymes":["passionné","fervent","mordu","connaisseur"],"antonymes":["néophyte","indifférent"],"exemplesCorrects":["C\'est un aficionado de jazz qui connaît chaque enregistrement.","Les aficionados se pressaient aux arènes dès l\'aube.","En véritable aficionado, il distinguait les crus les yeux fermés."],"exemplesIncorrects":["Il a réparé l\'aficionado de la cuisine en deux minutes.","L\'aficionado tombait à gros flocons sur la ville."],"distracteurs":["aficio","incognito","desperado"],"anecdote":"Le mot vient de l\'univers de la corrida, où l\'aficionado est le spectateur connaisseur ; il s\'est étendu à toutes les passions."},{"id":"maelstrom","mot":"maelström","nature":"nom masculin","definitions":["Tourbillon marin puissant.","Tourbillon d\'événements, agitation qui emporte tout."],"phonetique":"/ma.ɛl.stʁɔm/","etymologie":"Du néerlandais, nom d\'un tourbillon célèbre des côtes norvégiennes.","registre":"littéraire","niveau":5,"themes":["emprunts","nature"],"synonymes":["tourbillon","maelstrom","remous","gouffre"],"antonymes":["calme plat","étale"],"exemplesCorrects":["Le navire fut aspiré par un maelström terrifiant.","Il se sentait happé par le maelström de la grande ville.","La crise plongea le pays dans un maelström d\'incertitudes."],"exemplesIncorrects":["Il a savouré un maelström bien sucré au dessert.","Le maelström de la prairie ondulait paisiblement au vent."],"distracteurs":["mausolée","marasme","mausoleum","mastodonte"],"anecdote":"Edgar Poe a immortalisé le mot dans « Une descente dans le Maelström », récit d\'un pêcheur happé par le gouffre."},{"id":"chocolatine","mot":"chocolatine","nature":"nom féminin","definitions":["Dans le Sud-Ouest, viennoiserie feuilletée fourrée au chocolat (ailleurs « pain au chocolat »)."],"phonetique":"/ʃɔ.kɔ.la.tin/","etymologie":"Dérivé de chocolat ; usage régional du Sud-Ouest et du Québec.","registre":"courant","niveau":2,"themes":["regionalismes","quotidien"],"synonymes":["pain au chocolat","petit pain"],"antonymes":[],"exemplesCorrects":["À Toulouse, on commande une chocolatine, pas un pain au chocolat.","Le boulanger sort une fournée de chocolatines encore tièdes.","La querelle chocolatine contre pain au chocolat divise la France."],"exemplesIncorrects":["Il a garé sa chocolatine devant la mairie.","La chocolatine de la rivière était en crue ce matin."],"distracteurs":["clémentine","tartine","praline"],"anecdote":"La rivalité entre « chocolatine » et « pain au chocolat » est si vive qu\'elle a fait l\'objet de propositions de loi, mi-sérieuses, à l\'Assemblée."},{"id":"tuque","mot":"tuque","nature":"nom féminin","definitions":["Au Québec, bonnet de laine ajusté, porté l\'hiver."],"phonetique":"/tyk/","etymologie":"Mot québécois, altération de toque, « coiffe sans bord ».","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["bonnet","toque"],"antonymes":[],"exemplesCorrects":["Mets ta tuque, il fait moins vingt dehors !","Il a perdu sa tuque en faisant de la luge.","Une belle tuque rouge lui couvrait les oreilles."],"exemplesIncorrects":["Il a bu une tuque bien chaude en rentrant.","La tuque de la voiture était à plat ce matin."],"distracteurs":["tunique","truc","tuile"],"anecdote":"L\'expression québécoise « attache ta tuque ! » signifie « accroche-toi, ça va secouer » : la tuque y devient symbole de préparation."},{"id":"depanneur","mot":"dépanneur","nature":"nom masculin","definitions":["Au Québec, petite épicerie de proximité ouverte tard."],"phonetique":"/de.pa.nœʁ/","etymologie":"Dérivé de dépanner : le commerce qui « dépanne » à toute heure.","registre":"courant","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["épicerie","supérette"],"antonymes":[],"exemplesCorrects":["Je passe au dépanneur chercher du lait avant la fermeture.","Le dépanneur du coin est ouvert jusqu\'à minuit.","Au Québec, le dépanneur fait partie du paysage de quartier."],"exemplesIncorrects":["Le dépanneur soufflait en tempête sur le fleuve.","Il a planté un dépanneur au fond de son jardin."],"distracteurs":["dépanneuse","déménageur","démarcheur"],"anecdote":"En France, « dépanneur » désigne plutôt celui qui répare ; au Québec, c\'est le lieu où l\'on se dépanne d\'un achat de dernière minute."},{"id":"chicon","mot":"chicon","nature":"nom masculin","definitions":["En Belgique et dans le nord de la France, endive."],"phonetique":"/ʃi.kɔ̃/","etymologie":"De la famille de chicorée, dont l\'endive est issue.","registre":"courant","niveau":3,"themes":["regionalismes","quotidien"],"synonymes":["endive"],"antonymes":[],"exemplesCorrects":["Ce soir, on mange des chicons au gratin.","Au marché, les chicons bien blancs partent les premiers.","Le chicon se cultive à l\'abri de la lumière pour rester pâle."],"exemplesIncorrects":["Il a réglé son chicon d\'électricité à temps.","Le chicon de la voiture refusait de démarrer."],"distracteurs":["cochon","flacon","chignon"],"anecdote":"« Chicon au gratin », roulé dans du jambon, est un classique de la cuisine belge ; ailleurs on dira « endives au jambon »."},{"id":"wassingue","mot":"wassingue","nature":"nom féminin","definitions":["Dans le Nord, serpillière, toile dont on lave les sols."],"phonetique":"/wa.sɛ̃ɡ/","etymologie":"Du flamand, « toile à laver », de la famille de wassen, « laver ».","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["serpillière","panosse","wassingue"],"antonymes":[],"exemplesCorrects":["Passe un coup de wassingue, le carrelage est tout sale.","Elle essorait la wassingue au-dessus du seau.","Dans le Nord, on dit wassingue là où d\'autres disent serpillière."],"exemplesIncorrects":["Il a dégusté une wassingue bien fraîche au dessert.","La wassingue du ciel annonçait une belle journée."],"distracteurs":["meringue","seringue","wagon"],"anecdote":"La France compte une mosaïque de mots pour la serpillière : wassingue dans le Nord, panosse en Suisse, cinse, loque ou pièce ailleurs."},{"id":"septante","mot":"septante","nature":"adjectif","definitions":["En Belgique et en Suisse, le nombre soixante-dix."],"phonetique":"/sɛp.tɑ̃t/","etymologie":"Du latin septuaginta, « soixante-dix ».","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["soixante-dix"],"antonymes":[],"exemplesCorrects":["En Belgique, on dit septante-cinq pour soixante-quinze.","Ma grand-mère suisse a fêté ses septante ans.","Septante est plus régulier que l\'étrange soixante-dix français."],"exemplesIncorrects":["Il a acheté une septante toute neuve au marché.","La septante du moteur faisait un bruit inquiétant."],"distracteurs":["soixante","septembre","nonante"],"anecdote":"Le français de France a gardé « soixante-dix » et « quatre-vingt-dix », vestiges d\'un comptage par vingt ; la Belgique et la Suisse ont préféré la logique latine."},{"id":"ressac","mot":"ressac","nature":"nom masculin","definitions":["Retour violent des vagues qui se brisent contre un obstacle et refluent."],"phonetique":"/ʁə.sak/","etymologie":"De l\'espagnol resaca, « ressac, reflux ».","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["reflux","remous","ressaut"],"antonymes":["étale"],"exemplesCorrects":["Le ressac arrachait des galets à chaque vague.","On entendait, la nuit, le ressac régulier contre la digue.","Les nageurs se méfiaient du ressac près des rochers."],"exemplesIncorrects":["Il a servi un ressac bien frais à ses invités.","Le ressac de la forêt embaumait la résine."],"distracteurs":["ressort","bivouac","hamac"],"anecdote":"Par métaphore, on parle du « ressac » d\'une émotion ou d\'un souvenir qui revient en force après avoir semblé se retirer."},{"id":"frimas","mot":"frimas","nature":"nom masculin","definitions":["Brouillard froid qui se congèle en fine glace ; froid de l\'hiver."],"phonetique":"/fʁi.ma/","etymologie":"De l\'ancien français frime, d\'origine germanique, « brouillard givrant ».","registre":"littéraire","niveau":4,"themes":["nature","litteraire"],"synonymes":["givre","gelée blanche","froidure"],"antonymes":["canicule","tiédeur"],"exemplesCorrects":["Les arbres se couvraient de frimas aux premières gelées.","Emmitouflé, il affrontait les frimas de décembre.","Le frimas argentait les vitres au petit matin."],"exemplesIncorrects":["Il a bronzé sous le frimas éclatant du mois d\'août.","Le frimas tropical rendait la plage étouffante."],"distracteurs":["frimousse","climat","limon"],"anecdote":"Le mot appartient au vocabulaire poétique de l\'hiver, aux côtés de « froidure » et de « giboulée » ; on l\'emploie souvent au pluriel."},{"id":"meandre","mot":"méandre","nature":"nom masculin","definitions":["Sinuosité d\'un cours d\'eau.","Détour compliqué, cheminement tortueux."],"phonetique":"/me.ɑ̃dʁ/","etymologie":"Du nom du Méandre, fleuve très sinueux d\'Asie Mineure.","registre":"courant","niveau":3,"themes":["nature","abstrait"],"synonymes":["sinuosité","détour","lacet","circonvolution"],"antonymes":["ligne droite","raccourci"],"exemplesCorrects":["La rivière dessinait de larges méandres dans la plaine.","Il se perdait dans les méandres de l\'administration.","Suivre les méandres de sa pensée demandait de la patience."],"exemplesIncorrects":["Il a planté un méandre dans son potager au printemps.","Le méandre du soleil illuminait toute la pièce."],"distracteurs":["esclandre","calandre","cylindre"],"anecdote":"Le motif décoratif grec en grecques, fait d\'angles enchaînés, s\'appelle aussi « méandre », du nom du même fleuve capricieux."},{"id":"garrigue","mot":"garrigue","nature":"nom féminin","definitions":["Végétation broussailleuse et odorante des sols calcaires méditerranéens."],"phonetique":"/ɡa.ʁiɡ/","etymologie":"De l\'occitan garriga, terrain planté de chênes kermès.","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["maquis","lande","brousse"],"antonymes":["futaie","prairie grasse"],"exemplesCorrects":["La garrigue embaumait le thym et le romarin sous le soleil.","Ils marchaient dans la garrigue parmi les cigales.","Rien ne pousse mieux dans la garrigue que les plantes aromatiques."],"exemplesIncorrects":["Il a accroché la garrigue au mur du salon.","La garrigue gelée craquait sous les patins."],"distracteurs":["guérite","barrique","garrot"],"anecdote":"On distingue souvent la garrigue, sur calcaire, du maquis, sur sol siliceux : deux paysages méditerranéens aux parfums voisins."},{"id":"zephyr","mot":"zéphyr","nature":"nom masculin","definitions":["Vent doux et agréable, brise légère."],"phonetique":"/ze.fiʁ/","etymologie":"Du grec Zephuros, dieu du vent d\'ouest.","registre":"littéraire","niveau":4,"themes":["nature","litteraire"],"synonymes":["brise","souffle","alizé"],"antonymes":["bourrasque","ouragan","tempête"],"exemplesCorrects":["Un zéphyr printanier agitait à peine les feuilles.","Le zéphyr du soir apportait le parfum des jardins.","Les voiles se gonflaient sous un zéphyr complaisant."],"exemplesIncorrects":["Le zéphyr déracina plusieurs arbres cette nuit-là.","Il a renversé sa tasse à cause du violent zéphyr."],"distracteurs":["saphir","zénith","satyre"],"anecdote":"Dans la mythologie, Zéphyr est le plus doux des vents ; son nom sert encore à vanter la légèreté d\'un tissu ou d\'une brise."},{"id":"houle","mot":"houle","nature":"nom féminin","definitions":["Mouvement ondulant de la mer formé de vagues larges, sans déferlement."],"phonetique":"/ul/","etymologie":"Origine incertaine, peut-être du germanique hol, « creux ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["roulis","vague","ondulation"],"antonymes":["calme plat","mer d\'huile"],"exemplesCorrects":["Le bateau tanguait doucement au gré de la houle.","Une longue houle annonçait la tempête au large.","La houle berçait les barques amarrées au port."],"exemplesIncorrects":["Il a coupé la houle en deux pour la partager.","La houle des montagnes était couverte de neige."],"distracteurs":["boule","foule","houx"],"anecdote":"Par image, une « houle de têtes » ou une « houle humaine » décrit une foule qui ondule comme la mer."},{"id":"prolixe","mot":"prolixe","nature":"adjectif","definitions":["Qui s\'exprime trop longuement, avec un excès de mots."],"phonetique":"/pʁɔ.liks/","etymologie":"Du latin prolixus, « étendu, abondant ».","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["bavard","verbeux","diffus","loquace"],"antonymes":["laconique","concis","succinct"],"exemplesCorrects":["L\'auteur, trop prolixe, dilue ses meilleures idées.","Il fut prolixe sur ses voyages, avare sur ses échecs.","Une préface prolixe décourage parfois la lecture."],"exemplesIncorrects":["Son style prolixe tenait en trois mots cinglants.","Réponse prolixe : il se contenta d\'un hochement de tête."],"distracteurs":["complexe","prolifique","prologue","proche"],"anecdote":"Attention au faux ami : « prolifique » se rapporte à l\'abondance des œuvres, « prolixe » à l\'abondance, souvent excessive, des paroles."},{"id":"laconique","mot":"laconique","nature":"adjectif","definitions":["Qui s\'exprime en peu de mots ; bref et concis."],"phonetique":"/la.kɔ.nik/","etymologie":"De Laconie, région de Sparte dont les habitants passaient pour avares de mots.","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["concis","bref","lapidaire","succinct"],"antonymes":["prolixe","verbeux","bavard"],"exemplesCorrects":["Sa réponse fut laconique : « non ».","Le communiqué, volontairement laconique, n\'expliquait rien.","Il avait l\'art des formules laconiques et définitives."],"exemplesIncorrects":["Son discours laconique a duré plus de deux heures.","Il fut si laconique qu\'on ne put l\'arrêter de parler."],"distracteurs":["ironique","lacustre","canonique"],"anecdote":"Sommés par Philippe de Macédoine de se rendre « si » il entrait en Laconie, les Spartiates répondirent un seul mot : « Si. » Le laconisme en personne."},{"id":"thuriferaire","mot":"thuriféraire","nature":"nom masculin","definitions":["Flatteur empressé, admirateur servile.","Clerc qui porte l\'encensoir lors des cérémonies."],"phonetique":"/ty.ʁi.fe.ʁɛʁ/","etymologie":"Du latin thus, turis, « encens », et ferre, « porter ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["flagorneur","courtisan","laudateur","encenseur"],"antonymes":["détracteur","contempteur","critique"],"exemplesCorrects":["Le ministre était entouré de thuriféraires complaisants.","Loin des thuriféraires, elle préférait les critiques sincères.","L\'écrivain méprisait les thuriféraires qui louaient tout sans lire."],"exemplesIncorrects":["Il a réparé le thuriféraire de la chaudière.","Le thuriféraire de la rivière débordait après l\'orage."],"distracteurs":["vexillaire","secrétaire","tributaire"],"anecdote":"Du clerc qui balance l\'encensoir au flatteur qui « encense » son maître, le mot a glissé du rite religieux à la satire des cours."},{"id":"epigone","mot":"épigone","nature":"nom masculin","definitions":["Successeur ou imitateur sans originalité d\'un maître, d\'une école."],"phonetique":"/e.pi.ɡɔn/","etymologie":"Du grec epigonos, « né après », nom des fils des Sept chefs contre Thèbes.","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["imitateur","suiveur","disciple","continuateur"],"antonymes":["précurseur","initiateur","novateur"],"exemplesCorrects":["Ce peintre n\'est qu\'un épigone des grands maîtres flamands.","Les épigones du romantisme en ont épuisé les recettes.","Mieux vaut un précurseur maladroit qu\'un épigone habile."],"exemplesIncorrects":["Il a commandé un épigone bien cuit au restaurant.","L\'épigone soufflait en tempête sur la baie."],"distracteurs":["épigramme","antigone","épopée"],"anecdote":"Dans la mythologie grecque, les Épigones sont les fils qui reprirent la guerre de leurs pères contre Thèbes : des héritiers, jamais des fondateurs."},{"id":"nonobstant","mot":"nonobstant","nature":"préposition","definitions":["Sans être empêché par ; malgré, en dépit de."],"phonetique":"/nɔ.nɔp.stɑ̃/","etymologie":"De non et de l\'ancien participe obstant, du latin obstare, « faire obstacle ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["malgré","en dépit de","nonobstant"],"antonymes":["à cause de","grâce à"],"exemplesCorrects":["Nonobstant ses réticences, il finit par accepter.","La séance se tint, nonobstant l\'absence du président.","Nonobstant toute clause contraire, l\'accord prévaut."],"exemplesIncorrects":["Il a réparé le nonobstant de la voiture au garage.","Le nonobstant tombait à gros flocons sur la ville."],"distracteurs":["néanmoins","obstiné","nonchalant"],"anecdote":"Mot du langage juridique, « nonobstant » garde un parfum d\'actes notariés ; l\'employer ailleurs relève d\'une élégance un brin désuète."},{"id":"perorer","mot":"pérorer","nature":"verbe","definitions":["Discourir longuement et avec emphase, en se croyant brillant."],"phonetique":"/pe.ʁɔ.ʁe/","etymologie":"Du latin perorare, « conclure un discours, plaider jusqu\'au bout ».","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["discourir","pontifier","disserter","déclamer"],"antonymes":["se taire","écouter"],"exemplesCorrects":["Il pérorait au centre du salon, ravi de son auditoire.","Au lieu de pérorer, il ferait mieux d\'agir.","On le laissa pérorer une heure sans l\'interrompre."],"exemplesIncorrects":["Elle pérorait dans le plus grand silence, sans dire un mot.","Il a pérorè le mur du jardin avant l\'hiver."],"distracteurs":["perforer","déplorer","péricliter"],"anecdote":"À l\'origine simple terme de rhétorique pour « conclure », le mot a pris sa teinte ironique : pérorer, c\'est parler pour s\'écouter parler."},{"id":"baguenauder","mot":"baguenauder","nature":"verbe","definitions":["Flâner sans but, perdre son temps à des riens."],"phonetique":"/baɡ.no.de/","etymologie":"De baguenaude, fruit creux du baguenaudier, sans valeur.","registre":"soutenu","niveau":4,"themes":["quotidien","litteraire"],"synonymes":["flâner","musarder","déambuler","lambiner"],"antonymes":["s\'activer","se hâter","besogner"],"exemplesCorrects":["Il aimait baguenauder le long des quais le dimanche.","Au lieu de réviser, elle baguenaudait dans les librairies.","Nous avons baguenaudé tout l\'après-midi, sans plan ni montre."],"exemplesIncorrects":["Pressé, il baguenauda jusqu\'à la gare en deux minutes.","Il a baguenaudé un magnifique rapport en une nuit."],"distracteurs":["baliverner","bagarrer","badigeonner"],"anecdote":"Le baguenaudier porte des gousses gonflées qui éclatent sous les doigts : s\'amuser à les faire claquer, c\'était « baguenauder », perdre son temps."},{"id":"amadouer","mot":"amadouer","nature":"verbe","definitions":["Disposer favorablement quelqu\'un par des paroles douces ou flatteuses."],"phonetique":"/a.ma.dwe/","etymologie":"De amadou, matière qui s\'enflamme aisément, d\'où « rendre malléable ».","registre":"courant","niveau":3,"themes":["abstrait","emotions"],"synonymes":["enjôler","cajoler","apprivoiser","embobiner"],"antonymes":["braquer","rebuter","indisposer"],"exemplesCorrects":["Il tenta d\'amadouer le douanier d\'un sourire.","Quelques compliments suffirent à l\'amadouer.","On n\'amadoue pas si facilement un adversaire méfiant."],"exemplesIncorrects":["Furieux, il amadoua la porte d\'un grand coup de pied.","Il a amadoué le bois pour construire la cabane."],"distracteurs":["amocher","amarrer","amender","ambler"],"anecdote":"L\'amadou, ce champignon séché qui prend feu à la moindre étincelle, a donné l\'image : amadouer, c\'est rendre l\'autre aussi inflammable, aussi prêt à céder."},{"id":"aurore","mot":"aurore","nature":"nom féminin","definitions":["Lueur rosée qui précède le lever du soleil.","Commencement, naissance de quelque chose."],"phonetique":"/o.ʁɔʁ/","etymologie":"Du latin aurora, « lumière du matin ».","registre":"courant","niveau":1,"themes":["nature","litteraire"],"synonymes":["aube","point du jour","commencement"],"antonymes":["crépuscule","déclin","tombée de la nuit"],"exemplesCorrects":["Ils partirent dès l\'aurore, avant que la chaleur ne monte.","On voyait poindre l\'aurore derrière les collines.","Ce fut l\'aurore d\'une ère nouvelle pour la science."],"exemplesIncorrects":["Il alluma les lampes en pleine aurore de minuit.","L\'aurore tomba lentement et la nuit s\'installa."],"distracteurs":["aurône","augure","auréole"],"anecdote":"L\'aurore boréale doit son nom à cette déesse latine du matin : une lumière qui semble, elle aussi, annoncer un jour qui ne vient pas."},{"id":"bredouiller","mot":"bredouiller","nature":"verbe","definitions":["Parler de façon précipitée et confuse, en articulant mal."],"phonetique":"/bʁə.du.je/","etymologie":"Origine incertaine, d\'un radical expressif évoquant le bafouillage.","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["balbutier","bafouiller","marmonner","bégayer"],"antonymes":["articuler","déclamer","scander"],"exemplesCorrects":["Intimidé, il bredouilla quelques excuses incompréhensibles.","Elle bredouilla son nom, rouge de confusion.","Ne bredouille pas : reprends calmement depuis le début."],"exemplesIncorrects":["Il bredouilla son discours avec une éloquence parfaite.","Elle a bredouillé le mur de la cuisine en bleu."],"distracteurs":["gazouiller","barbouiller","brandiller"],"anecdote":"Au jeu de trictrac, « bredouille » désignait une victoire écrasante ; revenir « bredouille » de la chasse, c\'est, lui, rentrer les mains vides."},{"id":"ribambelle","mot":"ribambelle","nature":"nom féminin","definitions":["Longue suite, grand nombre de personnes ou de choses."],"phonetique":"/ʁi.bɑ̃.bɛl/","etymologie":"Origine incertaine, peut-être de riban, « ruban », d\'où l\'idée d\'une longue file.","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["kyrielle","flopée","multitude","cohorte"],"antonymes":["poignée","minorité"],"exemplesCorrects":["Une ribambelle d\'enfants suivait le marchand de glaces.","Il a posé une ribambelle de questions sans attendre les réponses.","Toute une ribambelle de cousins débarqua pour les fêtes."],"exemplesIncorrects":["Il ne restait qu\'une ribambelle de spectateurs : trois personnes.","Elle a bu une ribambelle bien fraîche au comptoir."],"distracteurs":["ritournelle","sarabande","farandole"],"anecdote":"Le mot évoque une guirlande de figurines en papier découpé qui se déplient en file : une image parfaite de la profusion."},{"id":"babiole","mot":"babiole","nature":"nom féminin","definitions":["Objet de peu de valeur ; chose sans importance."],"phonetique":"/ba.bjɔl/","etymologie":"De l\'italien babbola, « bagatelle, niaiserie ».","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["bagatelle","bricole","babiole","colifichet"],"antonymes":["trésor","merveille"],"exemplesCorrects":["Il rapporte toujours des babioles de ses voyages.","Ne dépense pas tout ton argent en babioles.","Ce que tu prends pour une babiole a une grande valeur sentimentale."],"exemplesIncorrects":["Ce diamant rarissime n\'est qu\'une babiole inestimable.","Il a signé un contrat de plusieurs millions pour cette babiole."],"distracteurs":["bestiole","gondole","faribole"],"anecdote":"« Babiole », « bricole », « broutille », « bagatelle » : le français ne manque pas de mots tendres pour ce qui ne pèse rien."},{"id":"placide","mot":"placide","nature":"adjectif","definitions":["D\'un calme que rien ne trouble ; paisible."],"phonetique":"/pla.sid/","etymologie":"Du latin placidus, « paisible, doux ».","registre":"courant","niveau":2,"themes":["emotions"],"synonymes":["paisible","serein","tranquille","imperturbable"],"antonymes":["agité","nerveux","irascible"],"exemplesCorrects":["Il gardait un air placide au milieu du tumulte.","La placide rivière reflétait les nuages.","Sa placide assurance finissait par agacer ses adversaires."],"exemplesIncorrects":["Furieux, il entra d\'un pas placide en claquant la porte.","La mer placide se déchaînait contre les rochers."],"distracteurs":["lucide","candide","limpide"],"anecdote":"Le prénom Placide, porté par des saints réputés pour leur douceur, vient directement de cet adjectif latin."},{"id":"maussade","mot":"maussade","nature":"adjectif","definitions":["D\'humeur sombre, peu aimable.","Terne, déplaisant, en parlant du temps ou d\'un lieu."],"phonetique":"/mo.sad/","etymologie":"De l\'ancien français mal sade, « désagréable », de sade, « plaisant ».","registre":"courant","niveau":2,"themes":["emotions"],"synonymes":["morose","renfrogné","chagrin","terne"],"antonymes":["enjoué","avenant","radieux"],"exemplesCorrects":["Il restait maussade malgré la bonne nouvelle.","Un ciel maussade pesait sur la ville depuis trois jours.","Elle répondit d\'un ton maussade, sans lever les yeux."],"exemplesIncorrects":["Quelle journée maussade : grand soleil et ciel sans nuage !","Il accueillit ses amis d\'un sourire maussade et chaleureux."],"distracteurs":["moussu","massif","mauresque","musardise"],"anecdote":"Le mot cache son contraire : « sade » signifiait « agréable », du latin sapidus, « qui a du goût », d\'où vient aussi « savoureux »."},{"id":"ephemere","mot":"éphémère","nature":"adjectif","definitions":["Qui ne dure qu\'un temps très court ; passager."],"phonetique":"/e.fe.mɛʁ/","etymologie":"Du grec ephêmeros, « qui ne dure qu\'un jour », de epi et hêmera, « jour ».","registre":"courant","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["passager","fugace","transitoire","précaire"],"antonymes":["durable","pérenne","éternel"],"exemplesCorrects":["La gloire est souvent éphémère.","Ils profitèrent d\'une éphémère accalmie pour sortir.","Les fleurs éphémères ne tiennent qu\'une matinée."],"exemplesIncorrects":["Ce monument éphémère traverse les siècles sans une ride.","Leur amitié éphémère dura toute une vie."],"distracteurs":["épidémie","éphéméride","éthéré"],"anecdote":"L\'éphémère est aussi un insecte qui, adulte, ne vit que quelques heures : un nom qui dit toute la brièveté de son existence."},{"id":"limpide","mot":"limpide","nature":"adjectif","definitions":["Parfaitement clair et transparent.","Facile à comprendre."],"phonetique":"/lɛ̃.pid/","etymologie":"Du latin limpidus, « clair, transparent ».","registre":"courant","niveau":2,"themes":["abstrait","nature"],"synonymes":["transparent","clair","cristallin","diaphane"],"antonymes":["trouble","opaque","obscur"],"exemplesCorrects":["L\'eau limpide laissait voir le fond du torrent.","Son explication était d\'une clarté limpide.","Un ciel limpide s\'étendait au-dessus des montagnes."],"exemplesIncorrects":["L\'eau limpide était si boueuse qu\'on n\'y voyait rien.","Ce raisonnement limpide laissa tout le monde perplexe."],"distracteurs":["lipide","intrépide","insipide"],"anecdote":"Sa parenté avec « lymphe » n\'est pas fortuite : tous deux descendent d\'une même idée d\'eau claire et pure."},{"id":"bise","mot":"bise","nature":"nom féminin","definitions":["Vent du nord, sec et froid."],"phonetique":"/biz/","etymologie":"D\'origine germanique, bisa, « vent du nord ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["vent du nord","froidure"],"antonymes":["zéphyr","brise tiède"],"exemplesCorrects":["La bise glaciale balayait la place déserte.","On rentrait le col relevé contre la bise.","« Quand la bise fut venue », commence la fable de la cigale."],"exemplesIncorrects":["La bise étouffante du désert nous accablait.","Il transpirait sous la bise tropicale de midi."],"distracteurs":["brise","balise","braise"],"anecdote":"À ne pas confondre avec la bise que l\'on fait sur la joue : ce sont deux mots distincts, l\'un venté, l\'autre affectueux."},{"id":"tintamarre","mot":"tintamarre","nature":"nom masculin","definitions":["Grand bruit discordant, vacarme assourdissant."],"phonetique":"/tɛ̃.ta.maʁ/","etymologie":"Formation expressive, de tinter et d\'un élément obscur -marre.","registre":"courant","niveau":3,"themes":["quotidien"],"synonymes":["vacarme","tapage","raffut","charivari"],"antonymes":["silence","quiétude"],"exemplesCorrects":["Les casseroles tombèrent dans un tintamarre épouvantable.","Quel tintamarre, ces klaxons aux heures de pointe !","La fanfare passa dans un joyeux tintamarre."],"exemplesIncorrects":["Un tintamarre de silence régnait dans la bibliothèque.","Il a savouré un tintamarre bien glacé au dessert."],"distracteurs":["tintement","tartine","tintouin"],"anecdote":"En Acadie, le « Tintamarre » est devenu une fête : on défile en faisant le plus de bruit possible pour affirmer joyeusement sa présence."},{"id":"ferveur","mot":"ferveur","nature":"nom féminin","definitions":["Ardeur enthousiaste, élan passionné du cœur ou de l\'esprit."],"phonetique":"/fɛʁ.vœʁ/","etymologie":"Du latin fervor, « chaleur, bouillonnement », de fervere, « bouillir ».","registre":"soutenu","niveau":3,"themes":["emotions"],"synonymes":["ardeur","zèle","enthousiasme","élan"],"antonymes":["tiédeur","indifférence","apathie"],"exemplesCorrects":["Elle défendait ses idées avec ferveur.","Les fidèles priaient avec une ferveur recueillie.","Il étudiait la musique avec une ferveur de tous les instants."],"exemplesIncorrects":["Il accomplit la corvée avec une ferveur résignée et morne.","La ferveur du congélateur conservait les aliments."],"distracteurs":["fraîcheur","faveur","ferraille","fervent"],"anecdote":"La ferveur « bout » au sens propre : la même racine latine a donné « effervescence » et « fervent »."},{"id":"engouement","mot":"engouement","nature":"nom masculin","definitions":["Enthousiasme vif et souvent passager pour quelqu\'un ou quelque chose."],"phonetique":"/ɑ̃.ɡu.mɑ̃/","etymologie":"De s\'engouer, « s\'étrangler en avalant », d\'où « se passionner soudain ».","registre":"courant","niveau":3,"themes":["emotions","abstrait"],"synonymes":["emballement","toquade","passion","enthousiasme"],"antonymes":["désaffection","indifférence","lassitude"],"exemplesCorrects":["L\'engouement du public pour ce jeu fut foudroyant.","Son engouement pour la photographie ne dura qu\'un été.","On assista à un engouement général pour ces vélos électriques."],"exemplesIncorrects":["Son profond engouement le poussa à tout abandonner par ennui.","Il a rangé l\'engouement dans le tiroir du salon."],"distracteurs":["engourdissement","enjouement","agencement"],"anecdote":"Le sens vient de l\'image de l\'étouffement : s\'engouer, c\'était avaler de travers ; la passion soudaine vous « prend à la gorge » de la même façon."},{"id":"quietude","mot":"quiétude","nature":"nom féminin","definitions":["Calme paisible, tranquillité de l\'âme."],"phonetique":"/kje.tyd/","etymologie":"Du latin quietudo, « repos », de quies, « tranquillité ».","registre":"soutenu","niveau":3,"themes":["emotions"],"synonymes":["sérénité","tranquillité","paix","ataraxie"],"antonymes":["inquiétude","agitation","trouble"],"exemplesCorrects":["Il goûtait la quiétude du soir au bord de l\'étang.","Rien ne troublait la quiétude de ce village reculé.","Elle travaillait dans la quiétude de l\'aube."],"exemplesIncorrects":["La quiétude de la bataille assourdissait les soldats.","Il bondit de quiétude en apprenant la catastrophe."],"distracteurs":["inquiétude","quotité","habitude"],"anecdote":"Son contraire, « inquiétude », est bien plus courant : la langue dit peut-être par là que le repos de l\'âme se remarque surtout quand il manque."},{"id":"taciturne","mot":"taciturne","nature":"adjectif","definitions":["Qui parle peu, d\'un naturel silencieux et renfermé."],"phonetique":"/ta.si.tyʁn/","etymologie":"Du latin taciturnus, « silencieux », de tacere, « se taire ».","registre":"soutenu","niveau":3,"themes":["emotions"],"synonymes":["silencieux","renfermé","réservé","sombre"],"antonymes":["loquace","volubile","expansif"],"exemplesCorrects":["C\'était un homme taciturne, qui pesait chacun de ses mots.","Elle devint taciturne après cette épreuve.","Le voyage se fit dans un silence taciturne."],"exemplesIncorrects":["Taciturne, il n\'arrêtait pas de raconter des histoires.","La fontaine taciturne murmurait jour et nuit."],"distracteurs":["nocturne","saturne","taquin"],"anecdote":"Guillaume d\'Orange fut surnommé « le Taciturne », non par mutisme, mais pour son art de garder un secret d\'État sans broncher."},{"id":"mantra","mot":"mantra","nature":"nom masculin","definitions":["Formule sacrée que l\'on répète, dans l\'hindouisme et le bouddhisme.","Phrase répétée comme un principe directeur."],"phonetique":"/mɑ̃.tʁa/","etymologie":"Du sanskrit mantra, « formule, parole sacrée ».","registre":"courant","niveau":3,"themes":["emprunts","abstrait"],"synonymes":["formule","incantation","devise","leitmotiv"],"antonymes":[],"exemplesCorrects":["Il répétait son mantra, assis en tailleur, les yeux clos.","« Rester simple » était devenu son mantra professionnel.","La méditation s\'accompagnait d\'un mantra murmuré."],"exemplesIncorrects":["Il a réparé le mantra crevé de son vélo.","Le mantra de la rivière débordait après l\'orage."],"distracteurs":["mantille","mandala","matraque"],"anecdote":"Le mot a quitté les temples pour le langage courant : on parle désormais du « mantra » d\'une entreprise comme d\'une formule répétée à l\'envi."},{"id":"saga","mot":"saga","nature":"nom féminin","definitions":["Récit héroïque médiéval scandinave.","Longue histoire mouvementée, souvent familiale."],"phonetique":"/sa.ɡa/","etymologie":"Du vieux norrois saga, « récit, ce qui est raconté ».","registre":"courant","niveau":3,"themes":["emprunts","litteraire"],"synonymes":["épopée","chronique","geste"],"antonymes":[],"exemplesCorrects":["Les sagas islandaises content les exploits des premiers colons.","Ce roman retrace la saga d\'une dynastie d\'industriels.","Leur procès interminable est devenu une véritable saga."],"exemplesIncorrects":["Il a commandé une saga bien cuite au restaurant.","La saga soufflait fort sur la côte cette nuit-là."],"distracteurs":["soga","sage","sagaie","sagouin"],"anecdote":"Les sagas, d\'abord transmises oralement, furent fixées par écrit au XIIIᵉ siècle : on leur doit une part immense de la mythologie nordique."},{"id":"toundra","mot":"toundra","nature":"nom féminin","definitions":["Vaste plaine glacée des régions arctiques, à la végétation rase."],"phonetique":"/tun.dʁa/","etymologie":"Du russe tundra, lui-même emprunté au same (lapon).","registre":"courant","niveau":3,"themes":["emprunts","nature"],"synonymes":["steppe arctique"],"antonymes":["jungle","forêt tropicale"],"exemplesCorrects":["Les rennes traversaient la toundra à la recherche de lichen.","En été, la toundra se couvre brièvement de fleurs.","Rien n\'arrête le vent sur l\'immense toundra."],"exemplesIncorrects":["La toundra luxuriante regorgeait de palmiers.","Il a planté une toundra dans son jardin au printemps."],"distracteurs":["tarentule","tundra","toupie"],"anecdote":"Sous la toundra, le sol gelé en permanence, le permafrost, emprisonne d\'énormes quantités de carbone, ce qui en fait un enjeu climatique majeur."},{"id":"geyser","mot":"geyser","nature":"nom masculin","definitions":["Source d\'eau chaude qui jaillit par intermittence en hautes colonnes."],"phonetique":"/ʒe.zɛʁ/","etymologie":"De l\'islandais Geysir, nom d\'une source jaillissante, de geysa, « jaillir ».","registre":"courant","niveau":2,"themes":["emprunts","nature"],"synonymes":["source jaillissante","fontaine bouillonnante"],"antonymes":[],"exemplesCorrects":["Le geyser projetait son panache d\'eau brûlante toutes les heures.","Les touristes attendaient l\'éruption du geyser.","Un geyser de boue surgissait du sol volcanique."],"exemplesIncorrects":["Le geyser gelé n\'avait pas coulé depuis des années.","Il a accroché le geyser au mur du salon."],"distracteurs":["gésier","geôlier","glacier"],"anecdote":"Tous les geysers du monde portent, indirectement, le nom du grand Geysir d\'Islande, le premier décrit par les voyageurs européens."},{"id":"nonante","mot":"nonante","nature":"adjectif","definitions":["En Belgique et en Suisse, le nombre quatre-vingt-dix."],"phonetique":"/nɔ.nɑ̃t/","etymologie":"Du latin nonaginta, « quatre-vingt-dix ».","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["quatre-vingt-dix"],"antonymes":[],"exemplesCorrects":["En Suisse, on compte octante ou huitante, puis nonante.","Le grand-père belge approchait des nonante ans.","Nonante-neuf est plus simple à dire que quatre-vingt-dix-neuf."],"exemplesIncorrects":["Il a acheté une nonante toute neuve au marché.","La nonante du moteur faisait un bruit inquiétant."],"distracteurs":["soixante","nuance","septante"],"anecdote":"« Septante », « octante » et « nonante » forment un système régulier que la France a perdu : nos « quatre-vingts » étonnent souvent nos voisins francophones."},{"id":"poutine","mot":"poutine","nature":"nom féminin","definitions":["Plat québécois de frites nappées de sauce brune et de fromage en grains."],"phonetique":"/pu.tin/","etymologie":"Mot québécois d\'origine incertaine, peut-être de l\'anglais pudding, « mélange ».","registre":"familier","niveau":2,"themes":["regionalismes","quotidien"],"synonymes":[],"antonymes":[],"exemplesCorrects":["Après le match, on s\'est partagé une grosse poutine.","La vraie poutine se reconnaît au crissement du fromage.","Chaque cabane à frites a sa recette de poutine."],"exemplesIncorrects":["Il a garé sa poutine devant la mairie.","La poutine de la rivière était en crue ce matin."],"distracteurs":["praline","tartine","routine"],"anecdote":"Née dans le Québec rural des années 1950, la poutine est devenue un emblème national, déclinée aujourd\'hui en dizaines de variantes."},{"id":"magasiner","mot":"magasiner","nature":"verbe","definitions":["Au Québec, faire des courses, du lèche-vitrine."],"phonetique":"/ma.ɡa.zi.ne/","etymologie":"Dérivé de magasin ; calque de l\'anglais to shop.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["faire les boutiques","faire les magasins"],"antonymes":[],"exemplesCorrects":["On va magasiner au centre commercial cet après-midi.","Elle aime magasiner les soldes de fin de saison.","Avant d\'acheter, il faut magasiner pour comparer les prix."],"exemplesIncorrects":["Il a magasiné le mur de la cuisine en jaune.","Le ciel magasinait à gros nuages au-dessus du fleuve."],"distracteurs":["emmagasiner","marchander","ramasser"],"anecdote":"Là où le Français « fait les magasins », le Québécois « magasine » : un verbe que le français de France n\'a jamais formé, faute d\'en sentir le besoin."},{"id":"dreve","mot":"drève","nature":"nom féminin","definitions":["En Belgique et dans le Nord, allée bordée d\'arbres."],"phonetique":"/dʁɛv/","etymologie":"Du néerlandais dreef, « allée plantée d\'arbres ».","registre":"courant","niveau":4,"themes":["regionalismes","nature"],"synonymes":["allée","avenue arborée","charmille"],"antonymes":[],"exemplesCorrects":["Une longue drève de hêtres menait au château.","Ils se promenaient dans la drève ombragée.","La drève débouchait sur une clairière inattendue."],"exemplesIncorrects":["Il a bu une drève bien fraîche en terrasse.","La drève du moteur faisait un bruit inquiétant."],"distracteurs":["grève","trêve","drache"],"anecdote":"Beaucoup de lieux-dits belges s\'appellent « la Drève » : le mot a fixé dans la toponymie ces alignements d\'arbres hérités des grands domaines."},{"id":"lande","mot":"lande","nature":"nom féminin","definitions":["Étendue plate et inculte couverte de bruyère, d\'ajoncs et de genêts."],"phonetique":"/lɑ̃d/","etymologie":"Du gaulois landa, « terre, étendue dégagée ».","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["brande","garrigue","friche"],"antonymes":["futaie","verger"],"exemplesCorrects":["La lande s\'étendait, mauve de bruyère, jusqu\'à l\'horizon.","Le vent sifflait sur la lande déserte.","Ils traversèrent une lande battue par la pluie."],"exemplesIncorrects":["La lande, plantée d\'immeubles, grouillait de monde.","Il a coupé une tranche de lande pour le dîner."],"distracteurs":["bande","amande","lente"],"anecdote":"Les landes de Gascogne, jadis marécageuses, furent plantées de pins au XIXᵉ siècle, formant la plus vaste forêt artificielle d\'Europe."},{"id":"calanque","mot":"calanque","nature":"nom féminin","definitions":["Crique étroite et profonde, aux parois rocheuses, du littoral méditerranéen."],"phonetique":"/ka.lɑ̃k/","etymologie":"Du provençal calanco, d\'un radical préroman cala, « crique, abri ».","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["crique","anse","cale"],"antonymes":["large","haute mer"],"exemplesCorrects":["Ils plongèrent dans l\'eau turquoise de la calanque.","On n\'accède à cette calanque qu\'à pied ou en bateau.","Les calanques de Marseille attirent randonneurs et grimpeurs."],"exemplesIncorrects":["La calanque enneigée dominait toute la vallée.","Il a servi une calanque bien fraîche à ses invités."],"distracteurs":["palanque","calandre","carlingue"],"anecdote":"Les calanques entre Marseille et Cassis forment depuis 2012 un parc national, l\'un des rares à être à la fois terrestre, marin et périurbain."},{"id":"etiage","mot":"étiage","nature":"nom masculin","definitions":["Niveau le plus bas d\'un cours d\'eau ; débit minimal d\'une rivière."],"phonetique":"/e.tjaʒ/","etymologie":"Dérivé d\'un mot du Sud-Ouest signifiant « été » : le niveau atteint à la saison sèche.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["basses eaux"],"antonymes":["crue","hautes eaux"],"exemplesCorrects":["En période d\'étiage, on devine les galets du lit de la rivière.","L\'étiage sévère a contraint à limiter l\'irrigation.","Le pont laisse voir ses piles à l\'étiage."],"exemplesIncorrects":["L\'étiage déborda et inonda toute la plaine.","Il a savouré un étiage bien glacé au comptoir."],"distracteurs":["étirage","étuvage","héritage"],"anecdote":"Par métaphore économique, on parle de « l\'étiage » d\'une activité pour désigner son niveau le plus bas avant la reprise."},{"id":"ecueil","mot":"écueil","nature":"nom masculin","definitions":["Rocher à fleur d\'eau, dangereux pour la navigation.","Obstacle, difficulté contre laquelle on risque d\'échouer."],"phonetique":"/e.kœj/","etymologie":"Du latin scopulus, « rocher, écueil », par l\'intermédiaire du provençal.","registre":"soutenu","niveau":3,"themes":["nature","abstrait"],"synonymes":["récif","obstacle","embûche","piège"],"antonymes":["facilité","atout"],"exemplesCorrects":["Le navire évita de justesse les écueils de la passe.","La précipitation est le principal écueil de ce projet.","Il a su éviter l\'écueil de la caricature."],"exemplesIncorrects":["Cet écueil a rendu la traversée parfaitement sûre.","Il a planté un écueil dans son potager au printemps."],"distracteurs":["accueil","cercueil","orgueil"],"anecdote":"La métaphore est si naturelle qu\'on l\'oublie : « échouer », au figuré, garde la mémoire des bateaux brisés sur les écueils."},{"id":"mistral","mot":"mistral","nature":"nom masculin","definitions":["Vent violent, froid et sec, qui souffle du nord vers la Méditerranée dans la vallée du Rhône."],"phonetique":"/mis.tʁal/","etymologie":"Du provençal mistral, du latin magistralis, « du maître » : le vent maître.","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["vent du nord"],"antonymes":["zéphyr","brise marine"],"exemplesCorrects":["Le mistral a soufflé trois jours, balayant le ciel jusqu\'au bleu.","Les cyprès pliaient sous les rafales du mistral.","Le mistral rend l\'air d\'une transparence éclatante."],"exemplesIncorrects":["Le mistral tropical et humide collait à la peau.","Il a versé du mistral dans son café pour le sucrer."],"distracteurs":["minéral","mistigri","littoral"],"anecdote":"On dit que le mistral, en chassant les nuages, « mange les nuages » : les Provençaux lui prêtent même une influence sur l\'humeur, parfois irritable, des habitants."},{"id":"susurrer","mot":"susurrer","nature":"verbe","definitions":["Dire à voix très basse, murmurer doucement."],"phonetique":"/sy.sy.ʁe/","etymologie":"Du latin susurrare, « murmurer », d\'origine onomatopéique.","registre":"soutenu","niveau":3,"themes":["quotidien","litteraire"],"synonymes":["murmurer","chuchoter","souffler","glisser"],"antonymes":["crier","hurler","clamer"],"exemplesCorrects":["Elle lui susurra quelques mots à l\'oreille.","Le vent susurrait dans les feuillages.","On susurrait dans les couloirs d\'étranges rumeurs."],"exemplesIncorrects":["Il susurra son ordre à pleins poumons d\'un bout à l\'autre du stade.","Elle a susurré le portail d\'un bleu éclatant."],"distracteurs":["suturer","sursauter","suspendre","subjuguer"],"anecdote":"Le mot imite ce qu\'il décrit : ses sifflantes répétées, « su-sur-rer », font entendre le murmure même qu\'il désigne."},{"id":"musarder","mot":"musarder","nature":"verbe","definitions":["Flâner, perdre son temps agréablement, s\'attarder à des riens."],"phonetique":"/my.zaʁ.de/","etymologie":"De muser, « perdre son temps, rêvasser ».","registre":"soutenu","niveau":3,"themes":["quotidien","litteraire"],"synonymes":["flâner","baguenauder","lambiner","traînasser"],"antonymes":["se hâter","s\'activer","filer"],"exemplesCorrects":["Il musardait le long des étals du marché.","Plutôt que de rentrer, elle musarda dans le parc.","On a musardé une heure devant les vitrines."],"exemplesIncorrects":["En retard, il musarda jusqu\'au bureau à toute allure.","Il a musardé un dossier complet en une nuit."],"distracteurs":["muser","museler","bavarder"],"anecdote":"« Muser » a aussi donné « amuser » : à l\'origine, amuser quelqu\'un, c\'était le faire « muser », le retenir agréablement à ne rien faire."},{"id":"ressasser","mot":"ressasser","nature":"verbe","definitions":["Revenir sans cesse sur les mêmes pensées, répéter inlassablement."],"phonetique":"/ʁə.sa.se/","etymologie":"De sas, « tamis » : repasser au crible, encore et encore.","registre":"courant","niveau":3,"themes":["abstrait","emotions"],"synonymes":["ruminer","rabâcher","remâcher","répéter"],"antonymes":["oublier","tourner la page"],"exemplesCorrects":["Il ressassait sans fin ses vieux griefs.","À quoi bon ressasser le passé ?","Elle ressassait la même question sans trouver de réponse."],"exemplesIncorrects":["Il a ressassé cette idée nouvelle pour la toute première fois.","Elle a ressassé le mur du salon d\'un beau vert."],"distracteurs":["ressaisir","tracasser","ressentir"],"anecdote":"L\'image est concrète : ressasser, c\'est repasser indéfiniment la même matière au tamis, le « sas », jusqu\'à n\'en plus rien tirer."},{"id":"vituperer","mot":"vitupérer","nature":"verbe","definitions":["Blâmer avec véhémence, élever des protestations indignées contre."],"phonetique":"/vi.ty.pe.ʁe/","etymologie":"Du latin vituperare, « blâmer, déprécier ».","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["pester","fulminer","invectiver","fustiger"],"antonymes":["louer","approuver","féliciter"],"exemplesCorrects":["Il vitupérait contre la lenteur de l\'administration.","Au lieu de vitupérer, proposez des solutions.","Elle vitupéra ces décisions qu\'elle jugeait absurdes."],"exemplesIncorrects":["Ravi, il vitupéra son ami d\'un grand sourire reconnaissant.","Il a vitupéré la clôture du jardin avant l\'hiver."],"distracteurs":["récupérer","vociférer","vénérer"],"anecdote":"On « vitupère contre » plus souvent qu\'on ne « vitupère » quelqu\'un : la préposition s\'est imposée, malgré les puristes qui la jugent superflue."},{"id":"debonnaire","mot":"débonnaire","nature":"adjectif","definitions":["D\'une bonté un peu molle, d\'un naturel doux et accommodant."],"phonetique":"/de.bɔ.nɛʁ/","etymologie":"De l\'ancien français de bon aire, « de bonne race, de bon naturel ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["bonhomme","placide","accommodant","indulgent"],"antonymes":["sévère","autoritaire","acariâtre"],"exemplesCorrects":["Un patron débonnaire fermait les yeux sur les retards.","Il avait l\'air débonnaire d\'un grand-père comblé.","Sous ses dehors débonnaires, c\'était un fin stratège."],"exemplesIncorrects":["Le tyran débonnaire faisait régner la terreur.","Elle a peint la barrière d\'un débonnaire éclatant."],"distracteurs":["doctrinaire","milliardaire","débineur"],"anecdote":"Louis le Pieux, fils de Charlemagne, est aussi appelé « le Débonnaire » : à l\'époque, le mot vantait la noblesse de caractère plus que la mollesse."},{"id":"chafouin","mot":"chafouin","nature":"adjectif","definitions":["Qui a une mine sournoise et rusée."],"phonetique":"/ʃa.fwɛ̃/","etymologie":"De chat et fouine : à la mine d\'un petit animal rusé.","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["sournois","matois","patelin","finaud"],"antonymes":["franc","ouvert","candide"],"exemplesCorrects":["Il arborait un petit air chafouin qui inspirait la méfiance.","Un sourire chafouin trahissait ses arrière-pensées.","Sa mine chafouine annonçait quelque mauvais tour."],"exemplesIncorrects":["Son visage chafouin respirait la franchise et la bonté.","Il a repeint sa chambre d\'un chafouin lumineux."],"distracteurs":["chagrin","babouin","chamois"],"anecdote":"Le mot soude deux bêtes à la réputation rusée, le chat et la fouine : la langue a fabriqué là un visage à partir d\'un bestiaire."},{"id":"brimborion","mot":"brimborion","nature":"nom masculin","definitions":["Petit objet sans valeur ; bagatelle."],"phonetique":"/bʁɛ̃.bɔ.ʁjɔ̃/","etymologie":"Altération de l\'ancien breborion, du latin breviarium, « bréviaire ».","registre":"littéraire","niveau":4,"themes":["quotidien","litteraire"],"synonymes":["babiole","colifichet","bagatelle","bricole"],"antonymes":["trésor","joyau"],"exemplesCorrects":["Son étagère croulait sous les brimborions rapportés de voyage.","Pourquoi t\'encombrer de tous ces brimborions ?","Un tiroir débordait de brimborions oubliés."],"exemplesIncorrects":["Ce collier de diamants est un brimborion d\'une valeur inestimable.","Il a dégusté un brimborion bien sucré au goûter."],"distracteurs":["histrion","morbidité","biberon"],"anecdote":"Curieux destin : du « bréviaire », livre de prières, le mot a glissé vers le menu objet sans importance, peut-être par moquerie des babioles dévotes."},{"id":"philippique","mot":"philippique","nature":"nom féminin","definitions":["Discours violent, réquisitoire véhément contre quelqu\'un."],"phonetique":"/fi.li.pik/","etymologie":"Des discours de Démosthène contre Philippe de Macédoine, puis de Cicéron contre Antoine.","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["réquisitoire","diatribe","satire","invective"],"antonymes":["éloge","panégyrique","apologie"],"exemplesCorrects":["Il se lança dans une philippique contre l\'hypocrisie des puissants.","Sa philippique enflammée laissa l\'assemblée stupéfaite.","L\'éditorial était une philippique contre la corruption."],"exemplesIncorrects":["Il prononça une tendre philippique pour féliciter la mariée.","Il a réparé la philippique de la voiture au garage."],"distracteurs":["polémique","périphérique","philharmonie"],"anecdote":"Le mot remonte à Démosthène, qui haranguait Athènes contre Philippe ; Cicéron reprit le genre contre Marc Antoine, qui le lui fit payer de sa vie."},{"id":"aporie","mot":"aporie","nature":"nom féminin","definitions":["Difficulté logique sans issue ; contradiction insoluble."],"phonetique":"/a.pɔ.ʁi/","etymologie":"Du grec aporia, « absence de passage, embarras ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["impasse","contradiction","dilemme","antinomie"],"antonymes":["solution","issue","évidence"],"exemplesCorrects":["Le raisonnement aboutissait à une aporie embarrassante.","Les dialogues de Platon se closent souvent sur une aporie.","Devant cette aporie, la commission renonça à conclure."],"exemplesIncorrects":["La démonstration, d\'une aporie limpide, convainquit tout le monde.","Il a savouré une aporie bien fraîche au dessert."],"distracteurs":["agonie","allégorie","apostrophe"],"anecdote":"Socrate cultivait l\'aporie : pousser son interlocuteur jusqu\'à l\'aveu « je ne sais plus » était, pour lui, le vrai début de la philosophie."},{"id":"palinodie","mot":"palinodie","nature":"nom féminin","definitions":["Changement complet d\'opinion ; rétractation de ce qu\'on avait soutenu."],"phonetique":"/pa.li.nɔ.di/","etymologie":"Du grec palinôidia, « chant repris », de palin, « de nouveau », et ôidê, « chant ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["rétractation","revirement","volte-face","désaveu"],"antonymes":["constance","fidélité","persévérance"],"exemplesCorrects":["Sa palinodie surprit jusqu\'à ses plus proches alliés.","On l\'accusa de palinodie après ce brusque revirement.","Les palinodies répétées du ministre lassaient l\'opinion."],"exemplesIncorrects":["Sa palinodie inébranlable forçait l\'admiration de tous.","Il a planté une palinodie au fond du jardin."],"distracteurs":["mélodie","parodie","palissade"],"anecdote":"Le poète grec Stésichore aurait, dit-on, perdu la vue pour avoir médit d\'Hélène, et l\'aurait recouvrée en composant une palinodie qui la réhabilitait."},{"id":"sycophante","mot":"sycophante","nature":"nom masculin","definitions":["Délateur, dénonciateur de profession ; calomniateur."],"phonetique":"/si.kɔ.fɑ̃t/","etymologie":"Du grec sukophantês, « délateur », littéralement « qui dénonce les voleurs de figues ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["délateur","dénonciateur","calomniateur","mouchard"],"antonymes":["défenseur","avocat"],"exemplesCorrects":["Les sycophantes prospéraient sous ce régime de suspicion.","Il refusait de devenir le sycophante de ses collègues.","Athènes connut une engeance de sycophantes vénaux."],"exemplesIncorrects":["Ce sycophante intègre défendit l\'accusé avec courage.","Il a réparé le sycophante de la chaudière."],"distracteurs":["sarcophage","sycomore","éléphant"],"anecdote":"À Athènes, dénoncer l\'exportation illégale de figues aurait donné son nom à ces accusateurs publics, vite devenus l\'archétype du calomniateur intéressé."},{"id":"atavisme","mot":"atavisme","nature":"nom masculin","definitions":["Réapparition d\'un caractère hérité d\'un ancêtre lointain.","Comportement transmis par l\'hérédité, par tradition."],"phonetique":"/a.ta.vism/","etymologie":"Du latin atavus, « aïeul, ancêtre lointain ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["hérédité","héritage","atavisme"],"antonymes":["innovation","rupture"],"exemplesCorrects":["Par atavisme, il avait le goût de la mer comme tous ses aïeux marins.","Cet atavisme paysan le ramenait toujours à la terre.","On expliquait sa prudence par un atavisme familial."],"exemplesIncorrects":["Son atavisme tout neuf n\'avait aucune racine dans le passé.","Il a bu un atavisme bien frais en terrasse."],"distracteurs":["altruisme","automatisme","ostracisme"],"anecdote":"Le mot fut forgé au XIXᵉ siècle par les naturalistes pour nommer ces ressemblances qui sautent une ou plusieurs générations avant de resurgir."},{"id":"casuistique","mot":"casuistique","nature":"nom féminin","definitions":["Partie de la morale qui résout les cas de conscience.","Subtilité excessive de raisonnement, ergotage."],"phonetique":"/ka.zɥis.tik/","etymologie":"Du latin casus, « cas » : l\'art de trancher les cas de conscience.","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["argutie","ergotage","subtilité","sophistique"],"antonymes":["franchise","simplicité"],"exemplesCorrects":["Il se perdait dans une casuistique sans fin pour justifier l\'injustifiable.","La casuistique permettait d\'adapter la règle aux situations particulières.","Assez de casuistique : la question est simple."],"exemplesIncorrects":["Sa casuistique d\'une grande clarté tenait en une phrase.","Il a planté une casuistique dans son potager."],"distracteurs":["acoustique","caustique","balistique"],"anecdote":"Pascal, dans ses Provinciales, ridiculisa la casuistique des jésuites au point de donner au mot sa nuance péjorative d\'ergotage retors."},{"id":"prolegomenes","mot":"prolégomènes","nature":"nom masculin","definitions":["Longue introduction en tête d\'un ouvrage ; notions préliminaires."],"phonetique":"/pʁɔ.le.ɡɔ.mɛn/","etymologie":"Du grec prolegomena, « ce qui est dit en préliminaire ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["préliminaires","introduction","préambule","prémisses"],"antonymes":["conclusion","épilogue"],"exemplesCorrects":["Les prolégomènes de l\'ouvrage en exposent la méthode.","Kant a intitulé un livre « Prolégomènes à toute métaphysique future ».","Après d\'interminables prolégomènes, il en vint enfin au fait."],"exemplesIncorrects":["Les prolégomènes refermaient le livre par une belle conclusion.","Il a savouré des prolégomènes bien sucrés au goûter."],"distracteurs":["épiphénomènes","phénomènes","prolétaires"],"anecdote":"Le mot s\'emploie presque toujours au pluriel ; l\'utiliser au singulier, « un prolégomène », passe pour une coquetterie de pédant."},{"id":"oripeaux","mot":"oripeaux","nature":"nom masculin","definitions":["Vêtements voyants et défraîchis ; faux brillant, clinquant."],"phonetique":"/ɔ.ʁi.po/","etymologie":"De l\'ancien français orie pel, « peau dorée » : un clinquant qui imite l\'or.","registre":"littéraire","niveau":5,"themes":["quotidien","litteraire"],"synonymes":["clinquant","défroque","oripeaux","guenilles"],"antonymes":["sobriété","élégance"],"exemplesCorrects":["Sous les oripeaux du luxe se cachait une grande misère.","L\'acteur ôta ses oripeaux de scène.","Il dénonçait les oripeaux d\'une fausse modernité."],"exemplesIncorrects":["Elle portait de sobres oripeaux d\'une élégance discrète.","Il a dégusté des oripeaux bien chauds au dîner."],"distracteurs":["oripeau","barreaux","rideaux"],"anecdote":"Du sens propre de « faux or », le mot a glissé vers le figuré : les « oripeaux » d\'une doctrine, ce sont ses ornements trompeurs."},{"id":"pusillanime","mot":"pusillanime","nature":"adjectif","definitions":["Qui manque de courage et de fermeté ; craintif, timoré."],"phonetique":"/py.zi.la.nim/","etymologie":"Du latin pusillanimis, « qui a l\'âme petite ».","registre":"soutenu","niveau":5,"themes":["emotions"],"synonymes":["timoré","craintif","couard","veule"],"antonymes":["courageux","intrépide","magnanime"],"exemplesCorrects":["Trop pusillanime, il n\'osa jamais défendre ses idées.","Une réponse pusillanime déçut ses partisans.","Ce n\'est pas le moment de se montrer pusillanime."],"exemplesIncorrects":["Pusillanime, il chargea l\'ennemi sans la moindre hésitation.","Il a repeint la clôture d\'un pusillanime éclatant."],"distracteurs":["unanime","polysémie","magnanime"],"anecdote":"Mot à mot, le pusillanime a « l\'âme petite » ; son exact contraire latin, le magnanime, a « la grande âme »."},{"id":"concupiscence","mot":"concupiscence","nature":"nom féminin","definitions":["Penchant ardent vers les plaisirs des sens et les biens matériels."],"phonetique":"/kɔ̃.ky.pi.sɑ̃s/","etymologie":"Du latin concupiscentia, de concupiscere, « désirer ardemment ».","registre":"littéraire","niveau":5,"themes":["abstrait","emotions"],"synonymes":["convoitise","appétit","avidité","sensualité"],"antonymes":["tempérance","ascèse","continence"],"exemplesCorrects":["Les moralistes mettaient en garde contre la concupiscence.","Une lueur de concupiscence brillait dans son regard.","Il opposait l\'ascèse à toute forme de concupiscence."],"exemplesIncorrects":["Sa concupiscence ascétique l\'éloignait de tout plaisir.","Il a réparé la concupiscence de la voiture au garage."],"distracteurs":["réminiscence","concurrence","convalescence"],"anecdote":"Terme central de la théologie morale, la concupiscence désigne ce désir qui, selon la tradition chrétienne, subsiste en l\'homme et le porte vers les biens d\'ici-bas."},{"id":"diktat","mot":"diktat","nature":"nom masculin","definitions":["Exigence imposée par la force, sans négociation possible."],"phonetique":"/dik.tat/","etymologie":"De l\'allemand Diktat, « chose dictée, imposée ».","registre":"soutenu","niveau":4,"themes":["abstrait","emprunts"],"synonymes":["ultimatum","injonction","oukase","exigence"],"antonymes":["compromis","négociation","accord"],"exemplesCorrects":["Il refusa de se plier au diktat de l\'occupant.","Ce traité fut vécu comme un diktat humiliant.","Elle dénonçait le diktat de la mode."],"exemplesIncorrects":["Ce diktat fut le fruit d\'un long compromis amical.","Il a savouré un diktat bien sucré au dessert."],"distracteurs":["dictée","constat","digression","diatribe"],"anecdote":"Le mot est entré en français dans l\'entre-deux-guerres, l\'Allemagne ayant qualifié de « Diktat » le traité de Versailles qu\'elle jugeait imposé."},{"id":"nirvana","mot":"nirvana","nature":"nom masculin","definitions":["Dans le bouddhisme, extinction du désir et libération de la souffrance.","État de sérénité parfaite, béatitude."],"phonetique":"/niʁ.va.na/","etymologie":"Du sanskrit nirvana, « extinction (du désir) ».","registre":"courant","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["béatitude","félicité","plénitude","sérénité"],"antonymes":["souffrance","tourment"],"exemplesCorrects":["Le bouddhisme vise l\'accès au nirvana.","Allongé au soleil, il atteignait une sorte de nirvana.","Ce silence absolu était pour elle un véritable nirvana."],"exemplesIncorrects":["Le nirvana de la bataille épuisait les soldats.","Il a garé son nirvana devant la mairie."],"distracteurs":["savane","caravane","nuance"],"anecdote":"Le mot signifie littéralement « extinction », comme celle d\'une flamme : non pas le néant, mais la fin de l\'agitation du désir."},{"id":"duende","mot":"duende","nature":"nom masculin","definitions":["Charme mystérieux et puissant qui émane d\'un artiste, d\'une œuvre."],"phonetique":"/dwɛn.de/","etymologie":"Mot espagnol, « lutin, esprit », puis grâce envoûtante d\'un interprète.","registre":"littéraire","niveau":5,"themes":["emprunts","emotions"],"synonymes":["magnétisme","grâce","charme","aura"],"antonymes":["fadeur","platitude"],"exemplesCorrects":["Cette danseuse de flamenco a un duende bouleversant.","Sans duende, la technique la plus parfaite reste froide.","Le poète Lorca a longuement médité sur le duende."],"exemplesIncorrects":["Il a réparé le duende crevé de son vélo.","Le duende tombait à gros flocons sur la ville."],"distracteurs":["duègne","duvet","détente"],"anecdote":"Federico García Lorca en fit le sujet d\'une célèbre conférence : le duende serait cette puissance obscure, presque douloureuse, qui distingue l\'art vivant du simple savoir-faire."},{"id":"gourou","mot":"gourou","nature":"nom masculin","definitions":["Maître spirituel, dans l\'hindouisme.","Personne très influente, guide d\'un groupe d\'adeptes."],"phonetique":"/ɡu.ʁu/","etymologie":"De l\'hindi guru, du sanskrit, « maître spirituel, vénérable ».","registre":"courant","niveau":3,"themes":["emprunts","abstrait"],"synonymes":["maître","mentor","guide","directeur"],"antonymes":["disciple","adepte","élève"],"exemplesCorrects":["Il s\'était fait gourou d\'une petite communauté.","On le présentait comme le gourou de la nouvelle cuisine.","Méfie-toi des gourous qui promettent le bonheur en dix leçons."],"exemplesIncorrects":["Il a planté un gourou au fond du jardin.","Le gourou de la rivière débordait après l\'orage."],"distracteurs":["verrou","garrot","ragoût"],"anecdote":"Du maître spirituel respecté, le mot a pris en Occident une teinte ambiguë : on parle aujourd\'hui de « gourou » du marketing comme d\'un meneur de secte."},{"id":"cicerone","mot":"cicérone","nature":"nom masculin","definitions":["Guide qui fait visiter une ville, un monument, et en commente les curiosités."],"phonetique":"/si.se.ʁon/","etymologie":"De l\'italien cicerone, de Cicéron, par allusion à l\'éloquence des guides.","registre":"soutenu","niveau":4,"themes":["emprunts"],"synonymes":["guide","accompagnateur"],"antonymes":["touriste","visiteur"],"exemplesCorrects":["Il nous servit de cicérone dans les ruelles de Venise.","Un cicérone érudit commentait chaque fresque.","Faute de cicérone, ils se perdirent dans la vieille ville."],"exemplesIncorrects":["Il a réparé le cicérone de la chaudière en deux minutes.","Le cicérone soufflait fort sur la côte cette nuit-là."],"distracteurs":["macédoine","cicatrice","chaperon"],"anecdote":"Les guides bavards d\'Italie furent surnommés « cicéroni » par dérision, tant leur faconde rappelait celle du grand orateur romain."},{"id":"dilettante","mot":"dilettante","nature":"nom masculin","definitions":["Personne qui s\'adonne à une activité par plaisir, en amateur, sans s\'y appliquer sérieusement."],"phonetique":"/di.le.tɑ̃t/","etymologie":"De l\'italien dilettante, « qui prend plaisir », du latin delectare, « charmer ».","registre":"courant","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["amateur","fantaisiste","touche-à-tout"],"antonymes":["professionnel","spécialiste","expert"],"exemplesCorrects":["Il peint en dilettante, sans jamais exposer.","On lui reprochait de travailler en dilettante.","Ce dilettante éclairé connaissait mille choses sans rien approfondir."],"exemplesIncorrects":["Ce dilettante acharné s\'entraînait dix heures par jour.","Il a garé son dilettante devant la mairie."],"distracteurs":["débutante","militante","dilatation"],"anecdote":"Le mot vient du plaisir : le dilettante est d\'abord celui qui « se délecte ». La nuance de légèreté, voire de superficialité, est venue plus tard."},{"id":"huitante","mot":"huitante","nature":"adjectif","definitions":["En Suisse romande, le nombre quatre-vingts."],"phonetique":"/ɥi.tɑ̃t/","etymologie":"Du latin octoginta, « quatre-vingts ».","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["quatre-vingts","octante"],"antonymes":[],"exemplesCorrects":["Dans le canton de Vaud, on dit huitante, pas quatre-vingts.","La facture s\'élevait à huitante francs.","Il a fêté ses huitante ans entouré des siens."],"exemplesIncorrects":["Il a acheté une huitante toute neuve au marché.","La huitante du moteur faisait un bruit inquiétant."],"distracteurs":["soixante","habitante","nonante"],"anecdote":"« Huitante » survit surtout dans les cantons de Vaud, du Valais et de Fribourg ; ailleurs en Suisse, on entend parfois l\'ancien « octante »."},{"id":"estaminet","mot":"estaminet","nature":"nom masculin","definitions":["Dans le Nord, petit café populaire, débit de boissons convivial."],"phonetique":"/ɛs.ta.mi.nɛ/","etymologie":"Du wallon staminé, « petit café », d\'origine incertaine.","registre":"courant","niveau":3,"themes":["regionalismes","quotidien"],"synonymes":["bistrot","troquet","taverne","café"],"antonymes":[],"exemplesCorrects":["On refaisait le monde dans l\'estaminet du village.","L\'estaminet sentait la bière et le tabac froid.","Chaque dimanche, les joueurs de cartes envahissaient l\'estaminet."],"exemplesIncorrects":["Il a garé son estaminet devant la mairie.","L\'estaminet de la rivière était en crue ce matin."],"distracteurs":["estafette","robinet","estampe"],"anecdote":"Les estaminets flamands, avec leurs jeux traditionnels comme la grenouille ou le billard Nicolas, connaissent aujourd\'hui un fort renouveau touristique."},{"id":"biloute","mot":"biloute","nature":"nom masculin","definitions":["Dans le Nord, terme d\'affection familier adressé à un homme : « mon gars »."],"phonetique":"/bi.lut/","etymologie":"Mot ch\'ti (picard), terme affectueux populaire.","registre":"familier","niveau":3,"themes":["regionalismes"],"synonymes":["mon gars","mon vieux","copain"],"antonymes":[],"exemplesCorrects":["Ça va, biloute ? Viens t\'asseoir avec nous.","Allez, biloute, encore un petit effort !","Dans le Nord, on s\'appelle volontiers biloute entre amis."],"exemplesIncorrects":["Il a réglé sa biloute d\'électricité à temps.","La biloute du moteur refusait de démarrer."],"distracteurs":["bidule","mazoute","bicoque"],"anecdote":"Le film « Bienvenue chez les Ch\'tis » a fait connaître « biloute » à toute la France, au point d\'en faire un emblème affectueux du Nord."},{"id":"espante","mot":"espanté","nature":"adjectif","definitions":["Dans le Midi, stupéfait, ébahi, frappé d\'étonnement."],"phonetique":"/ɛs.pɑ̃.te/","etymologie":"De l\'occitan espantar, « stupéfier », du latin expaventare, « épouvanter ».","registre":"familier","niveau":4,"themes":["regionalismes","emotions"],"synonymes":["ébahi","stupéfait","estomaqué","sidéré"],"antonymes":["indifférent","blasé"],"exemplesCorrects":["J\'en suis resté espanté, je ne m\'y attendais pas !","Elle nous a regardés, toute espantée.","Il était espanté devant un tel spectacle."],"exemplesIncorrects":["Parfaitement espanté, il bâilla d\'ennui pendant le feu d\'artifice.","Il a repeint le mur d\'un espanté lumineux."],"distracteurs":["épaté","esquinté","écarté"],"anecdote":"« Espanté » partage sa racine avec « épouvante » : la même peur latine a donné, au Sud, un mot pour l\'ébahissement et, au Nord, un mot pour l\'effroi."},{"id":"poutou","mot":"poutou","nature":"nom masculin","definitions":["Dans le Midi et le Sud-Ouest, baiser affectueux, bise."],"phonetique":"/pu.tu/","etymologie":"De l\'occitan poutou, « baiser », de la famille de pot, « lèvre ».","registre":"familier","niveau":2,"themes":["regionalismes","emotions"],"synonymes":["bise","bisou","baiser"],"antonymes":[],"exemplesCorrects":["Allez, fais un poutou à ta mamie avant de partir.","Il lui claqua un gros poutou sur la joue.","Un dernier poutou et au lit, les enfants !"],"exemplesIncorrects":["Il a garé son poutou devant la mairie.","Le poutou de la rivière était en crue ce matin."],"distracteurs":["poutre","filou","doudou"],"anecdote":"Du Sud-Ouest, « poutou » a essaimé dans tout le français familier comme synonyme tendre de « bisou », surtout dans le langage adressé aux enfants."},{"id":"tourbiere","mot":"tourbière","nature":"nom féminin","definitions":["Marécage où s\'accumule la tourbe, formée de végétaux décomposés."],"phonetique":"/tuʁ.bjɛʁ/","etymologie":"Dérivé de tourbe, du francique turba, matière végétale des marais.","registre":"courant","niveau":4,"themes":["nature"],"synonymes":["marais","marécage","fagne"],"antonymes":["désert","steppe aride"],"exemplesCorrects":["La tourbière abrite des plantes carnivores et de rares libellules.","On extrayait jadis la tourbe de cette tourbière pour se chauffer.","Le sentier serpentait entre les flaques de la tourbière."],"exemplesIncorrects":["La tourbière, brûlante et sèche, n\'offrait pas une goutte d\'eau.","Il a servi une tourbière bien fraîche à ses invités."],"distracteurs":["tabatière","tourmente","théière"],"anecdote":"Les tourbières stockent d\'immenses quantités de carbone et conservent parfois, intacts pendant des millénaires, des corps qu\'on appelle « hommes des tourbières »."},{"id":"penombre","mot":"pénombre","nature":"nom féminin","definitions":["Lumière faible, demi-jour entre l\'ombre et la pleine clarté."],"phonetique":"/pe.nɔ̃bʁ/","etymologie":"Du latin paene, « presque », et umbra, « ombre ».","registre":"courant","niveau":2,"themes":["nature","litteraire"],"synonymes":["demi-jour","clair-obscur","obscurité"],"antonymes":["pleine lumière","clarté","éclat"],"exemplesCorrects":["Ses yeux s\'habituaient peu à peu à la pénombre de la cave.","Dans la pénombre du soir, les contours s\'estompaient.","Elle aimait lire dans la douce pénombre des après-midi d\'hiver."],"exemplesIncorrects":["En pleine pénombre de midi, le soleil aveuglait les passants.","Il a coupé une tranche de pénombre pour le dîner."],"distracteurs":["encombre","décombre","concombre"],"anecdote":"En astronomie, la pénombre est la zone d\'ombre partielle d\'une éclipse : là où l\'astre n\'est caché qu\'à moitié."},{"id":"onde","mot":"onde","nature":"nom féminin","definitions":["En poésie, eau d\'un lac, d\'une rivière, de la mer.","Mouvement vibratoire qui se propage."],"phonetique":"/ɔ̃d/","etymologie":"Du latin unda, « eau, vague ».","registre":"littéraire","niveau":2,"themes":["nature","litteraire"],"synonymes":["flot","eau","vague","onde"],"antonymes":["rive","terre ferme"],"exemplesCorrects":["Le cygne glissait sur l\'onde immobile.","Une onde de choc parcourut l\'assemblée.","La lune se reflétait dans l\'onde tremblante."],"exemplesIncorrects":["Il a empilé trois ondes dans le placard de la cuisine.","L\'onde poussiéreuse du désert montait jusqu\'aux dunes."],"distracteurs":["ronde","monde","sonde"],"anecdote":"« Sur l\'onde » est une cheville de la poésie classique pour dire « sur l\'eau » ; le mot a gardé ce parfum noble que « flotte » a perdu."},{"id":"embacle","mot":"embâcle","nature":"nom masculin","definitions":["Amas de glaces qui obstrue un cours d\'eau ; obstruction d\'une rivière."],"phonetique":"/ɑ̃.bɑkl/","etymologie":"De embâcler, « obstruer » ; contraire de débâcle.","registre":"soutenu","niveau":5,"themes":["nature"],"synonymes":["obstruction","barrage de glace"],"antonymes":["débâcle","dégel"],"exemplesCorrects":["L\'embâcle menaçait d\'inonder les rives au moment du dégel.","Un embâcle de troncs bloquait le cours de la rivière.","Les pompiers surveillaient l\'embâcle formé sous le pont."],"exemplesIncorrects":["L\'embâcle libéra soudain le courant, qui s\'écoula librement.","Il a savouré un embâcle bien glacé au comptoir."],"distracteurs":["débâcle","obstacle","réceptacle"],"anecdote":"L\'embâcle bloque, la débâcle libère : quand les glaces de l\'embâcle cèdent d\'un coup, la débâcle peut provoquer des crues dévastatrices."},{"id":"exaltation","mot":"exaltation","nature":"nom féminin","definitions":["Vive excitation de l\'esprit, enthousiasme intense."],"phonetique":"/ɛɡ.zal.ta.sjɔ̃/","etymologie":"Du latin exaltatio, « élévation », de exaltare, « élever ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["enthousiasme","ferveur","ardeur","transport"],"antonymes":["abattement","apathie","indifférence"],"exemplesCorrects":["Il parlait de son projet avec une exaltation communicative.","L\'exaltation de la foule était à son comble.","Dans son exaltation, elle promit l\'impossible."],"exemplesIncorrects":["Il accomplit sa corvée dans une morne exaltation de lassitude.","L\'exaltation du congélateur conservait les aliments."],"distracteurs":["exhalaison","exultation","exploitation"],"anecdote":"À ne pas confondre avec « exhalation », qui concerne le souffle : l\'exaltation élève l\'âme, l\'exhalation s\'échappe des poumons."},{"id":"accablement","mot":"accablement","nature":"nom masculin","definitions":["État d\'abattement profond, physique ou moral."],"phonetique":"/a.kɑ.blə.mɑ̃/","etymologie":"De accabler, de l\'ancien caable, « machine de guerre qui écrase ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["abattement","prostration","découragement","lassitude"],"antonymes":["entrain","vigueur","allégresse"],"exemplesCorrects":["La nouvelle le plongea dans un profond accablement.","On lisait l\'accablement sur le visage des sinistrés.","Un accablement de fin d\'été pesait sur la ville."],"exemplesIncorrects":["Quel accablement de gagner enfin ce qu\'il désirait tant !","Il a réparé l\'accablement de la voiture au garage."],"distracteurs":["ralentissement","redoublement","acharnement"],"anecdote":"Le mot garde la mémoire d\'une arme : le « caable » médiéval, ancêtre de la catapulte, qui écrasait sous ses projectiles ; accabler, c\'est encore écraser."},{"id":"magnanime","mot":"magnanime","nature":"adjectif","definitions":["Qui pardonne aisément, qui fait preuve de générosité et de grandeur d\'âme."],"phonetique":"/ma.ɲa.nim/","etymologie":"Du latin magnanimus, de magnus, « grand », et animus, « âme ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["généreux","clément","noble","indulgent"],"antonymes":["mesquin","rancunier","pusillanime"],"exemplesCorrects":["Magnanime, le vainqueur épargna les vaincus.","Elle eut le geste magnanime de pardonner l\'affront.","Un esprit magnanime ne s\'abaisse pas à la vengeance."],"exemplesIncorrects":["Magnanime, il réclama vengeance jusqu\'au dernier.","Il a repeint la barrière d\'un magnanime éclatant."],"distracteurs":["unanime","magnétique","pusillanime"],"anecdote":"La magnanimité était pour Aristote une vertu maîtresse : la « grande âme » se reconnaît à ce qu\'elle se juge digne de grandes choses, et l\'est."},{"id":"mirobolant","mot":"mirobolant","nature":"adjectif","definitions":["Si extraordinaire qu\'il en paraît à peine croyable ; mirifique."],"phonetique":"/mi.ʁɔ.bɔ.lɑ̃/","etymologie":"De myrobolan, fruit exotique aux vertus jadis réputées miraculeuses.","registre":"familier","niveau":4,"themes":["abstrait"],"synonymes":["mirifique","fabuleux","prodigieux","faramineux"],"antonymes":["médiocre","banal","dérisoire"],"exemplesCorrects":["On lui promit des gains mirobolants qui ne vinrent jamais.","Ce n\'est pas un salaire mirobolant, mais il suffit.","Il racontait des aventures mirobolantes à qui voulait l\'entendre."],"exemplesIncorrects":["Un résultat mirobolant si décevant qu\'il démissionna.","Il a peint la clôture d\'un mirobolant éclatant."],"distracteurs":["miroitant","exorbitant","rutilant"],"anecdote":"Le myrobolan, fruit venu d\'Orient, passait pour une panacée ; de ses vertus exagérées est né l\'adjectif pour tout ce qui promet monts et merveilles."},{"id":"volubile","mot":"volubile","nature":"adjectif","definitions":["Qui parle avec abondance et rapidité ; très bavard."],"phonetique":"/vɔ.ly.bil/","etymologie":"Du latin volubilis, « qui tourne aisément », de volvere, « rouler ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["loquace","bavard","disert","prolixe"],"antonymes":["taciturne","laconique","réservé"],"exemplesCorrects":["Volubile, il enchaînait les anecdotes sans reprendre son souffle.","Elle devenait volubile dès qu\'on l\'interrogeait sur ses voyages.","Un guide volubile nous abreuva de détails."],"exemplesIncorrects":["Volubile, il restait muet des heures durant.","Il a repeint la porte d\'un volubile éclatant."],"distracteurs":["volatile","indélébile","automobile"],"anecdote":"Le liseron grimpant se nomme aussi « volubilis » : la même idée de ce qui s\'enroule et tourne, appliquée à la plante comme à la langue bien pendue."},{"id":"petulant","mot":"pétulant","nature":"adjectif","definitions":["Plein d\'une vivacité exubérante, d\'une ardeur impétueuse."],"phonetique":"/pe.ty.lɑ̃/","etymologie":"Du latin petulans, « impétueux », de petere, « se jeter sur ».","registre":"courant","niveau":3,"themes":["emotions"],"synonymes":["fougueux","exubérant","vif","turbulent"],"antonymes":["calme","placide","apathique"],"exemplesCorrects":["Une pétulante jeunesse animait toute la maisonnée.","Il répliqua avec une verve pétulante.","La pétulante fillette ne tenait pas en place."],"exemplesIncorrects":["Pétulant, il sombra dans une torpeur sans fin.","Il a repeint le portail d\'un pétulant lumineux."],"distracteurs":["pétillant","postulant","pétrifiant"],"anecdote":"Curieusement, « pétulant » et « péter » partagent la racine latine petere, « se précipiter » : la pétulance, c\'est l\'élan qui se jette en avant."},{"id":"vilipender","mot":"vilipender","nature":"verbe","definitions":["Traiter avec mépris, dénigrer publiquement."],"phonetique":"/vi.li.pɑ̃.de/","etymologie":"Du latin vilipendere, de vilis, « vil », et pendere, « estimer » : « tenir pour vil ».","registre":"littéraire","niveau":5,"themes":["abstrait"],"synonymes":["dénigrer","vitupérer","honnir","décrier"],"antonymes":["louer","vanter","encenser"],"exemplesCorrects":["On vilipenda son œuvre de son vivant, on la célébra ensuite.","Il vilipendait ses rivaux dans des pamphlets cinglants.","Inutile de vilipender l\'adversaire pour avoir raison."],"exemplesIncorrects":["Pour le remercier, elle le vilipenda chaleureusement.","Il a vilipendé la clôture du jardin avant l\'hiver."],"distracteurs":["dilapider","dépendre","violenter","vitupéré"],"anecdote":"Mot rare et précieux, « vilipender » dit littéralement qu\'on « pèse » quelqu\'un et qu\'on le trouve « vil » : un mépris mis en balance."},{"id":"escarcelle","mot":"escarcelle","nature":"nom féminin","definitions":["Autrefois, grande bourse suspendue à la ceinture ; par plaisanterie, les finances de quelqu\'un."],"phonetique":"/ɛs.kaʁ.sɛl/","etymologie":"De l\'ancien français escarcele, du latin médiéval scarsella, « petite bourse ».","registre":"littéraire","niveau":4,"themes":["quotidien","litteraire"],"synonymes":["bourse","porte-monnaie","cassette"],"antonymes":[],"exemplesCorrects":["Cette prime tomba opportunément dans son escarcelle.","Le voyageur portait son escarcelle bien serrée à la ceinture.","De nouveaux contrats vinrent gonfler l\'escarcelle de l\'entreprise."],"exemplesIncorrects":["Il a garé son escarcelle devant la mairie.","L\'escarcelle de la rivière était en crue ce matin."],"distracteurs":["escabelle","escarbille","ritournelle"],"anecdote":"Le mot, désuet au sens propre, ne survit guère que dans l\'expression « tomber dans l\'escarcelle de », c\'est-à-dire revenir, comme un gain, à quelqu\'un."},{"id":"sirocco","mot":"sirocco","nature":"nom masculin","definitions":["Vent du sud, chaud, sec et souvent chargé de sable, qui souffle du Sahara vers le bassin méditerranéen."],"phonetique":"/si.ʁɔ.ko/","etymologie":"De l\'italien scirocco, lui-même emprunté à l\'arabe šarqī, « oriental », de šarq, « est, levant » : le vent venu de cette direction.","registre":"soutenu","niveau":3,"themes":["emprunts","nature"],"synonymes":["simoun"],"antonymes":[],"exemplesCorrects":["Le sirocco soufflait depuis trois jours, déposant sur la ville une fine poussière ocre.","Sous le sirocco, l\'air devenait irrespirable et le ciel virait au jaune.","Les marins redoutaient le sirocco qui levait une houle courte et hargneuse."],"exemplesIncorrects":["Un sirocco neigeux descendait des sommets enveloppés de brume.","Elle a commandé un sirocco bien glacé à la terrasse du café."],"distracteurs":["étiage","ressac","embâcle","frimas"],"anecdote":"Le sirocco peut transporter le sable saharien jusqu\'au nord de l\'Europe, teintant parfois de roux la neige des Alpes."},{"id":"sylve","mot":"sylve","nature":"nom féminin","definitions":["Forêt, en particulier vaste et profonde, évoquée dans un registre poétique.","Au pluriel, recueil de pièces de vers d\'inspiration diverse, à la manière des Silves de Stace."],"phonetique":"/silv/","etymologie":"Du latin silva, « forêt, bois », qui a aussi donné « sylvestre » et « sylviculture ».","registre":"littéraire","niveau":3,"themes":["nature","emprunts","litteraire"],"synonymes":["forêt","futaie","bois","bosquet"],"antonymes":["clairière","lande","désert"],"exemplesCorrects":["Le poète s\'enfonçait dans la sylve obscure pour y chercher l\'inspiration.","Une sylve immémoriale couvrait jadis ces collines aujourd\'hui dénudées.","Sous la sylve épaisse, la lumière ne tombait qu\'en taches tremblantes."],"exemplesIncorrects":["Il a planté une sylve de tomates dans son potager ce printemps.","La sylve de l\'immeuble grouillait de passants pressés."],"distracteurs":["combe","garrigue","étiage","estran"],"anecdote":"Le latin silva a légué son nom au prénom Sylvie comme à Sylvain, le dieu romain protecteur des forêts."},{"id":"brame","mot":"brame","nature":"nom masculin","definitions":["Cri rauque et puissant que pousse le cerf à l\'époque du rut, à l\'automne.","Par extension littéraire, plainte sourde et prolongée."],"phonetique":"/bʁam/","etymologie":"Déverbal de « bramer », issu du bas latin bramare, « rugir, crier », d\'origine probablement germanique.","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["raire","bramement"],"antonymes":["silence","murmure"],"exemplesCorrects":["Au crépuscule d\'octobre, le brame du cerf montait du fond des bois.","On entendait au loin le brame rauque qui annonçait la saison des amours.","Le brame résonnait dans la combe comme une longue plainte."],"exemplesIncorrects":["Il a poussé un brame de joie en apprenant sa réussite à l\'examen.","Le brame léger du moineau égayait le jardin au petit matin."],"distracteurs":["ressac","frimas","embruns","limon"],"anecdote":"Chaque automne, les forêts comme celles de Chambord ou de Rambouillet attirent des promeneurs venus écouter, de nuit, le brame des cerfs."},{"id":"harmattan","mot":"harmattan","nature":"nom masculin","definitions":["Vent sec et poussiéreux qui souffle du Sahara vers le golfe de Guinée pendant la saison sèche, voilant l\'horizon d\'une brume de sable."],"phonetique":"/aʁ.ma.tɑ̃/","etymologie":"Emprunté, par l\'intermédiaire de l\'anglais, à une langue de la côte ouest-africaine, vraisemblablement le twi (ou fanti) haramata.","registre":"soutenu","niveau":3,"themes":["emprunts","nature"],"synonymes":[],"antonymes":[],"exemplesCorrects":["L\'harmattan desséchait les lèvres et brouillait le soleil d\'un halo laiteux.","Pendant l\'harmattan, la brume de poussière effaçait les contours des collines.","Les nuits d\'harmattan étaient étonnamment fraîches après la fournaise du jour."],"exemplesIncorrects":["L\'harmattan humide gonflait les rivières et inondait les rizières.","Il a rangé son harmattan dans le placard avec les autres manteaux d\'hiver."],"distracteurs":["sirocco","mousson","embruns","drache"],"anecdote":"Sur la côte ouest-africaine, on surnomme parfois l\'harmattan « le médecin », car son air sec apporte un répit à la moiteur tropicale."},{"id":"mousson","mot":"mousson","nature":"nom féminin","definitions":["Vent saisonnier de l\'océan Indien et de l\'Asie du Sud qui change de direction selon l\'époque de l\'année.","Par extension, la saison des pluies qu\'amène ce vent."],"phonetique":"/mu.sɔ̃/","etymologie":"Du portugais monção, emprunté à l\'arabe mawsim, « saison, époque fixée », répandu par les navigateurs de l\'océan Indien.","registre":"courant","niveau":3,"themes":["emprunts","nature"],"synonymes":["saison des pluies","pluies de mousson"],"antonymes":["sécheresse"],"exemplesCorrects":["La mousson d\'été déversait sur la côte des trombes d\'eau tièdes.","Les paysans attendaient la mousson pour repiquer le riz.","Dès les premières pluies de la mousson, la poussière laissait place à la boue."],"exemplesIncorrects":["Une mousson de neige a recouvert les sommets alpins cette nuit.","Il a épousseté la mousson accumulée sur les étagères du grenier."],"distracteurs":["alizé","embruns","étiage","frimas"],"anecdote":"Le mot arabe d\'origine signifie « saison » : les marins arabes nommaient ainsi le rythme des vents qui réglait leurs traversées vers l\'Inde."},{"id":"foehn","mot":"foehn","nature":"nom masculin","definitions":["Vent chaud et sec qui souffle sur le versant sous le vent d\'une chaîne de montagnes, après avoir abandonné son humidité sur le versant opposé."],"phonetique":"/føn/","etymologie":"De l\'allemand de Suisse Föhn, lui-même issu du latin favonius, « vent de l\'ouest, vent doux ».","registre":"soutenu","niveau":3,"themes":["nature","emprunts"],"synonymes":["vent"],"antonymes":[],"exemplesCorrects":["Le foehn avait fait fondre la neige en une seule nuit sur les pentes valaisannes.","Quand souffle le foehn, l\'air devient sec et les cimes paraissent étrangement proches.","On attribuait au foehn les migraines et l\'irritabilité des habitants de la vallée."],"exemplesIncorrects":["Le foehn glacial du large nous transperçait sur la jetée du port.","Un foehn humide et brumeux montait de la mer et détrempait nos vêtements."],"distracteurs":["alizé","embruns","houle","givre"],"anecdote":"En allemand, Föhn désigne aussi le sèche-cheveux, par analogie avec ce vent d\'air chaud descendant des montagnes."},{"id":"simoun","mot":"simoun","nature":"nom masculin","definitions":["Vent violent, brûlant et chargé de sable qui balaie les déserts d\'Afrique du Nord et d\'Arabie."],"phonetique":"/si.mun/","etymologie":"Emprunté à l\'anglais simoom, lui-même issu de l\'arabe samūm, « vent pestilentiel, empoisonné », de la racine samma, « empoisonner ».","registre":"littéraire","niveau":3,"themes":["emprunts","nature"],"synonymes":["sirocco","khamsin"],"antonymes":[],"exemplesCorrects":["Le simoun se leva soudain, ensevelissant la caravane sous des tourbillons de sable.","Nul ne s\'aventurait dans le désert quand menaçait le simoun.","Le simoun soufflait avec une fureur qui semblait vouloir effacer toute trace de vie."],"exemplesIncorrects":["Un simoun rafraîchissant montait de la mer en fin d\'après-midi.","Elle s\'est abritée du simoun sous un parapluie pendant l\'averse."],"distracteurs":["alizé","houle","embâcle","givre"],"anecdote":"Théophile Gautier et bien des écrivains romantiques firent du simoun l\'image même de la fureur dévorante du désert."},{"id":"combe","mot":"combe","nature":"nom féminin","definitions":["Petite vallée encaissée, dépression au creux d\'un relief de collines ou de montagnes, fréquente dans le Jura et les Alpes."],"phonetique":"/kɔ̃b/","etymologie":"Du gaulois cumba, « vallée, dépression », mot prélatin conservé surtout dans la toponymie et le vocabulaire géographique ; à rapprocher du gallois cwm et du breton komm.","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["vallon","ravin","gorge","val"],"antonymes":["crête","sommet","plateau"],"exemplesCorrects":["Le sentier descendait au fond de la combe où subsistait un peu de neige.","Une brume tenace stagnait dans la combe à l\'abri du vent.","Les villages se nichaient au creux des combes, à l\'écart des cols battus par les bourrasques."],"exemplesIncorrects":["Elle s\'est coiffée d\'une combe avant de sortir sous la pluie.","Il a gravi la combe pour atteindre le point le plus haut du massif."],"distracteurs":["calanque","garrigue","étiage","estran"],"anecdote":"Le mot survit dans des centaines de noms de lieux français, de Combloux à La Combe-de-Lancey, témoins discrets d\'un substrat gaulois."},{"id":"tohubohu","mot":"tohu-bohu","nature":"nom masculin","definitions":["Désordre confus et bruyant ; agitation chaotique mêlée de vacarme."],"phonetique":"/tɔ.y.bɔ.y/","etymologie":"De l\'hébreu biblique tohu wa-bohu, « informe et vide », expression de la Genèse décrivant la Terre avant la création.","registre":"soutenu","niveau":3,"themes":["emprunts"],"synonymes":["chaos","tintamarre","ramdam","tumulte"],"antonymes":["ordre","calme","quiétude","silence"],"exemplesCorrects":["Dans le tohu-bohu de la gare, il peinait à retrouver ses compagnons.","Le marché du matin n\'était qu\'un tohu-bohu de cris et de couleurs.","Un tohu-bohu indescriptible régnait dans la salle au moment du vote."],"exemplesIncorrects":["Le tohu-bohu paisible du monastère invitait à la méditation.","Il a rangé son bureau dans un parfait tohu-bohu, tout y était impeccable."],"distracteurs":["palimpseste","atavisme","logorrhée","marasme"],"anecdote":"Avant de désigner le vacarme, l\'expression hébraïque décrivait, dans la Genèse, l\'état chaotique du monde avant que la lumière n\'en sépare les éléments."},{"id":"deletere","mot":"délétère","nature":"adjectif","definitions":["Qui nuit à la santé, qui peut tuer en s\'attaquant à l\'organisme.","Au figuré : qui exerce une influence pernicieuse, qui corrompt moralement ou socialement."],"phonetique":"/de.le.tɛʁ/","etymologie":"Emprunté au bas latin deleterius, lui-même issu du grec dêlêtêrios, « nuisible, funeste », dérivé du verbe dêleîsthai, « nuire, détruire ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["nocif","pernicieux","nuisible","toxique","morbide"],"antonymes":["salutaire","bénéfique","salubre","bienfaisant"],"exemplesCorrects":["Des vapeurs délétères montaient du marais et incommodaient les voyageurs.","Il dénonçait l\'influence délétère que ce climat de soupçon faisait peser sur l\'amitié.","Une rumeur délétère se répandit dans la cour et ruina peu à peu sa réputation."],"exemplesIncorrects":["Cette tisane délétère m\'a fait le plus grand bien après le dîner.","Son discours délétère a réconforté toute l\'assemblée et redonné espoir."],"distracteurs":["léthargique","délibéré","doctoral","diaphane"],"anecdote":"Le mot appartenait d\'abord au vocabulaire des chimistes et des hygiénistes du XIXᵉ siècle, qui parlaient de « gaz délétères » bien avant que l\'usage figuré ne s\'impose en morale."},{"id":"subreptice","mot":"subreptice","nature":"adjectif","definitions":["Qui se fait de manière furtive, cachée, en se dérobant à l\'attention.","En droit ancien : obtenu par des moyens frauduleux, en surprenant la bonne foi d\'autrui."],"phonetique":"/syb.ʁɛp.tis/","etymologie":"Du latin subrepticius, « clandestin, dérobé », dérivé de subripere « soustraire furtivement, en se glissant dessous » (sub- « sous » et rapere « saisir, ravir »).","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["furtif","clandestin","insidieux","sournois","occulte"],"antonymes":["manifeste","ostensible","patent","déclaré"],"exemplesCorrects":["Il lui adressa un regard subreptice, espérant n\'être surpris de personne.","Une joie subreptice passa sur son visage avant qu\'il ne reprît son air grave.","Par une manœuvre subreptice, il fit disparaître le document compromettant."],"exemplesIncorrects":["Le maire a inauguré la place de façon subreptice, devant une foule immense et sous les applaudissements.","Elle annonça la nouvelle de manière subreptice, à voix haute, du haut de la tribune."],"distracteurs":["superfétatoire","succinct","sciemment","saccadé"],"anecdote":"L\'adverbe « subrepticement » a largement supplanté l\'adjectif dans l\'usage courant, au point que beaucoup de locuteurs ignorent l\'existence de « subreptice »."},{"id":"smala","mot":"smala","nature":"nom féminin","definitions":["Camp itinérant d\'un chef arabe, avec sa suite, ses tentes et ses troupeaux.","Familièrement, famille ou entourage nombreux qui se déplace en groupe."],"phonetique":"/sma.la/","etymologie":"De l\'arabe dialectal d\'Algérie zmāla, « famille, maison du chef et sa suite » (lui-même d\'origine berbère), popularisé en français après la prise de la smala d\'Abd el-Kader en 1843.","registre":"courant","niveau":3,"themes":["emprunts"],"synonymes":["tribu","maisonnée","marmaille","smalah"],"antonymes":[],"exemplesCorrects":["Il est arrivé au baptême avec toute sa smala, cousins et petits-cousins compris.","La smala du caïd se déplaçait au gré des pâturages et des points d\'eau.","Impossible de loger pareille smala dans un studio."],"exemplesIncorrects":["Elle a accroché une smala précieuse au-dessus de la cheminée du salon.","Le médecin a prescrit une smala à prendre chaque matin à jeun."],"distracteurs":["caravane","douar","cohorte","saugrenu"],"anecdote":"La prise de la smala d\'Abd el-Kader en 1843 inspira à Horace Vernet une toile immense, l\'une des plus grandes du château de Versailles."},{"id":"immarcescible","mot":"immarcescible","nature":"adjectif","definitions":["Qui ne peut se flétrir, se faner.","Au figuré : qui ne saurait s\'altérer ni disparaître ; impérissable, inaltérable."],"phonetique":"/i.maʁ.se.sibl/","etymologie":"Du latin chrétien immarcescibilis, de marcescere, « se flétrir, se dessécher », précédé du préfixe privatif in-.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["impérissable","inaltérable","indéfectible","éternel"],"antonymes":["périssable","éphémère","altérable","fugace"],"exemplesCorrects":["Il croyait en une gloire immarcescible que les siècles ne sauraient ternir.","Sa foi immarcescible le soutint jusque dans les pires épreuves.","Le marbre semblait promettre à ce visage une beauté immarcescible."],"exemplesIncorrects":["Ces roses coupées, immarcescibles, ont fané en deux jours sur la table.","Son humeur immarcescible changeait du tout au tout selon le temps qu\'il faisait."],"distracteurs":["irascible","inextinguible","incoercible","impavide"],"anecdote":"Le mot, d\'abord cantonné au vocabulaire religieux où il qualifiait la couronne de gloire promise aux justes, fascine par sa longueur et son allure savante les amateurs de mots rares."},{"id":"prometheen","mot":"prométhéen","nature":"adjectif","definitions":["Qui évoque Prométhée par son audace, sa révolte contre l\'ordre établi ou son désir de dépasser la condition humaine.","Qui témoigne d\'une ambition créatrice démesurée, défiant les limites imposées."],"phonetique":"/pʁɔ.me.te.ɛ̃/","etymologie":"Dérivé de Prométhée, le Titan de la mythologie grecque qui déroba le feu aux dieux pour le donner aux hommes et fut châtié par Zeus.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["titanesque","audacieux","rebelle","démiurgique"],"antonymes":["résigné","soumis","pusillanime","timoré"],"exemplesCorrects":["Il y avait dans ce projet un élan prométhéen, une volonté de tout réinventer.","Le romantisme a fait du génie une figure prométhéenne, en lutte contre les dieux et les hommes.","Son ambition prométhéenne le poussait à défier les limites mêmes de la science."],"exemplesIncorrects":["Il accepta son sort avec une humilité prométhéenne et baissa la tête.","Ce petit arrangement prométhéen consistait à ranger ses crayons par couleur."],"distracteurs":["protéiforme","promiscuité","providentiel","prosaïque"],"anecdote":"Mary Shelley sous-titra son Frankenstein « Le Prométhée moderne », faisant du savant qui crée la vie un nouvel avatar du Titan voleur de feu."},{"id":"vesperal","mot":"vespéral","nature":"adjectif","definitions":["Qui appartient au soir, qui a lieu ou paraît au moment du crépuscule.","Au figuré : qui évoque le déclin, la fin paisible d\'une journée ou d\'une vie."],"phonetique":"/vɛs.pe.ʁal/","etymologie":"Du latin tardif vesperalis, dérivé de vesper, « le soir, l\'étoile du soir ».","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["crépusculaire","vespertin","nocturne"],"antonymes":["matinal","matutinal","auroral"],"exemplesCorrects":["Une lumière vespérale dorait la façade des vieilles maisons.","Il aimait ces promenades vespérales où la ville se taisait peu à peu.","Le poète célébrait la douceur vespérale de son âge, sereine et résignée."],"exemplesIncorrects":["Dès l\'aube vespérale, le coq se mit à chanter dans la cour.","Nous avons pris un copieux petit-déjeuner vespéral avant de partir randonner."],"distracteurs":["viscéral","vénéneux","véhément","versatile"],"anecdote":"Dans la liturgie catholique, le « vespéral » désigne aussi un recueil contenant l\'office des vêpres, la prière chantée du soir."},{"id":"seraphique","mot":"séraphique","nature":"adjectif","definitions":["Qui appartient aux séraphins, les anges du plus haut rang.","Au figuré : d\'une pureté, d\'une douceur ou d\'une sérénité quasi angéliques, détaché des choses terrestres."],"phonetique":"/se.ʁa.fik/","etymologie":"Dérivé de séraphin, lui-même issu de l\'hébreu seraphim, pluriel de saraph, « brûlant », par l\'intermédiaire du latin ecclésiastique.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["angélique","céleste","éthéré","extatique"],"antonymes":["démoniaque","terrestre","charnel","prosaïque"],"exemplesCorrects":["Un sourire séraphique éclairait le visage de l\'enfant endormi.","Elle écoutait la musique dans une extase presque séraphique.","Le vieux moine inspirait une paix séraphique à tous ceux qui l\'approchaient."],"exemplesIncorrects":["Il est entré dans une colère séraphique et a renversé la table.","Le boxeur a porté un coup séraphique qui a mis son adversaire au tapis."],"distracteurs":["sibyllin","sardonique","sentencieux","sépulcral"],"anecdote":"Saint François d\'Assise est traditionnellement surnommé « le Docteur séraphique » et son ordre, les franciscains, « l\'ordre séraphique »."},{"id":"apophtegme","mot":"apophtegme","nature":"nom masculin","definitions":["Parole mémorable, sentence concise exprimant une vérité d\'une autorité reconnue, souvent attribuée à un personnage illustre."],"phonetique":"/a.pɔf.tɛɡm/","etymologie":"Emprunté au XVIe siècle au latin apophthegma, lui-même issu du grec apophthegma, « sentence, mot bien frappé », dérivé de apophthengesthai, « énoncer nettement ».","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["maxime","aphorisme","sentence","adage","dicton"],"antonymes":[],"exemplesCorrects":["Il aimait à ponctuer ses lettres d\'un apophtegme emprunté aux Anciens.","« Connais-toi toi-même » est sans doute l\'apophtegme le plus célèbre de la sagesse grecque.","Le vieux maître parlait par apophtegmes, comme s\'il craignait de gaspiller ses mots."],"exemplesIncorrects":["Le médecin a diagnostiqué un apophtegme au genou après sa chute.","Elle a rangé ses apophtegmes dans le tiroir, à côté des couverts."],"distracteurs":["paradigme","anathème","épithète","syllogisme"],"anecdote":"Plutarque rassembla les mots célèbres des grands hommes dans un recueil intitulé « Apophtegmes des rois et des généraux », véritable ancêtre antique du livre de citations."},{"id":"adamantin","mot":"adamantin","nature":"adjectif","definitions":["Qui a la dureté ou l\'éclat du diamant.","Au figuré : d\'une fermeté, d\'une pureté ou d\'une transparence inaltérables."],"phonetique":"/a.da.mɑ̃.tɛ̃/","etymologie":"Du latin adamantinus, du grec adamas, adamantos, littéralement « l\'indomptable » (de a- privatif et damaô, « dompter ») — terme appliqué d\'abord aux substances les plus dures, le fer et l\'acier, puis au diamant.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["cristallin","diamantin","inflexible","inaltérable"],"antonymes":["friable","trouble","malléable","fragile"],"exemplesCorrects":["Une lumière adamantine jaillissait de la rosée au lever du jour.","Il opposa à ses juges une fermeté adamantine que rien ne put entamer.","Sa prose avait une clarté adamantine, sans une ombre ni une scorie."],"exemplesIncorrects":["Le coussin adamantin était si moelleux qu\'on s\'y enfonçait avec délice.","Il a une volonté adamantine : il change d\'avis à la moindre contrariété."],"distracteurs":["argentin","opalin","ambrosien","azuréen"],"anecdote":"Le mot grec adamas, « l\'indomptable », a donné à la fois « diamant » et « aimant » en français, deux objets que les Anciens croyaient doués de pouvoirs invincibles."},{"id":"lenifiant","mot":"lénifiant","nature":"adjectif","definitions":["Qui apaise, adoucit la douleur ou l\'inquiétude.","Souvent péjoratif : qui calme à bon compte, par des paroles rassurantes mais vaines."],"phonetique":"/le.ni.fjɑ̃/","etymologie":"Participe présent du verbe lénifier, du bas latin lenificare, « adoucir », de lenis, « doux », et facere, « faire ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["apaisant","adoucissant","calmant","émollient"],"antonymes":["irritant","exacerbant","alarmant","exaspérant"],"exemplesCorrects":["Il tenait des propos lénifiants pour endormir la méfiance de ses adversaires.","La voix lénifiante du conférencier finit par bercer l\'auditoire tout entier.","On lui servit des discours lénifiants là où elle attendait des actes."],"exemplesIncorrects":["Sa remarque lénifiante a déclenché une violente dispute entre les convives.","Le café, particulièrement lénifiant, l\'a tenu éveillé toute la nuit."],"distracteurs":["lancinant","languissant","léthargique","lascif"],"anecdote":"Le mot vient du même radical latin lenis que « lénitif », terme de pharmacie désignant un remède destiné à calmer la douleur."},{"id":"vesanie","mot":"vésanie","nature":"nom féminin","definitions":["Folie, dérangement durable de l\'esprit, envisagé dans sa gravité.","Par extension littéraire : déraison furieuse, égarement collectif."],"phonetique":"/ve.za.ni/","etymologie":"Du latin vesania, « folie », de vesanus, « insensé », composé de ve- (privatif, marquant l\'écart) et sanus, « sain ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["démence","aliénation","égarement","folie"],"antonymes":["raison","lucidité","santé mentale"],"exemplesCorrects":["Les médecins d\'alors rangeaient sous le nom de vésanie tout ce que la raison ne pouvait plus contenir.","Une vésanie collective semblait s\'être emparée de la foule, ivre de slogans.","Le poète sombra peu à peu dans une vésanie que ses amis affectaient de ne pas voir."],"exemplesIncorrects":["Il a rangé ses dossiers avec une vésanie méthodique avant de partir.","Sa vésanie pour la cuisine italienne le pousse à voyager chaque été en Toscane."],"distracteurs":["véhémence","vétusté","vénalité","vacuité"],"anecdote":"Le terme figurait jadis dans les nosographies médicales pour désigner la classe des maladies mentales, avant que la psychiatrie moderne n\'en abandonne l\'usage clinique."},{"id":"desherence","mot":"déshérence","nature":"nom féminin","definitions":["État d\'un bien ou d\'une succession sans héritier, qui revient alors à l\'État.","Au figuré : état d\'abandon, de délaissement d\'une chose dont nul ne se réclame plus."],"phonetique":"/de.ze.ʁɑ̃s/","etymologie":"Dérivé de « déshériter » (dés- privatif + hériter), avec le suffixe -ence ; de la base latine heres, heredis, « héritier ». Littéralement « état où il n\'y a pas d\'héritier ».","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["abandon","délaissement","vacance"],"antonymes":["transmission","héritage","succession"],"exemplesCorrects":["Faute d\'héritier connu, la maison tomba en déshérence et l\'État en hérita.","Tout un pan de notre mémoire collective est aujourd\'hui laissé en déshérence.","Ces savoirs artisanaux, tombés en déshérence, ne survivent plus que chez quelques anciens."],"exemplesIncorrects":["Il a reçu une déshérence considérable à la mort de son oncle.","Le notaire a réparti la déshérence entre les trois enfants du défunt."],"distracteurs":["déliquescence","désuétude","déréliction","dévolution"],"anecdote":"En droit français, les biens dits « en déshérence » échoient à l\'État, qui les recueille faute de tout autre ayant droit."},{"id":"inanite","mot":"inanité","nature":"nom féminin","definitions":["Caractère de ce qui est vide de sens, de portée ou d\'utilité ; vanité profonde d\'une chose.","Par extension : futilité d\'un propos ou d\'une entreprise."],"phonetique":"/i.na.ni.te/","etymologie":"Du latin inanitas, « vide, vacuité », dérivé de inanis, « vide, creux ».","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["vacuité","futilité","vanité","inutilité"],"antonymes":["substance","consistance","utilité","valeur"],"exemplesCorrects":["Il finit par mesurer l\'inanité de ses efforts contre un mur d\'indifférence.","L\'inanité de ces débats sans fin décourageait jusqu\'aux plus patients.","Devant l\'immensité du ciel, elle ressentit l\'inanité de ses petites tracasseries."],"exemplesIncorrects":["Son discours était d\'une telle inanité qu\'il a convaincu toute l\'assemblée.","Grâce à l\'inanité de ses arguments, il a remporté le débat haut la main."],"distracteurs":["immensité","inanition","innéité","iniquité"],"anecdote":"À ne pas confondre avec « inanition », l\'état d\'épuisement faute de nourriture : les deux mots remontent au même latin inanis, « vide », mais l\'un dit le vide du sens, l\'autre celui de l\'estomac."},{"id":"prodrome","mot":"prodrome","nature":"nom masculin","definitions":["Signe avant-coureur, symptôme qui annonce l\'imminence d\'un mal ou d\'un événement.","Au figuré littéraire : ce qui précède et présage une crise."],"phonetique":"/pʁɔ.dʁom/","etymologie":"Du grec prodromos, « qui court devant, avant-coureur », de pro- (devant) et dromos (course).","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["prémices","présage","signe avant-coureur","préliminaire"],"antonymes":["séquelle","aboutissement","épilogue"],"exemplesCorrects":["Ces tensions diplomatiques n\'étaient que les prodromes d\'un conflit plus vaste.","La migraine débutait toujours par les mêmes prodromes : une lumière trop vive, un picotement.","Les historiens lisent dans ces émeutes les prodromes de la révolution à venir."],"exemplesIncorrects":["Après des mois de soins, le prodrome de sa maladie marqua enfin sa guérison.","Ce prodrome glorieux couronna une carrière déjà bien remplie."],"distracteurs":["paradigme","prolixité","promontoire","prosélyte"],"anecdote":"En médecine, on appelle encore « phase prodromique » la période où des symptômes diffus annoncent une maladie avant que celle-ci ne se déclare franchement."},{"id":"dehiscence","mot":"déhiscence","nature":"nom féminin","definitions":["Ouverture spontanée d\'un organe végétal arrivé à maturité, qui libère graines ou pollen.","Par extension : tout écartement, toute fente par laquelle un contenu se libère."],"phonetique":"/de.i.sɑ̃s/","etymologie":"Du latin dehiscere, « s\'ouvrir, s\'entrebâiller », de hiscere, « s\'entrouvrir, se fendre » ; le substantif est emprunté au bas latin dehiscentia.","registre":"soutenu","niveau":5,"themes":["nature","abstrait"],"synonymes":["ouverture","fente","écartement"],"antonymes":["fermeture","occlusion","indéhiscence"],"exemplesCorrects":["À la déhiscence des capsules, le pavot répand ses graines au moindre souffle.","Le botaniste notait la date exacte de déhiscence de chaque espèce.","On pourrait parler, par métaphore, de la déhiscence d\'un secret trop longtemps contenu."],"exemplesIncorrects":["La déhiscence de la porte cochère résonna lorsqu\'on la verrouilla pour la nuit.","Le maçon a comblé la déhiscence en cimentant solidement les deux pierres."],"distracteurs":["efflorescence","dénivellation","désinence","exsudation"],"anecdote":"On distingue en botanique les fruits « déhiscents », qui s\'ouvrent à maturité comme la gousse du pois, des fruits « indéhiscents », qui gardent leurs graines enfermées, telle la noisette."},{"id":"palingenesie","mot":"palingénésie","nature":"nom féminin","definitions":["Renaissance, retour à la vie ou régénération complète d\'un être, d\'une société ou du monde.","En philosophie et en théologie : doctrine d\'un perpétuel recommencement, d\'une nouvelle naissance des âmes ou de l\'univers."],"phonetique":"/pa.lɛ̃.ʒe.ne.zi/","etymologie":"Emprunté, par l\'intermédiaire du latin palingenesia, au grec palingenesia, composé de palin, « de nouveau, à nouveau », et de genesis, « naissance, génération » : littéralement « nouvelle naissance ».","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["renaissance","régénération","résurrection","renouveau"],"antonymes":["déclin","extinction","anéantissement","déchéance"],"exemplesCorrects":["Les stoïciens enseignaient une palingénésie du cosmos, sans cesse consumé et reformé.","Le romancier rêvait d\'une palingénésie de la société par la seule force de l\'art.","Il voyait dans le printemps l\'image d\'une palingénésie universelle."],"exemplesIncorrects":["Le médecin a prescrit une palingénésie deux fois par jour après les repas.","Elle a garé sa palingénésie devant l\'immeuble avant de monter."],"distracteurs":["parthénogenèse","métempsycose","anamnèse","eschatologie"],"anecdote":"Le mot, longtemps cantonné à la philosophie mystique, fut popularisé par la Palingénésie philosophique de Charles Bonnet (1769) puis par les Essais de palingénésie sociale de Ballanche ; Balzac en hérita pour exprimer sa croyance en une perpétuelle transformation des êtres et des sociétés."},{"id":"clenche","mot":"clenche","nature":"nom féminin","definitions":["Pièce mobile d\'un loquet qui, en s\'abaissant dans la gâche, maintient une porte fermée.","Régionalement (Nord, Belgique) : poignée ou bec-de-cane d\'une porte."],"phonetique":"/klɑ̃ʃ/","etymologie":"De l\'ancien bas francique *klinka, « loquet », apparenté au néerlandais klink ; mot d\'aire septentrionale, de même racine germanique que l\'anglais to clinch.","registre":"courant","niveau":5,"themes":["regionalismes","quotidien"],"synonymes":["loquet","bec-de-cane","poignée"],"antonymes":[],"exemplesCorrects":["Il abaissa la clenche sans bruit pour ne réveiller personne.","Dans le Nord, on vous dira d\'« abaisser la clenche » là où d\'autres disent la poignée.","La clenche rouillée résistait, et il fallut peser de tout son poids sur la porte."],"exemplesIncorrects":["Il a accroché son manteau à la clenche du portemanteau de l\'entrée.","La clenche du robinet gouttait toute la nuit dans l\'évier de la cuisine."],"distracteurs":["targette","espagnolette","crémone","gâche"],"anecdote":"Restée vivante dans le Nord de la France et en Belgique, « clenche » a longtemps désigné aussi bien le loquet que la poignée, au point de dérouter les visiteurs venus du Sud."},{"id":"nitescence","mot":"nitescence","nature":"nom féminin","definitions":["Éclat lumineux, état de ce qui brille d\'une lueur douce ou naissante."],"phonetique":"/ni.te.sɑ̃s/","etymologie":"Du latin nitescere, « commencer à briller », forme inchoative de nitere, « luire, resplendir ».","registre":"littéraire","niveau":5,"themes":["litteraire","nature"],"synonymes":["luminescence","éclat","brillance","lueur"],"antonymes":["obscurité","ternissure","opacité"],"exemplesCorrects":["La nitescence du couchant teintait les vitres d\'un or liquide.","On devinait sous la cendre la nitescence des dernières braises.","Une étrange nitescence émanait de la mer phosphorescente cette nuit-là."],"exemplesIncorrects":["Une épaisse nitescence enveloppait la cave et l\'on n\'y voyait goutte.","La nitescence du brouillard nous empêchait d\'avancer sur la route."],"distracteurs":["incandescence","réminiscence","turgescence","phosphène"],"anecdote":"Attesté dès 1834 sous la plume de Sainte-Beuve, dans Volupté, « nitescence » a séduit les poètes friands de termes savants pour dire la lumière sous toutes ses nuances."},{"id":"retif","mot":"rétif","nature":"adjectif","definitions":["Qui refuse d\'avancer ou d\'obéir, en parlant d\'une monture ; par extension, d\'une personne récalcitrante, qui résiste à ce qu\'on lui demande."],"phonetique":"/ʁe.tif/","etymologie":"Du latin populaire restivus, « qui s\'arrête, qui reste en arrière », dérivé du verbe restare, « rester, s\'arrêter », lui-même formé de re- et de stare, « se tenir debout ».","registre":"soutenu","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["récalcitrant","rebelle","indocile","réfractaire"],"antonymes":["docile","obéissant","soumis"],"exemplesCorrects":["Le cheval, rétif, refusa de franchir le ruisseau malgré les encouragements.","Cet élève rétif à toute discipline finissait toujours par se faire remarquer.","Elle restait rétive aux conseils, persuadée de mieux savoir."],"exemplesIncorrects":["Après une bonne nuit, je me sens parfaitement rétif et plein d\'énergie.","Ce fauteuil est très rétif, on s\'y assoit avec un grand confort."],"distracteurs":["pusillanime","loquace","affable","fébrile"],"anecdote":"Le mot s\'applique d\'abord aux chevaux qui « restent » plantés et refusent d\'avancer ; cette image équestre, héritée du latin restare (« s\'arrêter »), a donné son sens figuré à l\'esprit rétif."},{"id":"imperitie","mot":"impéritie","nature":"nom féminin","definitions":["Manque d\'aptitude, incapacité notoire à exercer une fonction ou un métier.","Maladresse coupable de celui qui agit sans le savoir-faire requis."],"phonetique":"/ɛ̃.pe.ʁi.si/","etymologie":"Du latin imperitia, « inexpérience, ignorance, maladresse », dérivé de imperitus, « inexpérimenté, ignorant », composé du préfixe privatif in- et de peritus, « expérimenté, habile, qui sait par expérience ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["incompétence","incapacité","maladresse","inhabileté"],"antonymes":["compétence","habileté","maestria","expertise"],"exemplesCorrects":["On lui reprocha une impéritie qui avait coûté cher à l\'entreprise.","L\'impéritie des dirigeants précipita la déroute de la campagne.","Sa plume dénonçait sans relâche l\'impéritie des administrations engourdies."],"exemplesIncorrects":["Il a mené le projet avec une impéritie remarquable qui força l\'admiration de tous.","Grâce à son impéritie de chirurgien, l\'opération fut un éclatant succès."],"distracteurs":["impavidité","improbité","impécuniosité","impétuosité"],"anecdote":"Le terme garde une coloration juridique : on parle encore d\'« impéritie » pour qualifier la faute du professionnel dont l\'incompétence engage la responsabilité."},{"id":"contrit","mot":"contrit","nature":"adjectif","definitions":["Qui éprouve un regret sincère, une tristesse marquée d\'avoir commis une faute ; pénétré de repentir."],"phonetique":"/kɔ̃.tʁi/","etymologie":"Du latin contritus, « broyé, écrasé », participe passé de conterere ; au sens religieux, « dont le cœur est brisé par le remords ».","registre":"soutenu","niveau":2,"themes":["emotions"],"synonymes":["repentant","penaud","confus","marri"],"antonymes":["impénitent","fier","satisfait"],"exemplesCorrects":["Il présenta ses excuses d\'un air contrit, n\'osant lever les yeux.","Contrite de sa maladresse, elle resta silencieuse le reste du dîner.","L\'enfant, contrit, avoua tout bas qu\'il avait cassé le vase."],"exemplesIncorrects":["Ravi de sa bonne plaisanterie, il riait d\'un air contrit.","Après sa victoire, il affichait un sourire contrit et triomphant."],"distracteurs":["serein","véhément","désinvolte","perspicace"],"anecdote":"Dans la tradition catholique, on distingue la « contrition parfaite », inspirée par l\'amour de Dieu, de la simple « attrition », motivée par la peur du châtiment."},{"id":"sagace","mot":"sagace","nature":"adjectif","definitions":["Qui fait preuve d\'une pénétration d\'esprit vive, capable de deviner et de comprendre ce qui échappe aux autres."],"phonetique":"/sa.ɡas/","etymologie":"Du latin sagax, sagacis, « qui a l\'odorat ou le flair subtil », d\'abord dit des chiens de chasse, dérivé de sagire, « percevoir finement, flairer ».","registre":"soutenu","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["perspicace","clairvoyant","fin","avisé"],"antonymes":["obtus","borné","naïf"],"exemplesCorrects":["Un observateur sagace aurait remarqué l\'hésitation dans sa voix.","Elle posa une question sagace qui désarçonna tout le jury.","Le vieux médecin, sagace, devina le mal avant même l\'examen."],"exemplesIncorrects":["Cette tarte est délicieusement sagace, relevée comme il faut.","Il a couru de manière très sagace et a remporté la course."],"distracteurs":["affable","taciturne","véhément","candide"],"anecdote":"Le mot vient du flair des chiens de chasse : être sagace, c\'est avoir du « nez » au sens figuré, savoir flairer ce que les autres ne perçoivent pas."},{"id":"cassine","mot":"cassine","nature":"nom féminin","definitions":["Petite maison de campagne, souvent modeste ou isolée.","Par dépréciation : masure, bicoque délabrée ; au sens militaire vieilli, petite construction isolée dans les champs servant de poste d\'embuscade."],"phonetique":"/ka.sin/","etymologie":"Emprunté à l\'italien septentrional « cassina », variante du toscan « cascina » (« ferme, étable à vaches »), issu du bas-latin « cassina » et remontant au latin vulgaire « *capsea », apparenté à « capsa » (« caisse »).","registre":"littéraire","niveau":5,"themes":["regionalismes","litteraire"],"synonymes":["masure","maisonnette","bicoque","chaumière"],"antonymes":["palais","manoir","demeure"],"exemplesCorrects":["Ils passaient l\'été dans une cassine perdue au milieu des oliviers.","La vieille cassine, fendue de lézardes, tenait encore debout par miracle.","Il rêvait de finir ses jours dans quelque cassine du Luberon, loin du tumulte."],"exemplesIncorrects":["Le promoteur a fait bâtir une somptueuse cassine de mille mètres carrés sur la colline.","Ils ont organisé le grand bal de mariage dans la cassine royale du château."],"distracteurs":["mazet","borie","bastide","métairie"],"anecdote":"Déjà présent chez Rabelais en 1532, le mot a longtemps désigné, dans la langue militaire, une bâtisse isolée au milieu des champs d\'où l\'on guettait l\'ennemi : la modeste maison de campagne pouvait ainsi devenir un poste d\'embuscade."},{"id":"obombrer","mot":"obombrer","nature":"verbe","definitions":["Couvrir d\'ombre, voiler d\'une ombre légère.","Au figuré, littéraire : assombrir, ternir l\'éclat de quelque chose."],"phonetique":"/ɔ.bɔ̃.bʁe/","etymologie":"Du latin obumbrare, « couvrir d\'ombre, ombrager », de ob- (devant, contre) et umbra, « ombre ». Attesté dès le XIIe siècle.","registre":"littéraire","niveau":5,"themes":["litteraire","nature"],"synonymes":["ombrager","voiler","assombrir","obscurcir"],"antonymes":["éclairer","illuminer","aviver"],"exemplesCorrects":["Un grand cèdre obombrait la terrasse aux heures les plus chaudes.","Une mélancolie soudaine vint obombrer sa joie naissante.","Les nuages obombraient la vallée d\'une grisaille pesante."],"exemplesIncorrects":["Le soleil de midi obombrait la plage d\'une lumière aveuglante.","Sa réussite éclatante obombra de bonheur toute la famille réunie."],"distracteurs":["obstruer","ombiliquer","obvier","obnubiler"],"anecdote":"Verbe que l\'on croise surtout chez les poètes et dans les anciennes traductions bibliques, où la nuée « obombre » les fidèles et où les anges « obombrent » de leurs ailes : il appartient à ce français rare et mystique que la prose courante a presque oublié."}]')},57649,e=>{"use strict";let i=e.i(98455).default,a=new Map(i.map(e=>[e.id,e]));e.s(["CORPUS",0,i,"getMotById",0,function(e){return a.get(e)}])}]);